var documenterSearchIndex = {"docs":
[{"location":"cookbook/06-permissions/#Recipe-06-—-Permissions","page":"Permissions","title":"Recipe 06 — Permissions","text":"Difficulty: Intermediate What you will build: Permission computation, guards for commands, and private channels via overwrites.\n\nPrerequisites: Recipe 03\n\n","category":"section"},{"location":"cookbook/06-permissions/#1.-How-Discord-Permissions-Work","page":"Permissions","title":"1. How Discord Permissions Work","text":"Permissions are a layered system:\n\nBase permissions — union of all role permissions for the member\nChannel overwrites — @everyone overwrite → role overwrites → member-specific overwrite\nSpecial cases — guild owner gets all permissions; Administrator bypasses everything\n\nwarning: ADMINISTRATOR Permission Bypass\nThe PermAdministrator permission bypasses all permission checks, including channel overwrites. A user with this permission can perform any action regardless of explicit denials.\n\nnote: Guild Owner Always Has All Permissions\nThe guild owner implicitly has every permission, including Administrator, regardless of their roles. Permission checks should always account for this using is_owner().","category":"section"},{"location":"cookbook/06-permissions/#2.-Permission-Flags-Reference","page":"Permissions","title":"2. Permission Flags Reference","text":"Accord.jl defines permissions as a Permissions bitfield type:\n\nFlag Bit Description\nPermCreateInstantInvite 0 Create channel invites\nPermKickMembers 1 Kick members\nPermBanMembers 2 Ban members\nPermAdministrator 3 Bypasses all permission checks\nPermManageChannels 4 Create/edit/delete channels\nPermManageGuild 5 Change server settings\nPermAddReactions 6 Add reactions to messages\nPermViewAuditLog 7 View audit log\nPermViewChannel 10 View channels\nPermSendMessages 11 Send messages in text channels\nPermManageMessages 13 Delete/pin other users' messages\nPermEmbedLinks 14 Send embeds\nPermAttachFiles 15 Upload files\nPermReadMessageHistory 16 Read message history\nPermMentionEveryone 17 @everyone / @here\nPermConnect 20 Connect to voice channels\nPermSpeak 21 Speak in voice channels\nPermMuteMembers 22 Mute members in voice\nPermDeafenMembers 23 Deafen members in voice\nPermMoveMembers 24 Move members between voice channels\nPermManageRoles 28 Create/edit roles below yours\nPermManageWebhooks 29 Manage webhooks\nPermModerateMembers 40 Timeout members\nPermSendVoiceMessages 46 Send voice messages\nPermSendPolls 49 Create polls","category":"section"},{"location":"cookbook/06-permissions/#Checking-Flags","page":"Permissions","title":"Checking Flags","text":"perms = [`Permissions`](@ref)(0x00000800)  # PermSendMessages\nhas_flag(perms, PermSendMessages)  # true\nhas_flag(perms, PermBanMembers)    # false","category":"section"},{"location":"cookbook/06-permissions/#Combining-Flags","page":"Permissions","title":"Combining Flags","text":"required = PermSendMessages | PermEmbedLinks | PermAttachFiles\nhas_flag(user_perms, required)  # true only if ALL are set","category":"section"},{"location":"cookbook/06-permissions/#3.-Computing-Base-Permissions","page":"Permissions","title":"3. Computing Base Permissions","text":"function get_member_permissions(client, guild_id, user_id)\n    guild = get_guild(client, guild_id)\n\n    # Get member's roles\n    member_store = get(client.state.members, guild_id, nothing)\n    isnothing(member_store) && return [`Permissions`](@ref)(0)\n    member = get(member_store, user_id)\n    isnothing(member) && return [`Permissions`](@ref)(0)\n\n    # Get guild roles from cache\n    role_store = get(client.state.roles, guild_id, nothing)\n    isnothing(role_store) && return [`Permissions`](@ref)(0)\n    guild_roles = collect(values(role_store))\n\n    member_roles = ismissing(member.roles) ? [`Snowflake`](@ref)[] : member.roles\n    owner_id = guild.owner_id\n\n    return compute_base_permissions(member_roles, guild_roles, owner_id, user_id)\nend","category":"section"},{"location":"cookbook/06-permissions/#4.-Computing-Channel-Permissions","page":"Permissions","title":"4. Computing Channel Permissions","text":"function get_channel_permissions(client, guild_id, channel_id, user_id)\n    base = get_member_permissions(client, guild_id, user_id)\n\n    channel = get_channel(client, channel_id)\n    overwrites = ismissing(channel.permission_overwrites) ? Overwrite[] : channel.permission_overwrites\n\n    member_store = get(client.state.members, guild_id, nothing)\n    isnothing(member_store) && return base\n    member = get(member_store, user_id)\n    isnothing(member) && return base\n\n    member_roles = ismissing(member.roles) ? Snowflake[] : member.roles\n\n    return compute_channel_permissions(base, member_roles, overwrites, guild_id, user_id)\nend","category":"section"},{"location":"cookbook/06-permissions/#5.-Permission-Guard-for-Commands","page":"Permissions","title":"5. Permission Guard for Commands","text":"","category":"section"},{"location":"cookbook/06-permissions/#Using-@check-Guards-(Recommended)","page":"Permissions","title":"Using @check Guards (Recommended)","text":"The cleanest way to protect commands — stack @check macros before @slash_command:\n\n# Only users with BAN_MEMBERS permission can use this\n@check has_permissions(:BAN_MEMBERS)\n@slash_command client \"ban\" \"Ban a user\" options_ban function(ctx)\n    target_id = Snowflake(get_option(ctx, \"user\", \"\"))\n    reason = get_option(ctx, \"reason\", \"No reason provided\")\n\n    create_guild_ban(ctx.client.ratelimiter, ctx.interaction.guild_id, target_id;\n        token=ctx.client.token, body=Dict(\"delete_message_seconds\" => 86400), reason=reason)\n\n    respond(ctx; content=\"Banned <@$(target_id)>. Reason: $reason\")\nend\n\nIf the user lacks the required permission, an ephemeral \"❌ You don't have permission\" message is sent automatically — no boilerplate needed.","category":"section"},{"location":"cookbook/06-permissions/#Stacking-Multiple-Checks","page":"Permissions","title":"Stacking Multiple Checks","text":"@check is_in_guild()\n@check has_permissions(:MANAGE_GUILD)\n@check is_owner()\n@slash_command client \"nuke\" \"Extreme action — owner only\" function(ctx)\n    respond(ctx; content=\"💥 Done!\")\nend\n\nAll checks must pass. If any fails, subsequent checks and the handler are skipped.","category":"section"},{"location":"cookbook/06-permissions/#Built-in-Check-Factories","page":"Permissions","title":"Built-in Check Factories","text":"Check Description\nhas_permissions(perms...) Require Discord permissions. Accepts Permissions constants or symbols (:ADMINISTRATOR, :BAN_MEMBERS).\nis_owner() Require the guild owner.\nis_in_guild() Require guild context (deny DMs).","category":"section"},{"location":"cookbook/06-permissions/#Accepts-Both-Permissions-Constants-and-Symbols","page":"Permissions","title":"Accepts Both Permissions Constants and Symbols","text":"# These are equivalent:\n@check has_permissions(PermManageGuild | PermBanMembers)\n@check has_permissions(:MANAGE_GUILD, :BAN_MEMBERS)","category":"section"},{"location":"cookbook/06-permissions/#Manual-Approach-(Legacy)","page":"Permissions","title":"Manual Approach (Legacy)","text":"For full control, you can still check permissions manually:\n\nfunction require_permissions(ctx, required::Permissions)\n    guild_id = ctx.interaction.guild_id\n    user_id = ctx.interaction.member.user.id\n\n    perms = get_member_permissions(ctx.client, guild_id, user_id)\n    if !has_flag(perms, required)\n        respond(ctx; content=\"You don't have permission to use this command.\", ephemeral=true)\n        return false\n    end\n    return true\nend\n\n# Usage in a command\noptions_ban = [\n    command_option(type=ApplicationCommandOptionTypes.USER, name=\"user\", description=\"User to ban\", required=true),\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"reason\", description=\"Ban reason\"),\n]\n\n@slash_command client \"ban\" \"Ban a user\" options_ban function(ctx)\n    require_permissions(ctx, PermBanMembers) || return\n\n    target_id = Snowflake(get_option(ctx, \"user\", \"\"))\n    reason = get_option(ctx, \"reason\", \"No reason provided\")\n\n    create_guild_ban(ctx.client.ratelimiter, ctx.interaction.guild_id, target_id;\n        token=ctx.client.token, body=Dict(\"delete_message_seconds\" => 86400), reason=reason)\n\n    respond(ctx; content=\"Banned <@$(target_id)>. Reason: $reason\")\nend","category":"section"},{"location":"cookbook/06-permissions/#6.-Common-Permission-Patterns","page":"Permissions","title":"6. Common Permission Patterns","text":"","category":"section"},{"location":"cookbook/06-permissions/#Mod-Only-Command","page":"Permissions","title":"Mod-Only Command","text":"# Using @check — clean and declarative\n@check has_permissions(:KICK_MEMBERS)\n@slash_command client \"warn\" \"Warn a user\" options_warn function(ctx)\n    respond(ctx; content=\"User warned.\")\nend","category":"section"},{"location":"cookbook/06-permissions/#Admin-Only-Command","page":"Permissions","title":"Admin-Only Command","text":"@check has_permissions(:ADMINISTRATOR)\n@slash_command client \"config\" \"Configure the bot\" function(ctx)\n    respond(ctx; content=\"Config panel:\", ephemeral=true)\nend","category":"section"},{"location":"cookbook/06-permissions/#Owner-Only-Command","page":"Permissions","title":"Owner-Only Command","text":"@check is_owner()\n@slash_command client \"shutdown\" \"Shut down the bot\" function(ctx)\n    respond(ctx; content=\"Shutting down...\")\n    stop(ctx.client)\nend","category":"section"},{"location":"cookbook/06-permissions/#Guild-Only-(No-DMs)","page":"Permissions","title":"Guild-Only (No DMs)","text":"@check is_in_guild()\n@slash_command client \"server-info\" \"Show server info\" function(ctx)\n    respond(ctx; content=\"Guild: $(ctx.guild_id)\")\nend","category":"section"},{"location":"cookbook/06-permissions/#7.-Creating-Private-Channels-via-Overwrites","page":"Permissions","title":"7. Creating Private Channels via Overwrites","text":"function create_private_channel(client, guild_id, name, user_id)\n    # @everyone can't view, specific user can\n    overwrites = [\n        Dict(\n            \"id\" => string(guild_id),    # @everyone role ID = guild ID\n            \"type\" => 0,                  # role overwrite\n            \"deny\" => string(PermViewChannel.value),\n            \"allow\" => \"0\",\n        ),\n        Dict(\n            \"id\" => string(user_id),\n            \"type\" => 1,                  # member overwrite\n            \"deny\" => \"0\",\n            \"allow\" => string((PermViewChannel | PermSendMessages | PermReadMessageHistory).value),\n        ),\n    ]\n\n    body = Dict(\n        \"name\" => name,\n        \"type\" => ChannelTypes.GUILD_TEXT,\n        \"permission_overwrites\" => overwrites,\n    )\n\n    create_guild_channel(client.ratelimiter, guild_id; token=client.token, body)\nend\n\n# Usage\nchannel = create_private_channel(client, guild_id, \"ticket-123\", user_id)\ncreate_message(client, channel.id; content=\"This channel is private to <@$(user_id)>.\")","category":"section"},{"location":"cookbook/06-permissions/#8.-Bot-Permission-Self-Check","page":"Permissions","title":"8. Bot Permission Self-Check","text":"Ensure the bot has the permissions it needs:\n\non(client, [`GuildCreate`](@ref)) do c, event\n    guild = event.guild\n    me_id = c.state.me.id\n\n    perms = get_member_permissions(c, guild.id, me_id)\n\n    required = PermSendMessages | PermEmbedLinks | PermManageMessages\n    if !has_flag(perms, required)\n        missing_perms = String[]\n        has_flag(perms, PermSendMessages) || push!(missing_perms, \"Send Messages\")\n        has_flag(perms, PermEmbedLinks) || push!(missing_perms, \"Embed Links\")\n        has_flag(perms, PermManageMessages) || push!(missing_perms, \"Manage Messages\")\n        @warn \"Missing permissions in guild\" guild=guild.name missing=missing_perms\n    end\nend\n\n\n\nNext steps: Recipe 07 — Caching to optimize state management for your bot's size.","category":"section"},{"location":"cookbook/02-messages-and-embeds/#Recipe-02-—-Rich-Messages","page":"Rich Messages","title":"Recipe 02 — Rich Messages","text":"Difficulty: Beginner What you will build: Embeds with all fields, reactions, file attachments, message editing/deletion, and a reaction-role system.\n\nPrerequisites: Recipe 01\n\n","category":"section"},{"location":"cookbook/02-messages-and-embeds/#1.-Simple-Messages","page":"Rich Messages","title":"1. Simple Messages","text":"# Plain text\ncreate_message(client, channel_id; content=\"Hello, world!\")\n\n# With a reply reference\ncreate_message(client, channel_id;\n    content=\"Replying to you!\",\n    message_reference=Dict(\n        \"message_id\" => string(original_message_id)\n    )\n)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#2.-Building-Embeds","page":"Rich Messages","title":"2. Building Embeds","text":"The embed() helper returns a Dict ready for the API:\n\ne = embed(\n    title=\"My Embed\",\n    description=\"A rich embed with all the trimmings.\",\n    url=\"https://github.com/your-org/Accord.jl\",\n    color=0x5865F2,  # Discord blurple\n    timestamp=string(Dates.now()) * \"Z\",\n    footer=Dict(\"text\" => \"Footer text\", \"icon_url\" => \"https://example.com/icon.png\"),\n    thumbnail=Dict(\"url\" => \"https://example.com/thumb.png\"),\n    image=Dict(\"url\" => \"https://example.com/image.png\"),\n    author=Dict(\n        \"name\" => \"Bot Author\",\n        \"url\" => \"https://example.com\",\n        \"icon_url\" => \"https://example.com/avatar.png\"\n    ),\n    fields=[\n        Dict(\"name\" => \"Field 1\", \"value\" => \"Value 1\", \"inline\" => true),\n        Dict(\"name\" => \"Field 2\", \"value\" => \"Value 2\", \"inline\" => true),\n        Dict(\"name\" => \"Wide Field\", \"value\" => \"This spans the full width.\"),\n    ]\n)\n\ncreate_message(client, channel_id; embeds=[e])","category":"section"},{"location":"cookbook/02-messages-and-embeds/#Color-Reference","page":"Rich Messages","title":"Color Reference","text":"const COLORS = Dict(\n    :blurple => 0x5865F2,\n    :green   => 0x57F287,\n    :yellow  => 0xFEE75C,\n    :fuchsia => 0xEB459E,\n    :red     => 0xED4245,\n    :white   => 0xFFFFFF,\n    :black   => 0x23272A,\n)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#3.-Multiple-Embeds","page":"Rich Messages","title":"3. Multiple Embeds","text":"note: Embed Limits\nDiscord imposes limits on embeds:Total characters: 6000 across all embeds in a message\nFields: Maximum 25 per embed\nField name: 256 characters maximum\nField value: 1024 characters maximum\nDescription: 4096 characters maximum\nUp to 10 embeds per message\n\nembeds = [\n    embed(title=\"Embed 1\", description=\"First\", color=0xED4245),\n    embed(title=\"Embed 2\", description=\"Second\", color=0x57F287),\n    embed(title=\"Embed 3\", description=\"Third\", color=0x5865F2),\n]\n\ncreate_message(client, channel_id; embeds=embeds)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#4.-Reactions","page":"Rich Messages","title":"4. Reactions","text":"# Unicode emoji\ncreate_reaction(client, channel_id, message_id, \"👍\")\n\n# Custom emoji — use format name:id\ncreate_reaction(client, channel_id, message_id, \"custom_emoji:123456789012345678\")","category":"section"},{"location":"cookbook/02-messages-and-embeds/#Reaction-Role-System","page":"Rich Messages","title":"Reaction-Role System","text":"# Map emoji to role IDs\nconst REACTION_ROLES = Dict(\n    \"🎮\" => [`Snowflake`](@ref)(111111111111111111),  # Gamer role\n    \"🎨\" => [`Snowflake`](@ref)(222222222222222222),  # Artist role\n    \"🎵\" => [`Snowflake`](@ref)(333333333333333333),  # Music role\n)\n\nconst ROLE_MESSAGE_ID = [`Snowflake`](@ref)(444444444444444444)  # the message to watch\n\non(client, [`MessageReactionAdd`](@ref)) do c, event\n    event.message_id != ROLE_MESSAGE_ID && return\n    ismissing(event.member) && return\n\n    # Get emoji name\n    emoji_name = event.emoji.name\n    ismissing(emoji_name) && return\n\n    role_id = get(REACTION_ROLES, emoji_name, nothing)\n    isnothing(role_id) && return\n    ismissing(event.guild_id) && return\n\n    add_guild_member_role(c.ratelimiter, event.guild_id, event.member.user.id, role_id;\n        token=c.token)\n    @info \"Added role\" role=role_id user=event.member.user.id\nend\n\non(client, [`MessageReactionRemove`](@ref)) do c, event\n    event.message_id != ROLE_MESSAGE_ID && return\n\n    emoji_name = event.emoji.name\n    ismissing(emoji_name) && return\n\n    role_id = get(REACTION_ROLES, emoji_name, nothing)\n    isnothing(role_id) && return\n    ismissing(event.guild_id) && return\n\n    remove_guild_member_role(c.ratelimiter, event.guild_id, event.user_id, role_id;\n        token=c.token)\n    @info \"Removed role\" role=role_id user=event.user_id\nend","category":"section"},{"location":"cookbook/02-messages-and-embeds/#5.-Editing-and-Deleting-Messages","page":"Rich Messages","title":"5. Editing and Deleting Messages","text":"# Edit a message\nedit_message(client, channel_id, message_id;\n    content=\"Updated content!\",\n    embeds=[embed(title=\"Updated\", color=0x57F287)]\n)\n\n# Delete a single message\ndelete_message(client, channel_id, message_id)\n\n# Bulk delete messages\nmessage_ids = [Snowflake(id1), Snowflake(id2), Snowflake(id3)]\nbulk_delete_messages(client.ratelimiter, channel_id;\n    token=client.token, message_ids=message_ids)\n\n!!! warning \"bulk_delete_messages Constraints\"\n    - Must delete between **2 and 100 messages** at a time\n    - Messages must be **less than 14 days old**\n    - Messages older than 14 days must be deleted individually with [`delete_message`](@ref)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#6.-File-Attachments","page":"Rich Messages","title":"6. File Attachments","text":"Send files using the files parameter as a vector of (filename, data) tuples:\n\n# Send a text file\ncreate_message(client, channel_id;\n    content=\"Here's a log file:\",\n    files=[(\"log.txt\", Vector{UInt8}(codeunits(\"Line 1\\nLine 2\\nLine 3\")))]\n)\n\n# Send an image from disk\nimg_data = read(\"chart.png\")\ncreate_message(client, channel_id;\n    content=\"Today's chart:\",\n    files=[(\"chart.png\", img_data)]\n)\n\n# Multiple files\ncreate_message(client, channel_id;\n    content=\"Multiple attachments:\",\n    files=[\n        (\"data.csv\", Vector{UInt8}(codeunits(\"a,b,c\\n1,2,3\"))),\n        (\"readme.txt\", Vector{UInt8}(codeunits(\"See attached data.\"))),\n    ]\n)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#7.-Embed-with-Attached-Image","page":"Rich Messages","title":"7. Embed with Attached Image","text":"Reference an attached image inside an embed using attachment://filename:\n\nimg_data = read(\"banner.png\")\ne = embed(\n    title=\"Welcome!\",\n    image=Dict(\"url\" => \"attachment://banner.png\"),\n    color=0x5865F2,\n)\ncreate_message(client, channel_id;\n    embeds=[e],\n    files=[(\"banner.png\", img_data)]\n)","category":"section"},{"location":"cookbook/02-messages-and-embeds/#8.-Practical-Example:-Info-Command","page":"Rich Messages","title":"8. Practical Example: Info Command","text":"using Dates\n\non(client, MessageCreate) do c, event\n    msg = event.message\n    ismissing(msg.author) && return\n    ismissing(msg.content) && return\n    !ismissing(msg.author.bot) && msg.author.bot == true && return\n\n    if msg.content == \"!serverinfo\"\n        ismissing(msg.guild_id) && return\n\n        guild = get_guild(c, msg.guild_id)\n        member_count = ismissing(guild.approximate_member_count) ? \"N/A\" : string(guild.approximate_member_count)\n\n        e = embed(\n            title=guild.name,\n            description=\"Server information\",\n            color=0x5865F2,\n            thumbnail=isnothing(guild.icon) ? nothing : Dict(\n                \"url\" => \"https://cdn.discordapp.com/icons/$(guild.id)/$(guild.icon).png\"\n            ),\n            fields=[\n                Dict(\"name\" => \"Owner\", \"value\" => \"<@$(guild.owner_id)>\", \"inline\" => true),\n                Dict(\"name\" => \"ID\", \"value\" => string(guild.id), \"inline\" => true),\n                Dict(\"name\" => \"Created\", \"value\" => string(timestamp(guild.id)), \"inline\" => true),\n                Dict(\"name\" => \"Verification\", \"value\" => string(guild.verification_level), \"inline\" => true),\n            ],\n            footer=Dict(\"text\" => \"Requested at $(Dates.format(now(), \"HH:MM:SS\"))\"),\n        )\n        create_message(c, msg.channel_id; embeds=[e])\n    end\nend\n\n\n\nNext steps: Recipe 03 — Slash Commands to replace prefix commands with Discord's native slash commands.","category":"section"},{"location":"cookbook/07-caching/#Recipe-07-—-Caching-Strategies","page":"Caching","title":"Recipe 07 — Caching Strategies","text":"Difficulty: Intermediate What you will build: Per-resource cache configuration, memory-efficient state for bots at any scale.\n\nPrerequisites: Recipe 01\n\n","category":"section"},{"location":"cookbook/07-caching/#1.-Why-Caching-Matters","page":"Caching","title":"1. Why Caching Matters","text":"Every time you call get_guild, get_channel, or get_user, Accord.jl checks its in-memory cache first. Cache hits avoid:\n\nREST API calls (each costs ~50-200ms)\nRate limit consumption (you only get ~50 requests/second)\n\nBut caching everything wastes memory. Accord.jl lets you choose per resource type.","category":"section"},{"location":"cookbook/07-caching/#2.-The-Four-Cache-Strategies","page":"Caching","title":"2. The Four Cache Strategies","text":"Strategy Constructor Behavior\nCacheForever CacheForever() Keep everything, never evict\nCacheNever CacheNever() Never cache, always fetch from API\nCacheLRU CacheLRU(n) Keep the n most recently used entries\nCacheTTL CacheTTL(seconds) Expire entries after seconds","category":"section"},{"location":"cookbook/07-caching/#3.-Per-Resource-Configuration","page":"Caching","title":"3. Per-Resource Configuration","text":"Configure caching in the Client constructor:\n\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages,\n\n    # Cache strategies (these are the defaults)\n    guild_strategy    = CacheForever(),     # guilds are small, keep all\n    channel_strategy  = CacheForever(),     # channels are small, keep all\n    user_strategy     = CacheLRU(10_000),   # keep 10k most active users\n    member_strategy   = CacheLRU(10_000),   # keep 10k most active members\n    presence_strategy = CacheNever(),       # presences are large, skip\n)","category":"section"},{"location":"cookbook/07-caching/#4.-Decision-Matrix","page":"Caching","title":"4. Decision Matrix","text":"Choose based on your bot's scale:\n\nBot Size Guilds Users Recommended Config\nSmall (<100 guilds) CacheForever() CacheForever() Cache everything\nMedium (100-1000 guilds) CacheForever() CacheLRU(50_000) LRU for users/members\nLarge (1000+ guilds) CacheForever() CacheLRU(100_000) LRU or TTL for users/members\nVery Large (10k+ guilds) CacheTTL(3600) CacheLRU(100_000) TTL for guilds too","category":"section"},{"location":"cookbook/07-caching/#Small-Bot-(Just-Cache-Everything)","page":"Caching","title":"Small Bot (Just Cache Everything)","text":"client = Client(token;\n    guild_strategy    = CacheForever(),\n    channel_strategy  = CacheForever(),\n    user_strategy     = CacheForever(),\n    member_strategy   = CacheForever(),\n    presence_strategy = CacheNever(),  # still skip presences\n)\n\ntip: Memory-Constrained Environments\nFor bots running on limited memory (VPS with <2GB RAM), use CacheLRU or CacheTTL strategies. Avoid CacheForever for users and members, as these can grow unbounded in large guilds.","category":"section"},{"location":"cookbook/07-caching/#Large-Bot-(Memory-Conscious)","page":"Caching","title":"Large Bot (Memory Conscious)","text":"client = Client(token;\n    guild_strategy    = CacheForever(),       # guilds are always needed\n    channel_strategy  = CacheLRU(50_000),     # only active channels\n    user_strategy     = CacheLRU(100_000),    # ~100k users\n    member_strategy   = CacheLRU(100_000),\n    presence_strategy = CacheNever(),\n)\n\nwarning: CacheNever Means REST Fallback on Every Access\nUsing CacheNever means every call to get_user, get_channel, etc. will hit the Discord REST API. This can quickly exhaust your rate limits. Only use CacheNever for data you truly don't need to cache, not as a default strategy.","category":"section"},{"location":"cookbook/07-caching/#5.-How-[Store](@ref){T}-Works-Internally","page":"Caching","title":"5. How Store{T} Works Internally","text":"Each resource type has a Store{T}:\n\nmutable struct Store{T}\n    strategy::CacheStrategy\n    data::Dict{[`Snowflake`](@ref), T}        # the actual cache\n    access_order::Vector{[`Snowflake`](@ref)}  # LRU tracking\n    timestamps::Dict{[`Snowflake`](@ref), Float64}  # TTL tracking\n    maxsize::Int\nend\n\nCacheForever: items go in data, never removed\nCacheNever: setindex! is a no-op, get always returns nothing\nCacheLRU: on access, the key moves to end of access_order; when full, the oldest is evicted\nCacheTTL: on access, checks if time() - timestamps[key] > ttl; if so, deletes and returns nothing","category":"section"},{"location":"cookbook/07-caching/#6.-Automatic-Cache-Updates","page":"Caching","title":"6. Automatic Cache Updates","text":"The cache updates automatically from gateway events:\n\nEvent Cache Action\nReadyEvent Sets state.me, caches unavailable guilds\nGuildCreate Caches guild, channels, roles, emojis, members\nGuildUpdate Updates guild\nGuildDelete Removes guild and all associated data\nChannelCreate/Update Caches channel\nChannelDelete Removes channel\nGuildMemberAdd Caches member and user\nGuildMemberRemove Removes member\nGuildMemberUpdate Updates member fields\nGuildRoleCreate/Update Caches role\nGuildRoleDelete Removes role\nMessageCreate Caches message author\nVoiceStateUpdateEvent Updates voice state tracking","category":"section"},{"location":"cookbook/07-caching/#7.-Memory-Estimation","page":"Caching","title":"7. Memory Estimation","text":"Rough per-object memory estimates:\n\nObject Approximate Size\nGuild 2-5 KB\nDiscordChannel 0.5-1 KB\nUser 0.3-0.5 KB\nMember 0.2-0.5 KB\nRole 0.2-0.3 KB\nPresence 0.5-2 KB\n\nFor a bot in 1,000 guilds with an average 500 members per guild:\n\nGuilds: 1,000 × 3 KB ≈ 3 MB\nChannels: ~15,000 × 0.7 KB ≈ 10 MB\nUsers (LRU 100k): 100,000 × 0.4 KB ≈ 40 MB\n\nTotal: ~53 MB — very manageable.","category":"section"},{"location":"cookbook/07-caching/#8.-Inspecting-the-Cache","page":"Caching","title":"8. Inspecting the Cache","text":"Use non-blocking mode for REPL inspection:\n\nstart(client; blocking=false)\nwait_until_ready(client)\n\n# Cache stats\n@info \"Guilds:   $(length(client.state.guilds))\"\n@info \"Channels: $(length(client.state.channels))\"\n@info \"Users:    $(length(client.state.users))\"\n\n# Look up a specific guild\nguild = get(client.state.guilds, [`Snowflake`](@ref)(123456789))\nguild.name\n\n# List cached roles for a guild\nroles = get(client.state.roles, [`Snowflake`](@ref)(123456789), nothing)\nif !isnothing(roles)\n    for role in values(roles)\n        println(\"  $(role.name): $(role.id)\")\n    end\nend","category":"section"},{"location":"cookbook/07-caching/#9.-Custom-Application-Level-Caching","page":"Caching","title":"9. Custom Application-Level Caching","text":"For external API data, build your own TTL cache:\n\nmutable struct TTLCache{K, V}\n    data::Dict{K, Tuple{V, Float64}}\n    ttl::Float64\nend\n\nTTLCache{K, V}(ttl::Float64) where {K, V} = TTLCache{K, V}(Dict{K, Tuple{V, Float64}}(), ttl)\n\nfunction Base.get(cache::TTLCache{K, V}, key::K, default=nothing) where {K, V}\n    if haskey(cache.data, key)\n        val, ts = cache.data[key]\n        if time() - ts <= cache.ttl\n            return val\n        end\n        delete!(cache.data, key)\n    end\n    return default\nend\n\nfunction Base.setindex!(cache::TTLCache{K, V}, value::V, key::K) where {K, V}\n    cache.data[key] = (value, time())\nend\n\n# Usage: cache weather API responses for 5 minutes\nconst weather_cache = TTLCache{String, Dict}(300.0)\n\n\n\nNext steps: Recipe 08 — Sharding if your bot is in 2,500+ guilds.","category":"section"},{"location":"cookbook/03-slash-commands/#Recipe-03-—-Slash-Commands","page":"Slash Commands","title":"Recipe 03 — Slash Commands","text":"Difficulty: Intermediate What you will build: Slash commands with options, autocomplete, subcommands, deferred responses, and followup messages.\n\nPrerequisites: Recipe 01\n\n","category":"section"},{"location":"cookbook/03-slash-commands/#1.-How-Slash-Commands-Work-in-Accord.jl","page":"Slash Commands","title":"1. How Slash Commands Work in Accord.jl","text":"The interaction flow:\n\nYou create a CommandTree and register commands on it\nOn ReadyEvent, call sync_commands! to push definitions to Discord\nOn InteractionCreate, call dispatch_interaction! to route to handlers\nEach handler receives an InteractionContext with helper methods","category":"section"},{"location":"cookbook/03-slash-commands/#2.-Basic-Slash-Command","page":"Slash Commands","title":"2. Basic Slash Command","text":"using Accord\n\ntoken = ENV[\"DISCORD_TOKEN\"]\nclient = Client(token; intents=IntentGuilds)\n\n# Register a simple command using the macro\n@slash_command client \"hello\" \"Say hello!\" function(ctx)\n    respond(ctx; content=\"Hello, <@$(ctx.interaction.member.user.id)>!\")\nend\n\n# Sync commands when ready\non(client, ReadyEvent) do c, event\n    @info \"Bot ready, syncing commands...\"\n    sync_commands!(c, c.command_tree)\nend\n\nstart(client)\n\nNote that Client automatically handles interaction dispatch to its internal command_tree.","category":"section"},{"location":"cookbook/03-slash-commands/#3.-Commands-with-Options","page":"Slash Commands","title":"3. Commands with Options","text":"Use command_option() to define typed parameters:\n\noptions = [\n    command_option(\n        type=ApplicationCommandOptionTypes.STRING,\n        name=\"name\",\n        description=\"Who to greet\",\n        required=true,\n    ),\n    command_option(\n        type=ApplicationCommandOptionTypes.INTEGER,\n        name=\"times\",\n        description=\"How many times to greet\",\n        required=false,\n        min_value=1,\n        max_value=5,\n    ),\n]\n\n@slash_command client \"greet\" \"Greet someone\" options function(ctx)\n    name = get_option(ctx, \"name\", \"World\")\n    times = get_option(ctx, \"times\", 1)\n    greeting = join(fill(\"Hello, $name!\", times), \"\\n\")\n    respond(ctx; content=greeting)\nend","category":"section"},{"location":"cookbook/03-slash-commands/#Option-Type-Reference","page":"Slash Commands","title":"Option Type Reference","text":"Constant Value Julia type returned\nApplicationCommandOptionTypes.STRING 3 String\nApplicationCommandOptionTypes.INTEGER 4 Int\nApplicationCommandOptionTypes.BOOLEAN 5 Bool\nApplicationCommandOptionTypes.USER 6 Snowflake string\nApplicationCommandOptionTypes.CHANNEL 7 Snowflake string\nApplicationCommandOptionTypes.ROLE 8 Snowflake string\nApplicationCommandOptionTypes.MENTIONABLE 9 Snowflake string\nApplicationCommandOptionTypes.NUMBER 10 Float64\nApplicationCommandOptionTypes.ATTACHMENT 11 Attachment ID","category":"section"},{"location":"cookbook/03-slash-commands/#4.-Static-Choices","page":"Slash Commands","title":"4. Static Choices","text":"options = [\n    command_option(\n        type=ApplicationCommandOptionTypes.STRING,\n        name=\"color\",\n        description=\"Pick a color\",\n        required=true,\n        choices=[\n            Dict(\"name\" => \"Red\", \"value\" => \"red\"),\n            Dict(\"name\" => \"Green\", \"value\" => \"green\"),\n            Dict(\"name\" => \"Blue\", \"value\" => \"blue\"),\n        ]\n    ),\n]\n\n@slash_command client \"color\" \"Pick a color\" options function(ctx)\n    color = get_option(ctx, \"color\", \"red\")\n    hex = Dict(\"red\" => 0xED4245, \"green\" => 0x57F287, \"blue\" => 0x5865F2)[color]\n    e = embed(title=\"You picked $color!\", color=hex)\n    respond(ctx; embeds=[e])\nend","category":"section"},{"location":"cookbook/03-slash-commands/#5.-Autocomplete","page":"Slash Commands","title":"5. Autocomplete","text":"For dynamic suggestions, mark an option as autocomplete=true and register an autocomplete handler:\n\nconst FRUITS = [\"apple\", \"apricot\", \"avocado\", \"banana\", \"blueberry\",\n                \"cherry\", \"coconut\", \"dragonfruit\", \"fig\", \"grape\",\n                \"kiwi\", \"lemon\", \"mango\", \"orange\", \"papaya\",\n                \"peach\", \"pear\", \"pineapple\", \"raspberry\", \"strawberry\"]\n\noptions = [\n    command_option(\n        type=ApplicationCommandOptionTypes.STRING,\n        name=\"fruit\",\n        description=\"Pick a fruit\",\n        required=true,\n        autocomplete=true,\n    ),\n]\n\n@slash_command client \"fruit\" \"Search for a fruit\" options function(ctx)\n    fruit = get_option(ctx, \"fruit\", \"\")\n    respond(ctx; content=\"You picked: **$fruit**\")\nend\n\n@autocomplete client \"fruit\" function(ctx)\n    query = lowercase(get_option(ctx, \"fruit\", \"\"))\n    matches = filter(f -> startswith(f, query), FRUITS)\n    choices = [Dict(\"name\" => f, \"value\" => f) for f in first(matches, 25)]\n\n    body = Dict(\n        \"type\" => InteractionCallbackTypes.APPLICATION_COMMAND_AUTOCOMPLETE_RESULT,\n        \"data\" => Dict(\"choices\" => choices)\n    )\n    create_interaction_response(ctx.client.ratelimiter, ctx.interaction.id, ctx.interaction.token;\n        token=ctx.client.token, body)\nend","category":"section"},{"location":"cookbook/03-slash-commands/#6.-Subcommands-and-Subcommand-Groups","page":"Slash Commands","title":"6. Subcommands and Subcommand Groups","text":"Subcommands are options of type SUB_COMMAND:\n\noptions = [\n    command_option(\n        type=ApplicationCommandOptionTypes.SUB_COMMAND,\n        name=\"add\",\n        description=\"Add a tag\",\n        options=[\n            command_option(type=ApplicationCommandOptionTypes.STRING, name=\"name\", description=\"Tag name\", required=true),\n            command_option(type=ApplicationCommandOptionTypes.STRING, name=\"content\", description=\"Tag content\", required=true),\n        ]\n    ),\n    command_option(\n        type=ApplicationCommandOptionTypes.SUB_COMMAND,\n        name=\"get\",\n        description=\"Get a tag\",\n        options=[\n            command_option(type=ApplicationCommandOptionTypes.STRING, name=\"name\", description=\"Tag name\", required=true),\n        ]\n    ),\n]\n\n# In-memory tag storage\nconst tags = Dict{String, String}()\n\n@slash_command client \"tag\" \"Manage tags\" options function(ctx)\n    data = ctx.interaction.data\n    ismissing(data) && return\n    ismissing(data.options) && return\n\n    sub = data.options[1]\n    sub_opts = Dict{String, Any}()\n    if !ismissing(sub.options)\n        for opt in sub.options\n            !ismissing(opt.value) && (sub_opts[opt.name] = opt.value)\n        end\n    end\n\n    if sub.name == \"add\"\n        tags[sub_opts[\"name\"]] = sub_opts[\"content\"]\n        respond(ctx; content=\"Tag **$(sub_opts[\"name\"])** created!\", ephemeral=true)\n    elseif sub.name == \"get\"\n        name = sub_opts[\"name\"]\n        content = get(tags, name, nothing)\n        if isnothing(content)\n            respond(ctx; content=\"Tag **$name** not found.\", ephemeral=true)\n        else\n            respond(ctx; content=content)\n        end\n    end\nend","category":"section"},{"location":"cookbook/03-slash-commands/#7.-Guild-vs-Global-Commands","page":"Slash Commands","title":"7. Guild vs Global Commands","text":"note: Command Sync Delay\nGlobal commands take up to 1 hour to propagate across all Discord servers. If you update a global command, users may see the old version for a while.\n\n# Global commands — available everywhere, up to 1 hour to propagate\n@slash_command client \"ping\" \"Check latency\" function(ctx)\n    respond(ctx; content=\"Pong!\")\nend\n\ntip: Use Guild Commands During Development\nGuild commands update instantly (within a few seconds). During development, sync commands to a specific guild for rapid iteration:\n\n# Guild command — instant, only in one server\nGUILD_ID = 123456789012345678\n@slash_command client GUILD_ID \"debug\" \"Debug info\" function(ctx)\n    respond(ctx; content=\"Debug mode active\", ephemeral=true)\nend\n\n# Or sync everything to a specific guild for development\non(client, [`ReadyEvent`](@ref)) do c, event\n    sync_commands!(c, c.command_tree; guild_id=[`Snowflake`](@ref)(GUILD_ID))  # instant during dev\nend","category":"section"},{"location":"cookbook/03-slash-commands/#8.-Deferred-Responses","page":"Slash Commands","title":"8. Deferred Responses","text":"If your command takes more than 3 seconds, defer first:\n\n@slash_command client \"slow\" \"A slow operation\" function(ctx)\n    defer(ctx)  # shows \"Bot is thinking...\"\n\n    # Do expensive work\n    sleep(5)\n    result = \"Done after 5 seconds!\"\n\n    # Edit the deferred response\n    respond(ctx; content=result)\nend","category":"section"},{"location":"cookbook/03-slash-commands/#Ephemeral-Deferred-Response","page":"Slash Commands","title":"Ephemeral Deferred Response","text":"@slash_command client \"secret\" \"Private slow operation\" function(ctx)\n    defer(ctx; ephemeral=true)  # only visible to the user\n\n    sleep(3)\n    respond(ctx; content=\"Secret result!\")\nend","category":"section"},{"location":"cookbook/03-slash-commands/#9.-Followup-Messages","page":"Slash Commands","title":"9. Followup Messages","text":"Send additional messages after the initial response:\n\n@slash_command client \"multi\" \"Multiple responses\" function(ctx)\n    respond(ctx; content=\"First response!\")\n\n    sleep(1)\n    followup(ctx; content=\"Here's a followup!\")\n\n    sleep(1)\n    followup(ctx; content=\"And another one!\", ephemeral=true)\nend","category":"section"},{"location":"cookbook/03-slash-commands/#10.-Edit-the-Original-Response","page":"Slash Commands","title":"10. Edit the Original Response","text":"@slash_command client \"countdown\" \"Countdown timer\" function(ctx)\n    defer(ctx)\n\n    for i in 3:-1:1\n        edit_response(ctx; content=\"**$i**...\")\n        sleep(1)\n    end\n\n    edit_response(ctx; content=\"**Go!**\")\nend\n\n","category":"section"},{"location":"cookbook/03-slash-commands/#Complete-Example","page":"Slash Commands","title":"Complete Example","text":"using Accord\n\ntoken = ENV[\"DISCORD_TOKEN\"]\nclient = Client(token; intents=IntentGuilds)\n\n# Simple command\n@slash_command client \"ping\" \"Check bot latency\" function(ctx)\n    t = time()\n    defer(ctx)\n    ms = round(Int, (time() - t) * 1000)\n    respond(ctx; content=\"Pong! API latency: **$(ms) ms**\")\nend\n\n# Command with options\noptions = [\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"text\", description=\"Text to echo\", required=true),\n    command_option(type=ApplicationCommandOptionTypes.BOOLEAN, name=\"ephemeral\", description=\"Only visible to you?\"),\n]\n\n@slash_command client \"echo\" \"Echo a message\" options function(ctx)\n    text = get_option(ctx, \"text\", \"\")\n    eph = get_option(ctx, \"ephemeral\", false)\n    respond(ctx; content=text, ephemeral=eph)\nend\n\non(client, ReadyEvent) do c, event\n    @info \"Syncing commands...\"\n    sync_commands!(c, c.command_tree)\n    @info \"Bot ready!\"\nend\n\nstart(client)\n\n\n\nNext steps: Recipe 04 — Buttons, Selects & Modals to add interactive components to your messages.","category":"section"},{"location":"cookbook/16-ai-agent/#Recipe-16-—-AI-Agent-Bot","page":"AI Agent Bot","title":"Recipe 16 — AI Agent Bot","text":"Difficulty: Advanced What you will build: A Discord bot that connects to LLM APIs (OpenAI, Anthropic Claude, Ollama) with streaming responses, tool use, conversation memory, and rate limiting.\n\nPrerequisites: Recipe 03, Recipe 04\n\n","category":"section"},{"location":"cookbook/16-ai-agent/#1.-Architecture","page":"AI Agent Bot","title":"1. Architecture","text":"User message → Discord → Accord.jl → LLM API → Discord\n                             ↑                    ↓\n                      Conversation memory    Streaming edits\n                      Tool execution         Followup messages\n\nwarning: API Key Management\nNever hardcode API keys in your source code. Use environment variables:api_key = ENV[\"OPENAI_API_KEY\"]  # Not a literal string!If you accidentally commit an API key:Revoke the key immediately via the provider's dashboard\nGenerate a new key\nUpdate your .env file\nAdd .env to .gitignore if not already there","category":"section"},{"location":"cookbook/16-ai-agent/#2.-Calling-LLM-APIs-from-Julia","page":"AI Agent Bot","title":"2. Calling LLM APIs from Julia","text":"All three major providers work via HTTP.jl.","category":"section"},{"location":"cookbook/16-ai-agent/#OpenAI","page":"AI Agent Bot","title":"OpenAI","text":"import HTTP\nimport JSON3\n\nfunction openai_chat(messages::Vector{Dict}; model=\"gpt-4o\", api_key=ENV[\"OPENAI_API_KEY\"])\n    body = Dict(\n        \"model\" => model,\n        \"messages\" => messages,\n        \"max_tokens\" => 1024,\n    )\n\n    resp = HTTP.post(\n        \"https://api.openai.com/v1/chat/completions\",\n        [\"Authorization\" => \"Bearer \\$api_key\", \"Content-Type\" => \"application/json\"],\n        JSON3.write(body)\n    )\n\n    data = JSON3.read(resp.body)\n    return data[\"choices\"][1][\"message\"][\"content\"]\nend","category":"section"},{"location":"cookbook/16-ai-agent/#Anthropic-Claude","page":"AI Agent Bot","title":"Anthropic Claude","text":"function claude_chat(messages::Vector{Dict}; model=\"claude-sonnet-4-5-20250929\", api_key=ENV[\"ANTHROPIC_API_KEY\"])\n    body = Dict(\n        \"model\" => model,\n        \"max_tokens\" => 1024,\n        \"messages\" => messages,\n    )\n\n    resp = HTTP.post(\n        \"https://api.anthropic.com/v1/messages\",\n        [\n            \"x-api-key\" => \\$api_key,\n            \"anthropic-version\" => \"2023-06-01\",\n            \"Content-Type\" => \"application/json\",\n        ],\n        JSON3.write(body)\n    )\n\n    data = JSON3.read(resp.body)\n    return data[\"content\"][1][\"text\"]\nend","category":"section"},{"location":"cookbook/16-ai-agent/#Local-Ollama","page":"AI Agent Bot","title":"Local Ollama","text":"function ollama_chat(messages::Vector{Dict}; model=\"llama3.1\", base_url=\"http://localhost:11434\")\n    body = Dict(\n        \"model\" => model,\n        \"messages\" => messages,\n        \"stream\" => false,\n    )\n\n    resp = HTTP.post(\n        \"\\$base_url/api/chat\",\n        [\"Content-Type\" => \"application/json\"],\n        JSON3.write(body)\n    )\n\n    data = JSON3.read(resp.body)\n    return data[\"message\"][\"content\"]\nend\n\ntip: Streaming Response Pattern\nFor better UX, stream LLM responses by editing the Discord message as tokens arrive. Throttle edits to ~1 per second to avoid rate limits and reduce visual flicker. Always truncate to 2000 characters (Discord's message limit).","category":"section"},{"location":"cookbook/16-ai-agent/#3.-Streaming-Responses","page":"AI Agent Bot","title":"3. Streaming Responses","text":"Show the LLM's response progressively by editing the message:\n\nfunction openai_chat_stream(messages::Vector{Dict}, update_fn::Function;\n        model=\"gpt-4o\", api_key=ENV[\"OPENAI_API_KEY\"])\n    body = Dict(\n        \"model\" => model,\n        \"messages\" => messages,\n        \"max_tokens\" => 1024,\n        \"stream\" => true,\n    )\n\n    buffer = IOBuffer()\n    last_edit = Ref(0.0)\n    full_text = Ref(\"\")\n\n    HTTP.open(\"POST\", \"https://api.openai.com/v1/chat/completions\",\n        [\"Authorization\" => \"Bearer \\$api_key\", \"Content-Type\" => \"application/json\"],\n    ) do io\n        write(io, JSON3.write(body))\n        HTTP.closewrite(io)\n\n        while !eof(io)\n            line = readline(io)\n            startswith(line, \"data: \") || continue\n            data_str = line[7:end]\n            data_str == \"[DONE]\" && break\n\n            try\n                chunk = JSON3.read(data_str)\n                delta = get(chunk[\"choices\"][1][\"delta\"], \"content\", nothing)\n                if !isnothing(delta)\n                    full_text[] *= delta\n\n                    # Throttle edits to 1 per second\n                    if time() - last_edit[] >= 1.0\n                        update_fn(full_text[])\n                        last_edit[] = time()\n                    end\n                end\n            catch\n                continue\n            end\n        end\n    end\n\n    # Final update\n    update_fn(full_text[])\n    return full_text[]\nend","category":"section"},{"location":"cookbook/16-ai-agent/#Using-with-Discord","page":"AI Agent Bot","title":"Using with Discord","text":"options_chat = [\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"message\", description=\"Your message\", required=true),\n]\n\n@slash_command client \"chat\" \"Chat with AI\" options_chat function(ctx)\n    user_msg = get_option(ctx, \"message\", \"\")\n    defer(ctx)\n\n    messages = [\n        Dict(\"role\" => \"system\", \"content\" => \"You are a helpful assistant in a Discord server. Keep responses under 2000 characters.\"),\n        Dict(\"role\" => \"user\", \"content\" => user_msg),\n    ]\n\n    openai_chat_stream(messages, text -> begin\n        try\n            truncated = length(text) > 1990 ? text[1:1990] * \"...\" : text\n            edit_response(ctx; content=truncated)\n        catch e\n            @warn \"Edit failed\" exception=e\n        end\n    end)\nend","category":"section"},{"location":"cookbook/16-ai-agent/#4.-Tool-Use-/-Function-Calling","page":"AI Agent Bot","title":"4. Tool Use / Function Calling","text":"Let the LLM call functions your bot defines:\n\n# Define available tools\nconst TOOLS = [\n    Dict(\n        \"type\" => \"function\",\n        \"function\" => Dict(\n            \"name\" => \"get_weather\",\n            \"description\" => \"Get current weather for a city\",\n            \"parameters\" => Dict(\n                \"type\" => \"object\",\n                \"properties\" => Dict(\n                    \"city\" => Dict(\"type\" => \"string\", \"description\" => \"City name\"),\n                ),\n                \"required\" => [\"city\"],\n            ),\n        ),\n    ),\n    Dict(\n        \"type\" => \"function\",\n        \"function\" => Dict(\n            \"name\" => \"roll_dice\",\n            \"description\" => \"Roll dice in NdM format\",\n            \"parameters\" => Dict(\n                \"type\" => \"object\",\n                \"properties\" => Dict(\n                    \"notation\" => Dict(\"type\" => \"string\", \"description\" => \"Dice notation like 2d6\"),\n                ),\n                \"required\" => [\"notation\"],\n            ),\n        ),\n    ),\n]\n\n# Tool implementations\nfunction execute_tool(name::String, args::Dict)\n    if name == \"get_weather\"\n        city = args[\"city\"]\n        # Simulated — replace with real API\n        return \"\"\"{\"city\": \"\\$city\", \"temp\": \"22°C\", \"condition\": \"Sunny\"}\"\"\"\n    elseif name == \"roll_dice\"\n        notation = args[\"notation\"]\n        m = match(r\"(\\d+)d(\\d+)\", notation)\n        isnothing(m) && return \"\"\"{\"error\": \"Invalid notation\"}\"\"\"\n        n, sides = parse(Int, m[1]), parse(Int, m[2])\n        rolls = [rand(1:sides) for _ in 1:n]\n        return \"\"\"{\"rolls\": \\$rolls, \"total\": \\$(sum(rolls))}\"\"\"\n    end\n    return \"\"\"{\"error\": \"Unknown tool\"}\"\"\"\nend","category":"section"},{"location":"cookbook/16-ai-agent/#Agent-Loop","page":"AI Agent Bot","title":"Agent Loop","text":"function agent_chat(messages::Vector{Dict}; model=\"gpt-4o\", api_key=ENV[\"OPENAI_API_KEY\"], max_iterations=5)\n    for _ in 1:max_iterations\n        body = Dict(\n            \"model\" => model,\n            \"messages\" => messages,\n            \"tools\" => TOOLS,\n            \"max_tokens\" => 1024,\n        )\n\n        resp = HTTP.post(\n            \"https://api.openai.com/v1/chat/completions\",\n            [\"Authorization\" => \"Bearer \\$api_key\", \"Content-Type\" => \"application/json\"],\n            JSON3.write(body)\n        )\n\n        data = JSON3.read(resp.body)\n        choice = data[\"choices\"][1]\n        msg = choice[\"message\"]\n\n        # Add assistant message to history\n        push!(messages, Dict(pairs(msg)))\n\n        # Check for tool calls\n        if choice[\"finish_reason\"] == \"tool_calls\" && haskey(msg, \"tool_calls\")\n            for tool_call in msg[\"tool_calls\"]\n                func = tool_call[\"function\"]\n                name = func[\"name\"]\n                args = JSON3.read(func[\"arguments\"], Dict{String, Any})\n\n                @info \"Tool call\" name=name args=args\n                result = execute_tool(name, args)\n\n                push!(messages, Dict(\n                    \"role\" => \"tool\",\n                    \"tool_call_id\" => tool_call[\"id\"],\n                    \"content\" => result,\n                ))\n            end\n            continue  # Loop back for LLM to process results\n        end\n\n        # No tool calls — return the response\n        return get(msg, \"content\", \"\")\n    end\n\n    return \"I ran out of steps trying to answer that.\"\nend","category":"section"},{"location":"cookbook/16-ai-agent/#5.-Conversation-Memory","page":"AI Agent Bot","title":"5. Conversation Memory","text":"Per-channel conversation history with a sliding window:\n\nconst MAX_HISTORY = 20\nconst conversations = Dict{[`Snowflake`](@ref), Vector{Dict{String,String}}}()\n\nfunction get_history(channel_id::[`Snowflake`](@ref))\n    get!(conversations, channel_id) do\n        Dict{String,String}[]\n    end\nend\n\nfunction add_message!(channel_id::[`Snowflake`](@ref), role::String, content::String)\n    history = get_history(channel_id)\n    push!(history, Dict(\"role\" => role, \"content\" => content))\n\n    # Sliding window: keep last MAX_HISTORY messages\n    while length(history) > MAX_HISTORY\n        popfirst!(history)\n    end\nend\n\nfunction clear_history!(channel_id::Snowflake)\n    conversations[channel_id] = Dict{String,String}[]\nend","category":"section"},{"location":"cookbook/16-ai-agent/#6.-Per-User-Rate-Limiting","page":"AI Agent Bot","title":"6. Per-User Rate Limiting","text":"Token bucket pattern to prevent API abuse:\n\nmutable struct TokenBucket\n    tokens::Float64\n    max_tokens::Float64\n    refill_rate::Float64  # tokens per second\n    last_refill::Float64\nend\n\nTokenBucket(max_tokens, refill_rate) = TokenBucket(max_tokens, max_tokens, refill_rate, time())\n\nfunction try_consume!(bucket::TokenBucket, n::Float64=1.0)\n    now_t = time()\n    elapsed = now_t - bucket.last_refill\n    bucket.tokens = min(bucket.max_tokens, bucket.tokens + elapsed * bucket.refill_rate)\n    bucket.last_refill = now_t\n\n    if bucket.tokens >= n\n        bucket.tokens -= n\n        return true\n    end\n    return false\nend\n\n# Per-user rate limits: 5 requests, refill 1 per 10 seconds\nconst user_buckets = Dict{Snowflake, TokenBucket}()\n\nfunction check_rate_limit(user_id::Snowflake)\n    bucket = get!(user_buckets, user_id) do\n        TokenBucket(5.0, 0.1)  # 5 requests max, 1 every 10 seconds\n    end\n    return try_consume!(bucket)\nend","category":"section"},{"location":"cookbook/16-ai-agent/#7.-Complete-Working-Bot","page":"AI Agent Bot","title":"7. Complete Working Bot","text":"using Accord\nimport HTTP\nimport JSON3\n\ntoken = ENV[\"DISCORD_TOKEN\"]\nclient = Client(token; intents=IntentGuilds)\ntree = CommandTree()\n\n# --- Configuration ---\nconst SYSTEM_PROMPT = \"\"\"You are a helpful AI assistant in a Discord server.\nKeep responses concise (under 1800 characters).\nYou can use markdown formatting.\nIf asked to do something you can't, explain why.\"\"\"\n\nconst MAX_HISTORY = 20\nconst conversations = Dict{Snowflake, Vector{Dict{String,String}}}()\nconst user_buckets = Dict{Snowflake, TokenBucket}()\n\n# --- Helpers ---\nfunction get_history(channel_id)\n    get!(conversations, channel_id, Dict{String,String}[])\nend\n\nfunction add_to_history!(channel_id, role, content)\n    history = get_history(channel_id)\n    push!(history, Dict(\"role\" => role, \"content\" => content))\n    while length(history) > MAX_HISTORY\n        popfirst!(history)\n    end\nend\n\nmutable struct TokenBucket\n    tokens::Float64\n    max_tokens::Float64\n    refill_rate::Float64\n    last_refill::Float64\nend\nTokenBucket(max_t, rate) = TokenBucket(max_t, max_t, rate, time())\n\nfunction try_consume!(b::TokenBucket)\n    elapsed = time() - b.last_refill\n    b.tokens = min(b.max_tokens, b.tokens + elapsed * b.refill_rate)\n    b.last_refill = time()\n    b.tokens >= 1.0 || return false\n    b.tokens -= 1.0\n    return true\nend\n\nfunction check_rate_limit(user_id)\n    bucket = get!(user_buckets, user_id) do; TokenBucket(5.0, 0.1) end\n    try_consume!(bucket)\nend\n\n# --- API Call ---\nfunction call_llm(messages; api_key=ENV[\"OPENAI_API_KEY\"])\n    body = Dict(\n        \"model\" => \"gpt-4o\",\n        \"messages\" => messages,\n        \"max_tokens\" => 1024,\n        \"stream\" => false,\n    )\n    resp = HTTP.post(\n        \"https://api.openai.com/v1/chat/completions\",\n        [\"Authorization\" => \"Bearer \\$api_key\", \"Content-Type\" => \"application/json\"],\n        JSON3.write(body)\n    )\n    data = JSON3.read(resp.body)\n    return data[\"choices\"][1][\"message\"][\"content\"]\nend\n\n# --- Commands ---\n\n# /chat <message>\noptions_chat = [\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"message\", description=\"Your message\", required=true),\n]\n\n@slash_command client \"chat\" \"Chat with the AI\" options_chat function(ctx)\n    user_id = ctx.interaction.member.user.id\n    channel_id = ctx.interaction.channel_id\n\n    # Rate limit check\n    if !check_rate_limit(user_id)\n        respond(ctx; content=\"You're sending messages too fast. Please wait a moment.\", ephemeral=true)\n        return\n    end\n\n    user_msg = get_option(ctx, \"message\", \"\")::String\n    defer(ctx)\n\n    # Build messages with history\n    add_to_history!(channel_id, \"user\", user_msg)\n    messages = vcat(\n        [Dict(\"role\" => \"system\", \"content\" => SYSTEM_PROMPT)],\n        get_history(channel_id)\n    )\n\n    try\n        response = call_llm(messages)\n\n        # Truncate if needed\n        if length(response) > 1990\n            response = response[1:1990] * \"...\"\n        end\n\n        add_to_history!(channel_id, \"assistant\", response)\n        respond(ctx; content=response)\n    catch e\n        @error \"LLM call failed\" exception=e\n        respond(ctx; content=\"Sorry, I couldn't process that request. Please try again.\")\n    end\nend\n\n# /clear-history\n@slash_command client \"clear-history\" \"Clear conversation history\" function(ctx)\n    channel_id = ctx.interaction.channel_id\n    conversations[channel_id] = Dict{String,String}[]\n    respond(ctx; content=\"Conversation history cleared.\", ephemeral=true)\nend\n\n# /model-info\n@slash_command client \"model-info\" \"Show AI model info\" function(ctx)\n    channel_id = ctx.interaction.channel_id\n    history_len = length(get_history(channel_id))\n\n    e = embed(\n        title=\"AI Assistant Info\",\n        color=0x5865F2,\n        fields=[\n            Dict(\"name\" => \"Model\", \"value\" => \"GPT-4o\", \"inline\" => true),\n            Dict(\"name\" => \"History\", \"value\" => \"\\$history_len / \\$MAX_HISTORY messages\", \"inline\" => true),\n            Dict(\"name\" => \"Rate Limit\", \"value\" => \"5 requests / 50 seconds\", \"inline\" => true),\n        ]\n    )\n    respond(ctx; embeds=[e], ephemeral=true)\nend\n\n# --- Wiring ---\non(client, [`InteractionCreate`](@ref)) do c, event\n    dispatch_interaction!(tree, c, event.interaction)\nend\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    sync_commands!(c, tree)\n    @info \"AI Agent bot ready!\" user=event.user.username\nend\n\nstart(client)","category":"section"},{"location":"cookbook/16-ai-agent/#8.-Advanced:-Voice-Commanded-AI-Agent","page":"AI Agent Bot","title":"8. Advanced: Voice-Commanded AI Agent","text":"Combine Recipe 05 (Voice) with this recipe for a voice-commanded agent:\n\n# Architecture:\n# 1. User speaks in voice channel\n# 2. Capture audio → PCM buffer\n# 3. Detect silence → trim audio\n# 4. pcm_to_wav() → WAV bytes\n# 5. Whisper API → transcript text\n# 6. Send transcript to LLM\n# 7. LLM response → text channel (or TTS → voice playback)\n\n# The voice capture code from Recipe 05 feeds into:\nfunction handle_voice_transcript(client, channel_id, transcript)\n    # Add to conversation and get AI response\n    add_to_history!(channel_id, \"user\", \"[Voice] \\$transcript\")\n\n    messages = vcat(\n        [Dict(\"role\" => \"system\", \"content\" => SYSTEM_PROMPT)],\n        get_history(channel_id)\n    )\n\n    response = call_llm(messages)\n    add_to_history!(channel_id, \"assistant\", response)\n\n    create_message(client, channel_id; content=response)\nend","category":"section"},{"location":"cookbook/16-ai-agent/#9.-Choosing-an-LLM-Provider","page":"AI Agent Bot","title":"9. Choosing an LLM Provider","text":"Provider Strengths Cost Local?\nOpenAI GPT-4o Tool calling, streaming, function calling $$$ No\nAnthropic Claude Long context, careful reasoning $$$ No\nOllama (Llama 3) Free, private, no rate limits Free Yes\nOllama (Mistral) Fast, good quality/speed ratio Free Yes\n\nFor development, start with Ollama (free, no API key needed). For production, choose based on your quality/cost requirements.\n\n\n\nThis recipe brings together everything in the cookbook: slash commands, embeds, async patterns, and external API integration. You now have all the tools to build production Discord bots in Julia.\n\nBack to: Cookbook Index","category":"section"},{"location":"cookbook/12-performance/#Recipe-12-—-Performance","page":"Performance","title":"Recipe 12 — Performance","text":"Difficulty: Advanced What you will build: Optimized bots using Julia-specific techniques: type stability, precompilation, async patterns, and profiling.\n\nPrerequisites: Recipe 11\n\n","category":"section"},{"location":"cookbook/12-performance/#1.-Type-Stability-in-Handlers","page":"Performance","title":"1. Type Stability in Handlers","text":"tip: Type Stability for Performance\nJulia's JIT compiler generates fast code when types are predictable. Always annotate types when extracting options from get_option, which returns Any. Use @code_warntype to identify type instabilities (look for red \"Any\" in the output).\n\nJulia's JIT compiler generates fast code when types are predictable. The get_option function returns Any — annotate it:\n\n# Slow: compiler doesn't know the type\n@slash_command client \"compute\" \"Do math\" function(ctx)\n    x = get_option(ctx, \"x\", 0)      # returns Any\n    y = get_option(ctx, \"y\", 0)      # returns Any\n    respond(ctx; content=\"Result: $(x + y)\")  # dynamic dispatch\nend\n\n# Fast: annotate types\n@slash_command client \"compute\" \"Do math\" function(ctx)\n    x = get_option(ctx, \"x\", 0)::Number\n    y = get_option(ctx, \"y\", 0)::Number\n    respond(ctx; content=\"Result: $(x + y)\")  # static dispatch\nend","category":"section"},{"location":"cookbook/12-performance/#Verify-with-@code_warntype","page":"Performance","title":"Verify with @code_warntype","text":"function handle_compute(ctx)\n    x = get_option(ctx, \"x\", 0)::Number\n    y = get_option(ctx, \"y\", 0)::Number\n    return x + y\nend\n\n# In the REPL (with a mock context):\n# @code_warntype handle_compute(ctx)\n# Look for red \"Any\" — those are type instabilities","category":"section"},{"location":"cookbook/12-performance/#2.-Precompilation","page":"Performance","title":"2. Precompilation","text":"","category":"section"},{"location":"cookbook/12-performance/#SnoopCompile-for-Precompile-Statements","page":"Performance","title":"SnoopCompile for Precompile Statements","text":"# precompile_script.jl\nusing SnoopCompile\n\ntinf = @snoopi_deep begin\n    using Accord\n\n    # Simulate typical operations\n    client = Client(\"Bot fake_token\"; intents=IntentGuilds)\n    tree = CommandTree()\n    embed(title=\"Test\", color=0x5865F2)\n    button(label=\"Test\", custom_id=\"test\")\n    action_row([button(label=\"X\", custom_id=\"x\")])\n    command_option(type=3, name=\"test\", description=\"test\")\nend\n\n# Generate precompile statements\npc = SnoopCompile.parcel(tinf)\nSnoopCompile.write(\"precompile\", pc)","category":"section"},{"location":"cookbook/12-performance/#PackageCompiler.jl-System-Image","page":"Performance","title":"PackageCompiler.jl System Image","text":"Create a custom sysimage for near-instant startup:\n\nusing PackageCompiler\n\ncreate_sysimage(\n    [\"Accord\", \"HTTP\", \"JSON3\"],\n    sysimage_path=\"bot_sysimage.so\",\n    precompile_execution_file=\"precompile_script.jl\",\n)\n\nRun with the sysimage:\n\njulia --sysimage=bot_sysimage.so --project=. bin/run.jl\n\nStartup goes from ~10s to ~1s.","category":"section"},{"location":"cookbook/12-performance/#3.-Async-Patterns","page":"Performance","title":"3. Async Patterns","text":"","category":"section"},{"location":"cookbook/12-performance/#@async-vs-Threads.@spawn","page":"Performance","title":"@async vs Threads.@spawn","text":"# @async — runs on the same thread, cooperative multitasking\n# Good for I/O-bound work (API calls, file reads)\non(client, MessageCreate) do c, event\n    @async begin\n        result = some_api_call()  # yields while waiting\n        create_message(c, event.message.channel_id; content=result)\n    end\nend\n\n# Threads.@spawn — runs on a different thread\n# Good for CPU-bound work (computation, image processing)\non(client, MessageCreate) do c, event\n    Threads.@spawn begin\n        result = expensive_computation()  # runs in parallel\n        create_message(c, event.message.channel_id; content=string(result))\n    end\nend\n\nStart Julia with multiple threads:\n\njulia --threads=4 --project=. bin/run.jl","category":"section"},{"location":"cookbook/12-performance/#Avoiding-Event-Loop-Blocking","page":"Performance","title":"Avoiding Event Loop Blocking","text":"!!! warning \"Global Variables Cause Type Instability\"\n    Avoid global mutable state. Global variables have unpredictable types, forcing the compiler to use dynamic dispatch. Instead, inject state through `Client(; state=...)` or use `const` globals with concrete types.\n\n# BAD: blocks the event loop\non(client, MessageCreate) do c, event\n    sleep(10)  # nothing else processes for 10 seconds!\n    create_message(c, event.message.channel_id; content=\"Done\")\nend\n\n# GOOD: defer to a task\non(client, MessageCreate) do c, event\n    @async begin\n        sleep(10)\n        create_message(c, event.message.channel_id; content=\"Done\")\n    end\nend","category":"section"},{"location":"cookbook/12-performance/#Channel-Based-Worker-Pattern","page":"Performance","title":"Channel-Based Worker Pattern","text":"# Process heavy work in a dedicated worker\nconst work_queue = Channel{Tuple{Client, Snowflake, String}}(100)\n\n# Worker task\n@async begin\n    for (client, channel_id, input) in work_queue\n        try\n            result = expensive_processing(input)\n            create_message(client, channel_id; content=result)\n        catch e\n            @error \"Worker error\" exception=e\n        end\n    end\nend\n\n# Handler just enqueues\non(client, MessageCreate) do c, event\n    msg = event.message\n    ismissing(msg.content) && return\n    startswith(msg.content, \"!process \") || return\n    put!(work_queue, (c, msg.channel_id, msg.content[10:end]))\nend","category":"section"},{"location":"cookbook/12-performance/#4.-Memory-Management","page":"Performance","title":"4. Memory Management","text":"","category":"section"},{"location":"cookbook/12-performance/#Cache-Sizing","page":"Performance","title":"Cache Sizing","text":"# Monitor memory usage\nfunction memory_report(client)\n    guilds = length(client.state.guilds)\n    channels = length(client.state.channels)\n    users = length(client.state.users)\n\n    total_mb = Base.summarysize(client.state) / 1024 / 1024\n\n    @info \"Memory report\" guilds channels users total_mb=round(total_mb, digits=1)\nend\n\n# Run periodically\n@async while client.running\n    sleep(300)  # every 5 minutes\n    memory_report(client)\nend","category":"section"},{"location":"cookbook/12-performance/#Avoid-String-Allocations-in-Hot-Paths","page":"Performance","title":"Avoid String Allocations in Hot Paths","text":"# Allocates a new string every call\nfunction make_greeting(name)\n    return \"Hello, $name! Welcome to the server.\"\nend\n\n# Pre-allocate with IOBuffer for complex strings\nfunction make_report(items)\n    io = IOBuffer()\n    for (i, item) in enumerate(items)\n        print(io, i, \". \", item, \"\\n\")\n    end\n    return String(take!(io))\nend","category":"section"},{"location":"cookbook/12-performance/#5.-Profiling","page":"Performance","title":"5. Profiling","text":"","category":"section"},{"location":"cookbook/12-performance/#@time-and-@allocated","page":"Performance","title":"@time and @allocated","text":"# In REPL with non-blocking mode\nstart(client; blocking=false)\n\n# Time a specific operation\n@time create_message(client, channel_id; content=\"test\")\n# 0.052 seconds (423 allocations: 28.5 KiB)\n\n@allocated embed(title=\"Test\", color=0x5865F2)\n# 1248","category":"section"},{"location":"cookbook/12-performance/#Profile.@profile","page":"Performance","title":"Profile.@profile","text":"using Profile\n\n# Profile event handling\nProfile.@profile begin\n    for i in 1:1000\n        embed(title=\"Test $i\", color=i, fields=[\n            Dict(\"name\" => \"Field\", \"value\" => \"Value\")\n        ])\n    end\nend\n\nProfile.print(mincount=10)","category":"section"},{"location":"cookbook/12-performance/#Allocation-tracking","page":"Performance","title":"Allocation tracking","text":"# Find where allocations happen\nProfile.Allocs.@profile sample_rate=1.0 begin\n    for i in 1:100\n        embed(title=\"Test\", fields=[\n            Dict(\"name\" => \"N\", \"value\" => string(i))\n        ])\n    end\nend","category":"section"},{"location":"cookbook/12-performance/#6.-Batch-Operations","page":"Performance","title":"6. Batch Operations","text":"Use batch endpoints to reduce API calls:\n\n# Instead of N individual deletes:\nfor id in message_ids\n    delete_message(client, channel_id, id)  # N API calls\nend\n\n# Use bulk delete (1 API call):\nbulk_delete_messages(client.ratelimiter, channel_id;\n    token=client.token, message_ids=message_ids)\n\n# Instead of N individual command creates:\n# Use sync_commands! which calls bulk_overwrite_global_application_commands\nsync_commands!(client, tree)  # 1 API call for all commands","category":"section"},{"location":"cookbook/12-performance/#7.-Connection-Pooling-for-External-Services","page":"Performance","title":"7. Connection Pooling for External Services","text":"# Reuse HTTP connections for external APIs\nconst http_pool = Ref{HTTP.Pool}()\n\nfunction init_pool()\n    http_pool[] = HTTP.Pool(16)  # 16 connections\nend\n\nfunction call_external_api(endpoint, body)\n    HTTP.post(endpoint, [\"Content-Type\" => \"application/json\"],\n        JSON3.write(body);\n        pool=http_pool[],\n        retry=true,\n        retries=3,\n    )\nend","category":"section"},{"location":"cookbook/12-performance/#8.-Benchmark:-Event-Handler-Overhead","page":"Performance","title":"8. Benchmark: Event Handler Overhead","text":"using BenchmarkTools\n\n# Measure handler dispatch overhead\neh = EventHandler()\nregister_handler!(eh, MessageCreate, (c, e) -> nothing)\n\n# Create a fake event\nfake_msg = Message(id=Snowflake(1), channel_id=Snowflake(2))\nfake_event = MessageCreate(fake_msg)\n\n@benchmark dispatch_event!($eh, nothing, $fake_event)\n# Should be < 1μs — handler dispatch is not your bottleneck\n\n\n\nNext steps: Recipe 13 — Deployment for running your bot in production.","category":"section"},{"location":"cookbook/14-troubleshooting/#Recipe-14-—-Troubleshooting","page":"Troubleshooting","title":"Recipe 14 — Troubleshooting","text":"Difficulty: All levels What you will build: A reference for diagnosing common errors, gateway issues, and interaction failures.\n\nPrerequisites: Recipe 01\n\n\n\nwarning: Common Pitfalls\nMost bot issues fall into these categories:Wrong intents: Missing IntentMessageContent for reading messages, missing privileged intents\nMissing permissions: Bot lacks required Discord permissions for actions\nToken issues: Wrong token format, expired tokens, or missing \"Bot \" prefix\nTiming: Interaction responses taking longer than 3 seconds","category":"section"},{"location":"cookbook/14-troubleshooting/#1.-Common-Error-Table","page":"Troubleshooting","title":"1. Common Error Table","text":"Error Cause Fix\nGateway close 4004 Authentication failed Check your token; ensure Bot prefix\nGateway close 4014 Disallowed intent(s) Enable privileged intents in Developer Portal\nHTTP 401 Invalid token Regenerate token in Developer Portal\nHTTP 403 Missing permissions Check bot's role permissions in server\nHTTP 429 Rate limited Reduce request rate; Accord.jl handles this automatically\nHTTP 400 Bad request body Check payload format; log the body before sending\ncontent is empty Missing IntentMessageContent Enable Message Content intent\nNo message events Missing IntentGuildMessages Add IntentGuildMessages to intents\nNo member events Missing IntentGuildMembers Enable privileged intent + add to intents\nInteraction failed Response took >3 seconds Use defer(ctx) before slow operations\n\"Unknown interaction\" Double response or expired Don't respond twice; respond within 15 minutes\n\"Interaction already acknowledged\" Called respond after defer + respond Use edit_response after defer, not respond (note: Accord.jl handles this — respond auto-detects deferred state)\n\ntip: Enable Debug Logging\nWhen troubleshooting, enable debug logging to see detailed event and request information:ENV[\"JULIA_DEBUG\"] = \"Accord\"  # Accord.jl specific\nENV[\"JULIA_DEBUG\"] = \"all\"     # All packages (very verbose)","category":"section"},{"location":"cookbook/14-troubleshooting/#2.-Debug-Logging","page":"Troubleshooting","title":"2. Debug Logging","text":"Enable debug output from Accord.jl:\n\n# Before starting the client\nENV[\"JULIA_DEBUG\"] = \"Accord\"\n\n# Or for everything:\nENV[\"JULIA_DEBUG\"] = \"all\"","category":"section"},{"location":"cookbook/14-troubleshooting/#Custom-Logging","page":"Troubleshooting","title":"Custom Logging","text":"using Logging\n\n# Log to file with timestamps\nio = open(\"bot.log\", \"a\")\nlogger = SimpleLogger(io, Logging.Debug)\nglobal_logger(logger)\n\n# Log all events\non(client, AbstractEvent) do c, event\n    @debug \"Event received\" type=typeof(event) time=time()\nend","category":"section"},{"location":"cookbook/14-troubleshooting/#3.-Gateway-Issues","page":"Troubleshooting","title":"3. Gateway Issues","text":"","category":"section"},{"location":"cookbook/14-troubleshooting/#Gateway-Opcodes","page":"Troubleshooting","title":"Gateway Opcodes","text":"Opcode Name Direction\n0 Dispatch Receive\n1 Heartbeat Send/Receive\n2 Identify Send\n6 Resume Send\n7 Reconnect Receive\n9 Invalid Session Receive\n10 Hello Receive\n11 Heartbeat ACK Receive","category":"section"},{"location":"cookbook/14-troubleshooting/#Gateway-Close-Codes","page":"Troubleshooting","title":"Gateway Close Codes","text":"Code Meaning Can Resume?\n4000 Unknown error Yes\n4001 Unknown opcode Yes\n4002 Decode error Yes\n4003 Not authenticated No\n4004 Authentication failed No — check token\n4005 Already authenticated Yes\n4007 Invalid seq No — new session\n4008 Rate limited Yes\n4009 Session timed out No — new session\n4010 Invalid shard No — check shard config\n4011 Sharding required No — enable sharding\n4012 Invalid API version No — update library\n4013 Invalid intents No — check intent value\n4014 Disallowed intents No — enable in portal","category":"section"},{"location":"cookbook/14-troubleshooting/#Resume-vs-New-Session","page":"Troubleshooting","title":"Resume vs New Session","text":"Accord.jl handles reconnection automatically. If you see frequent reconnects:\n\non(client, ResumedEvent) do c, event\n    @info \"Gateway connection resumed\"\nend\n\non(client, ReadyEvent) do c, event\n    @info \"New gateway session established\" guilds=length(event.guilds)\nend\n\nIf you see many ReadyEvents but few ResumedEvents, the bot may be losing its session (network issues, too slow to heartbeat).","category":"section"},{"location":"cookbook/14-troubleshooting/#4.-Interaction-Failures","page":"Troubleshooting","title":"4. Interaction Failures","text":"","category":"section"},{"location":"cookbook/14-troubleshooting/#The-3-Second-Rule","page":"Troubleshooting","title":"The 3-Second Rule","text":"Discord requires an initial response within 3 seconds. If your handler is slow:\n\n# BAD: will fail if database is slow\n@slash_command client \"lookup\" \"Look up data\" function(ctx)\n    result = slow_database_query()  # might take 5 seconds\n    respond(ctx; content=result)     # TOO LATE — interaction expired\nend\n\n# GOOD: defer first\n@slash_command client \"lookup\" \"Look up data\" function(ctx)\n    defer(ctx)                       # immediate acknowledgment\n    result = slow_database_query()   # take as long as needed (up to 15 min)\n    respond(ctx; content=result)     # edits the deferred response\nend","category":"section"},{"location":"cookbook/14-troubleshooting/#Double-Response-Errors","page":"Troubleshooting","title":"Double Response Errors","text":"# BAD: responding twice\n@slash_command client \"test\" \"Test\" function(ctx)\n    respond(ctx; content=\"First\")\n    respond(ctx; content=\"Second\")   # ERROR: already responded\nend\n\n# GOOD: use followup for additional messages\n@slash_command client \"test\" \"Test\" function(ctx)\n    respond(ctx; content=\"First\")\n    followup(ctx; content=\"Second\")  # followup works after initial response\nend","category":"section"},{"location":"cookbook/14-troubleshooting/#Component-Interaction-Response-Types","page":"Troubleshooting","title":"Component Interaction Response Types","text":"When handling button/select interactions, respond auto-selects UPDATE_MESSAGE (updates the original message). If you want a new message instead:\n\nregister_component!(tree, \"my_btn\", function(ctx)\n    # This updates the message the button is on:\n    respond(ctx; content=\"Updated!\")\n\n    # For a separate ephemeral reply, use followup:\n    # defer(ctx)  # acknowledge first\n    # followup(ctx; content=\"Separate reply!\", ephemeral=true)\nend)","category":"section"},{"location":"cookbook/14-troubleshooting/#5.-Rate-Limit-Debugging","page":"Troubleshooting","title":"5. Rate Limit Debugging","text":"Accord.jl handles rate limits automatically, but you can monitor them:\n\n# Check if you're hitting rate limits frequently\nregister_middleware!(client.event_handler) do client, event\n    if event isa InteractionCreate\n        @debug \"Interaction received\" id=event.interaction.id type=event.interaction.type\n    end\n    return event\nend","category":"section"},{"location":"cookbook/14-troubleshooting/#Common-Rate-Limit-Scenarios","page":"Troubleshooting","title":"Common Rate Limit Scenarios","text":"Action Rate Limit Notes\nSend messages 5/5s per channel Spread across channels\nEdit messages 5/5s per channel Same bucket as send\nCreate reactions 1/0.25s Very tight\nBulk delete 1/1s Max 100 messages\nGlobal commands 200/day Use guild commands for dev\nGateway identify 1/5s Respect shard startup delay","category":"section"},{"location":"cookbook/14-troubleshooting/#6.-Voice-Connection-Debugging","page":"Troubleshooting","title":"6. Voice Connection Debugging","text":"# Verbose voice connection logging\nENV[\"JULIA_DEBUG\"] = \"Accord\"\n\n# Check voice states\nfunction debug_voice(client, guild_id)\n    vs = get(client.state.voice_states, guild_id, nothing)\n    if isnothing(vs)\n        @info \"No voice states for guild\"\n        return\n    end\n    for (uid, state) in vs\n        @info \"Voice state\" user=uid channel=state.channel_id session=state.session_id\n    end\nend","category":"section"},{"location":"cookbook/14-troubleshooting/#Common-Voice-Issues","page":"Troubleshooting","title":"Common Voice Issues","text":"Issue Cause Fix\nconnect! hangs Missing IntentGuildVoiceStates Add intent\nNo audio output Missing ffmpeg Install ffmpeg\n\"No encryption key\" Session not fully established Wait longer after connect\nAudio cuts out Network jitter Check server connection\nOpus encode errors Wrong PCM format Ensure 48kHz, 16-bit, stereo","category":"section"},{"location":"cookbook/14-troubleshooting/#7.-REPL-Driven-Debugging","page":"Troubleshooting","title":"7. REPL-Driven Debugging","text":"Use non-blocking mode to inspect live state:\n\nstart(client; blocking=false)\nwait_until_ready(client)\n\n# Inspect client state\nclient.state.me                          # bot user\nclient.state.me.username                 # bot username\nlength(client.state.guilds)              # cached guild count\nlength(client.state.channels)            # cached channel count\n\n# Check a specific guild\nguild = get(client.state.guilds, Snowflake(123456789))\nguild.name\nguild.owner_id\n\n# Check shard status\nfor shard in client.shards\n    @info \"Shard\" id=shard.id connected=shard.session.connected\nend\n\n# Send a test message\ncreate_message(client, Snowflake(123456789); content=\"Test from REPL\")\n\n# Test an embed\ne = embed(title=\"Debug\", description=\"Testing\", color=0xFEE75C)\ncreate_message(client, Snowflake(123456789); embeds=[e])","category":"section"},{"location":"cookbook/14-troubleshooting/#8.-Checklist-for-New-Bots","page":"Troubleshooting","title":"8. Checklist for New Bots","text":"Token starts with Bot (Accord.jl adds this automatically)\nBot is invited with correct permissions (use OAuth2 URL generator)\nRequired intents are enabled in Developer Portal\nRequired intents are passed to Client()\nIntentMessageContent is enabled if reading message content\nInteractionCreate handler calls dispatch_interaction!\nReadyEvent handler calls sync_commands!\nCommand responses happen within 3 seconds (or use defer)\n.env file is in .gitignore\nError handler is registered with on_error\n\n\n\nNext steps: Recipe 15 — Why Julia? for the case for building Discord bots in Julia.","category":"section"},{"location":"cookbook/01-basic-bot/#Recipe-01-—-Your-First-Bot","page":"Your First Bot","title":"Recipe 01 — Your First Bot","text":"Difficulty: Beginner What you will build: A Discord bot that responds to messages, measures latency, and runs interactively in the REPL.\n\n","category":"section"},{"location":"cookbook/01-basic-bot/#1.-Project-Setup","page":"Your First Bot","title":"1. Project Setup","text":"# Create a new project\nmkdir MyBot && cd MyBot\njulia --project=. -e 'using Pkg; Pkg.add(\"Accord\")'\n\nYour Project.toml now tracks Accord.jl as a dependency.","category":"section"},{"location":"cookbook/01-basic-bot/#2.-Token-Management","page":"Your First Bot","title":"2. Token Management","text":"tip: Token Security\nNever commit your Discord token to version control. Create a .env file and add it to .gitignore immediately.\n\n# .env\nDISCORD_TOKEN=Bot MTIzNDU2Nzg5MDEyMzQ1Njc4OQ.XXXXXX.XXXXXXXXXXXXXXXXXXXXXXXX\n\n# .gitignore\n.env\nManifest.toml\n\nLoad it in your bot:\n\n# Load token from environment\nfunction load_env(path=\".env\")\n    isfile(path) || return\n    for line in eachline(path)\n        stripped = strip(line)\n        (isempty(stripped) || startswith(stripped, '#')) && continue\n        key, value = split(stripped, '='; limit=2)\n        ENV[strip(key)] = strip(value)\n    end\nend\n\nload_env()\ntoken = ENV[\"DISCORD_TOKEN\"]","category":"section"},{"location":"cookbook/01-basic-bot/#3.-Hello-World-Bot","page":"Your First Bot","title":"3. Hello World Bot","text":"using Accord\n\nload_env()  # from above\ntoken = ENV[\"DISCORD_TOKEN\"]\n\n# Create client with specific intents\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentMessageContent\n)\n\n!!! note \"Intents\"\n    Gateway intents control which events your bot receives. You must declare both `IntentGuildMessages` (for message events) and `IntentMessageContent` (to read actual message text). Without these, your bot won't see message content!\n\n# Log when connected\non(client, [`ReadyEvent`](@ref)) do c, event\n    @info \"Bot online!\" user=event.user.username guilds=length(event.guilds)\nend\n\n# Respond to messages\non(client, [`MessageCreate`](@ref)) do c, event\n    msg = event.message\n    ismissing(msg.author) && return\n    ismissing(msg.content) && return\n    !ismissing(msg.author.bot) && msg.author.bot == true && return\n\n    if msg.content == \"!hello\"\n        create_message(c, msg.channel_id; content=\"Hello from Accord.jl!\")\n    end\nend\n\nstart(client)\n\nRun it:\n\njulia --project=. bot.jl","category":"section"},{"location":"cookbook/01-basic-bot/#4.-Ping/Pong-with-Latency","page":"Your First Bot","title":"4. Ping/Pong with Latency","text":"on(client, MessageCreate) do c, event\n    msg = event.message\n    ismissing(msg.author) && return\n    ismissing(msg.content) && return\n    !ismissing(msg.author.bot) && msg.author.bot == true && return\n\n    if msg.content == \"!ping\"\n        t_start = time()\n        sent = create_message(c, msg.channel_id; content=\"Pong!\")\n        latency_ms = round(Int, (time() - t_start) * 1000)\n\n        e = embed(\n            title=\"Pong!\",\n            description=\"Round-trip latency: **$(latency_ms) ms**\",\n            color=0x57F287  # green\n        )\n        edit_message(c, msg.channel_id, sent.id; embeds=[e])\n    end\nend","category":"section"},{"location":"cookbook/01-basic-bot/#5.-Understanding-Intents","page":"Your First Bot","title":"5. Understanding Intents","text":"Intents control which events your bot receives. Combine them with |:\n\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentMessageContent\n)","category":"section"},{"location":"cookbook/01-basic-bot/#Intent-Reference","page":"Your First Bot","title":"Intent Reference","text":"Intent Bit Privileged Events\nIntentGuilds 0 No GuildCreate, GuildUpdate, GuildDelete, channels, roles\nIntentGuildMembers 1 Yes GuildMemberAdd/Remove/Update\nIntentGuildModeration 2 No GuildBanAdd/Remove, GuildAuditLogEntryCreate\nIntentGuildExpressions 3 No GuildEmojisUpdate, GuildStickersUpdate\nIntentGuildIntegrations 4 No IntegrationCreate/Update/Delete\nIntentGuildWebhooks 5 No WebhooksUpdate\nIntentGuildInvites 6 No InviteCreate/Delete\nIntentGuildVoiceStates 7 No VoiceStateUpdateEvent\nIntentGuildPresences 8 Yes PresenceUpdate\nIntentGuildMessages 9 No MessageCreate/Update/Delete in guilds\nIntentGuildMessageReactions 10 No MessageReactionAdd/Remove\nIntentGuildMessageTyping 11 No TypingStart\nIntentDirectMessages 12 No MessageCreate/Update/Delete in DMs\nIntentDirectMessageReactions 13 No MessageReactionAdd/Remove in DMs\nIntentDirectMessageTyping 14 No TypingStart in DMs\nIntentMessageContent 15 Yes Populates message.content, embeds, attachments\nIntentGuildScheduledEvents 16 No ScheduledEvent events\nIntentAutoModerationConfiguration 20 No AutoModerationRuleCreate/Update/Delete\nIntentAutoModerationExecution 21 No AutoModerationActionExecution\nIntentGuildMessagePolls 24 No MessagePollVoteAdd/Remove\nIntentDirectMessagePolls 25 No MessagePollVoteAdd/Remove in DMs\n\nPrivileged intents must be enabled in the Discord Developer Portal under Bot > Privileged Gateway Intents.\n\nwarning: MESSAGE_CONTENT Intent Required\nAs of 2022, Discord requires the privileged IntentMessageContent intent to receive message content. Without this intent, message.content will be empty or missing. You must enable this in the Developer Portal AND pass it in the Client constructor.\n\nShortcuts:\n\nIntentAllNonPrivileged  # all non-privileged intents (default)\nIntentAll               # all intents including privileged","category":"section"},{"location":"cookbook/01-basic-bot/#6.-Non-Blocking-Mode-(REPL-Development)","page":"Your First Bot","title":"6. Non-Blocking Mode (REPL Development)","text":"Start the bot without blocking your REPL:\n\nstart(client; blocking=false)\n\n# Now you can interact with the client live:\nwait_until_ready(client)\n@info \"Bot user: $(client.state.me.username)\"\n\n# Send a message from the REPL\ncreate_message(client, [`Snowflake`](@ref)(123456789); content=\"Hello from the REPL!\")\n\n# Inspect cached state\n@info \"Guilds cached: $(length(client.state.guilds))\"\n\nThis is extremely useful during development — you get a live REPL connected to Discord.","category":"section"},{"location":"cookbook/01-basic-bot/#7.-Graceful-Shutdown","page":"Your First Bot","title":"7. Graceful Shutdown","text":"# Stop the client cleanly\nstop(client)\n\nIn blocking mode, pressing Ctrl+C triggers a graceful shutdown automatically.","category":"section"},{"location":"cookbook/01-basic-bot/#8.-Handling-Multiple-Events","page":"Your First Bot","title":"8. Handling Multiple Events","text":"You can register multiple handlers for the same event:\n\n# Analytics handler\non(client, [`MessageCreate`](@ref)) do c, event\n    @debug \"Message received\" channel=event.message.channel_id\nend\n\n# Command handler (both run independently)\non(client, [`MessageCreate`](@ref)) do c, event\n    msg = event.message\n    ismissing(msg.content) && return\n    msg.content == \"!ping\" && create_message(c, msg.channel_id; content=\"Pong!\")\nend\n\n# Catch-all: log every event type\non(client, [`AbstractEvent`](@ref)) do c, event\n    @debug \"Event\" type=typeof(event)\nend","category":"section"},{"location":"cookbook/01-basic-bot/#9.-Logging-Guild-Activity","page":"Your First Bot","title":"9. Logging Guild Activity","text":"on(client, [`GuildCreate`](@ref)) do c, event\n    @info \"Guild available\" name=event.guild.name id=event.guild.id\nend\n\non(client, [`GuildMemberAdd`](@ref)) do c, event\n    @info \"Member joined\" guild_id=event.guild_id\n    # Note: requires IntentGuildMembers (privileged)\nend\n\n","category":"section"},{"location":"cookbook/01-basic-bot/#Complete-Example","page":"Your First Bot","title":"Complete Example","text":"using Accord\n\n# Load token\ntoken = get(ENV, \"DISCORD_TOKEN\", \"\")\nisempty(token) && error(\"Set DISCORD_TOKEN environment variable\")\n\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentMessageContent\n)\n\non(client, ReadyEvent) do c, event\n    @info \"Bot online!\" user=event.user.username guilds=length(event.guilds)\nend\n\non(client, MessageCreate) do c, event\n    msg = event.message\n    ismissing(msg.author) && return\n    ismissing(msg.content) && return\n    !ismissing(msg.author.bot) && msg.author.bot == true && return\n\n    if msg.content == \"!ping\"\n        t = time()\n        sent = create_message(c, msg.channel_id; content=\"Pinging...\")\n        ms = round(Int, (time() - t) * 1000)\n        edit_message(c, msg.channel_id, sent.id;\n            content=\"Pong! Latency: **$(ms) ms**\")\n    elseif msg.content == \"!info\"\n        e = embed(\n            title=\"Bot Info\",\n            color=0x5865F2,\n            fields=[\n                Dict(\"name\" => \"Library\", \"value\" => \"Accord.jl\", \"inline\" => true),\n                Dict(\"name\" => \"Julia\", \"value\" => string(VERSION), \"inline\" => true),\n            ]\n        )\n        create_message(c, msg.channel_id; embeds=[e])\n    end\nend\n\non(client, GuildCreate) do c, event\n    @info \"Guild available\" name=event.guild.name id=event.guild.id\nend\n\n@info \"Starting bot...\"\nstart(client)\n\n\n\nNext steps: Recipe 02 — Rich Messages to learn about embeds, reactions, and file attachments.","category":"section"},{"location":"cookbook/05-voice/#Recipe-05-—-Voice:-Playback,-Recording-and-Transcription","page":"Voice","title":"Recipe 05 — Voice: Playback, Recording & Transcription","text":"Difficulty: Advanced What you will build: A voice bot that plays audio, records speech, and transcribes it with the Whisper API.\n\nPrerequisites: Recipe 03, ffmpeg installed, IntentGuildVoiceStates enabled\n\n\n\nwarning: System Dependencies for Voice\nAccord.jl's voice support requires:Opus_jll and libsodium_jll — bundled automatically via JLL packages\nFFmpeg — must be installed on your system and available in PATH for FFmpegSourceInstall FFmpeg:Ubuntu/Debian: sudo apt-get install ffmpeg\nmacOS: brew install ffmpeg\nWindows: Download from https://ffmpeg.org/download.html","category":"section"},{"location":"cookbook/05-voice/#1.-Prerequisites","page":"Voice","title":"1. Prerequisites","text":"client = Client(token;\n    intents = IntentGuilds | IntentGuildVoiceStates\n)\n\nnote: Voice Connection Timeout Behavior\nVoice connections may take several seconds to establish as they require:Gateway handshake (VOICESTATEUPDATE)\nVoice server assignment (VoiceServerUpdate event)\nVoice WebSocket connection\nUDP IP discovery\nEncryption negotiationIf connect! hangs, verify IntentGuildVoiceStates is enabled and the bot has permission to connect to the voice channel.","category":"section"},{"location":"cookbook/05-voice/#2.-Connecting-to-Voice","page":"Voice","title":"2. Connecting to Voice","text":"using Accord\n\nvc = [`VoiceClient`](@ref)(client, guild_id, voice_channel_id)\n\n# Full handshake: gateway → voice WS → UDP → ready\nconnect!(vc)\n\n# Later, disconnect\ndisconnect!(vc)\n\nThe connect! flow:\n\nSends VOICE_STATE_UPDATE to the gateway\nWaits for VoiceStateUpdateEvent and VoiceServerUpdate events\nConnects to the voice WebSocket\nPerforms IP discovery via UDP\nSelects encryption mode and establishes the session","category":"section"},{"location":"cookbook/05-voice/#3.-Playing-Audio","page":"Voice","title":"3. Playing Audio","text":"","category":"section"},{"location":"cookbook/05-voice/#From-Any-File-(via-FFmpeg)","page":"Voice","title":"From Any File (via FFmpeg)","text":"source = [`FFmpegSource`](@ref)(\"song.mp3\")\nplay!(vc, source)\n\nFFmpegSource handles any format ffmpeg supports: MP3, FLAC, OGG, WAV, M4A, URLs, etc.\n\n# Play from a URL\nsource = [`FFmpegSource`](@ref)(\"https://example.com/stream.mp3\")\nplay!(vc, source)\n\n# Adjust volume at the ffmpeg level\nsource = [`FFmpegSource`](@ref)(\"song.mp3\"; volume=0.5)\nplay!(vc, source)","category":"section"},{"location":"cookbook/05-voice/#From-Raw-PCM","page":"Voice","title":"From Raw PCM","text":"# Raw PCM Int16, 48kHz stereo\npcm_data = zeros(Int16, 48000 * 2 * 5)  # 5 seconds of silence\nsource = [`PCMSource`](@ref)(pcm_data)\nplay!(vc, source)","category":"section"},{"location":"cookbook/05-voice/#From-a-Raw-PCM-File","page":"Voice","title":"From a Raw PCM File","text":"# File must be: 48kHz, 16-bit signed little-endian, stereo\nsource = [`FileSource`](@ref)(\"audio.raw\")\nplay!(vc, source)","category":"section"},{"location":"cookbook/05-voice/#Silence-(Keep-Alive)","page":"Voice","title":"Silence (Keep-Alive)","text":"# 5 seconds of silence to keep the voice connection alive\nsource = [`SilenceSource`](@ref)(5000)\nplay!(vc, source)","category":"section"},{"location":"cookbook/05-voice/#4.-Playback-Control","page":"Voice","title":"4. Playback Control","text":"player = vc.player\n\n# Pause/resume\npause!(player)\nresume!(player)\n\n# Check status\nis_playing(player)  # true/false\n\n# Volume (0.0 to 2.0, applied to PCM before encoding)\nplayer.volume = 0.5   # 50%\nplayer.volume = 1.5   # 150%\n\n# Stop playback\nstop!(vc)","category":"section"},{"location":"cookbook/05-voice/#5.-Opus-Encoding-Details","page":"Voice","title":"5. Opus Encoding Details","text":"Discord requires Opus-encoded audio:\n\nSample rate: 48,000 Hz\nChannels: 2 (stereo)\nFrame duration: 20 ms\nFrame size: 960 samples per channel (1,920 total)\n\nAccord.jl handles this automatically when you use play!. For manual encoding:\n\nencoder = [`OpusEncoder`](@ref)()  # defaults: 48kHz, stereo, AUDIO application\n\npcm_frame = rand(Int16, 960 * 2)  # one 20ms frame\nopus_data = opus_encode(encoder, pcm_frame)\n\n# Decoding\ndecoder = [`OpusDecoder`](@ref)()\npcm_out = opus_decode(decoder, opus_data)","category":"section"},{"location":"cookbook/05-voice/#6.-Voice-Transcription","page":"Voice","title":"6. Voice Transcription","text":"This recipe captures incoming voice audio and sends it to OpenAI's Whisper API for transcription.","category":"section"},{"location":"cookbook/05-voice/#Architecture","page":"Voice","title":"Architecture","text":"Discord Voice → UDP packets → Opus decode → PCM buffer\n                                              ↓\n                              Silence detected → WAV file\n                                              ↓\n                              Whisper API → Transcript → Text channel","category":"section"},{"location":"cookbook/05-voice/#PCM-to-WAV-Helper","page":"Voice","title":"PCM to WAV Helper","text":"function pcm_to_wav(pcm::Vector{Int16}; sample_rate=48000, channels=2)\n    data_size = length(pcm) * sizeof(Int16)\n    file_size = 36 + data_size\n\n    io = IOBuffer()\n    # RIFF header\n    write(io, b\"RIFF\")\n    write(io, UInt32(file_size))\n    write(io, b\"WAVE\")\n    # fmt chunk\n    write(io, b\"fmt \")\n    write(io, UInt32(16))          # chunk size\n    write(io, UInt16(1))           # PCM format\n    write(io, UInt16(channels))\n    write(io, UInt32(sample_rate))\n    write(io, UInt32(sample_rate * channels * sizeof(Int16)))  # byte rate\n    write(io, UInt16(channels * sizeof(Int16)))                 # block align\n    write(io, UInt16(16))          # bits per sample\n    # data chunk\n    write(io, b\"data\")\n    write(io, UInt32(data_size))\n    write(io, pcm)\n\n    return take!(io)\nend","category":"section"},{"location":"cookbook/05-voice/#Transcription-with-Whisper-API","page":"Voice","title":"Transcription with Whisper API","text":"import HTTP\nimport JSON3\n\nfunction transcribe_audio(wav_bytes::Vector{UInt8}; api_key=ENV[\"OPENAI_API_KEY\"])\n    # Build multipart form\n    body = HTTP.Forms.Form(Dict(\n        \"file\" => HTTP.Forms.File(wav_bytes, \"audio.wav\", \"audio/wav\"),\n        \"model\" => \"whisper-1\",\n        \"language\" => \"en\",\n    ))\n\n    resp = HTTP.post(\n        \"https://api.openai.com/v1/audio/transcriptions\",\n        [\"Authorization\" => \"Bearer $api_key\"],\n        body\n    )\n\n    result = JSON3.read(resp.body)\n    return result[\"text\"]\nend","category":"section"},{"location":"cookbook/05-voice/#Capture-and-Transcribe-Loop","page":"Voice","title":"Capture and Transcribe Loop","text":"This is a conceptual pattern for capturing voice data per user (SSRC):\n\n# Per-user audio buffers\nconst audio_buffers = Dict{UInt32, Vector{Int16}}()  # SSRC → PCM samples\nconst decoders = Dict{UInt32, OpusDecoder}()\nconst silence_counters = Dict{UInt32, Int}()\n\nconst SILENCE_THRESHOLD = 50     # ~1 second of silence (50 × 20ms frames)\nconst MIN_AUDIO_FRAMES = 25      # at least 0.5s of speech\n\nfunction process_voice_packet(ssrc::UInt32, opus_data::Vector{UInt8})\n    dec = get!(decoders, ssrc) do; OpusDecoder() end\n    buf = get!(audio_buffers, ssrc) do; Int16[] end\n\n    pcm = opus_decode(dec, opus_data)\n\n    # Simple energy-based silence detection\n    energy = sum(abs.(Float64.(pcm))) / length(pcm)\n    if energy < 100.0\n        silence_counters[ssrc] = get(silence_counters, ssrc, 0) + 1\n\n        if silence_counters[ssrc] >= SILENCE_THRESHOLD && length(buf) > MIN_AUDIO_FRAMES * 960 * 2\n            # Silence detected after speech — transcribe\n            wav = pcm_to_wav(buf)\n            audio_buffers[ssrc] = Int16[]\n            silence_counters[ssrc] = 0\n\n            @async begin\n                try\n                    text = transcribe_audio(wav)\n                    if !isempty(strip(text))\n                        create_message(client, text_channel_id;\n                            content=\"**SSRC $ssrc**: $text\")\n                    end\n                catch e\n                    @error \"Transcription failed\" exception=e\n                end\n            end\n            return\n        end\n    else\n        silence_counters[ssrc] = 0\n    end\n\n    append!(buf, pcm)\n    audio_buffers[ssrc] = buf\nend","category":"section"},{"location":"cookbook/05-voice/#7.-Slash-Commands-for-Voice","page":"Voice","title":"7. Slash Commands for Voice","text":"tree = CommandTree()\n\nregister_command!(tree, \"join\", \"Join your voice channel\", function(ctx)\n    defer(ctx)\n\n    guild_id = ctx.interaction.guild_id\n    user_id = ctx.interaction.member.user.id\n\n    # Find user's voice channel from state\n    guild_vs = get(ctx.client.state.voice_states, guild_id, nothing)\n    if isnothing(guild_vs)\n        respond(ctx; content=\"You're not in a voice channel!\")\n        return\n    end\n    vs = get(guild_vs, user_id, nothing)\n    if isnothing(vs) || isnothing(vs.channel_id)\n        respond(ctx; content=\"You're not in a voice channel!\")\n        return\n    end\n\n    vc = VoiceClient(ctx.client, guild_id, vs.channel_id)\n    connect!(vc)\n    respond(ctx; content=\"Joined <#$(vs.channel_id)>!\")\nend)\n\nregister_command!(tree, \"leave\", \"Leave voice channel\", function(ctx)\n    # Assumes you store the VoiceClient somewhere accessible\n    disconnect!(vc)\n    respond(ctx; content=\"Disconnected from voice.\")\nend)\n\nregister_command!(tree, \"play\", \"Play audio\", function(ctx)\n    url = get_option(ctx, \"url\", \"\")\n    defer(ctx)\n\n    source = FFmpegSource(url)\n    play!(vc, source)\n    respond(ctx; content=\"Now playing!\")\nend; options=[\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"url\", description=\"Audio URL or path\", required=true),\n])\n\nregister_command!(tree, \"stop\", \"Stop playback\", function(ctx)\n    stop!(vc)\n    respond(ctx; content=\"Playback stopped.\")\nend)\n\n\n\nNext steps: Recipe 06 — Permissions to add permission checks to your commands.","category":"section"},{"location":"cookbook/08-sharding/#Recipe-08-—-Sharding","page":"Sharding","title":"Recipe 08 — Sharding","text":"Difficulty: Advanced What you will build: Multi-shard bots for scaling beyond 2,500 guilds.\n\nPrerequisites: Recipe 01, Recipe 07\n\n","category":"section"},{"location":"cookbook/08-sharding/#1.-When-Do-You-Need-Sharding?","page":"Sharding","title":"1. When Do You Need Sharding?","text":"note: Discord's 2500-Guild Shard Requirement\nDiscord requires sharding when your bot joins 2,500 or more guilds. Each shard handles a subset of guilds. Without sharding, your bot will receive gateway close code 4011 (\"Sharding required\") and cannot connect.\n\nDiscord requires sharding when your bot joins 2,500+ guilds. Each shard handles a subset of guilds:\n\nShard 0: guilds where (guild_id >> 22) % num_shards == 0\nShard 1: guilds where (guild_id >> 22) % num_shards == 1\n...","category":"section"},{"location":"cookbook/08-sharding/#2.-Basic-Sharding-Setup","page":"Sharding","title":"2. Basic Sharding Setup","text":"using Accord\n\ntoken = ENV[\"DISCORD_TOKEN\"]\n\n# 4 shards\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentMessageContent,\n    num_shards = 4,\n)\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    shard_info = ismissing(event.shard) ? \"N/A\" : \"$(event.shard[1])/$(event.shard[2])\"\n    @info \"Shard ready!\" shard=shard_info guilds=length(event.guilds)\nend\n\non(client, [`MessageCreate`](@ref)) do c, event\n    msg = event.message\n    ismissing(msg.content) && return\n    msg.content == \"!ping\" && create_message(c, msg.channel_id; content=\"Pong!\")\nend\n\nstart(client)\n\nAccord.jl starts shards with a 5-second delay between them (Discord's required rate limit).\n\nwarning: Shard Count is Immutable After Connection\nThe number of shards (num_shards) cannot be changed while the bot is running. To change shard count, you must restart the bot. Plan your shard count based on current guild count plus expected growth.","category":"section"},{"location":"cookbook/08-sharding/#3.-How-Shards-Work-Internally","page":"Sharding","title":"3. How Shards Work Internally","text":"struct ShardInfo\n    id::Int          # 0-indexed shard ID\n    total::Int       # total number of shards\n    task::[`Task`](@ref)        # the async gateway connection task\n    session::[`GatewaySession`](@ref)\n    events::Channel{[`AbstractEvent`](@ref)}   # shared across all shards\n    commands::Channel{[`GatewayCommand`](@ref)}\n    ready::Base.Event\nend\n\nKey design:\n\nAll shards share a single events channel — your handlers see events from all shards\nThe Client routes gateway commands (voice state, presence) to the correct shard automatically\nShard assignment: shard_for_guild(guild_id, num_shards) uses (guild_id >> 22) % num_shards","category":"section"},{"location":"cookbook/08-sharding/#4.-Auto-Detecting-Shard-Count","page":"Sharding","title":"4. Auto-Detecting Shard Count","text":"Discord's /gateway/bot endpoint tells you the recommended shard count:\n\ninfo = get_gateway_bot(\"Bot $token\")\n\nprintln(\"Gateway URL: \", info.url)\nprintln(\"Recommended shards: \", info.shards)\nprintln(\"Session start limit: \", info.session_start_limit)\n\n# Use the recommended count\nclient = Client(token; num_shards=info.shards)\n\nThe session_start_limit tells you how many session starts you have left (resets daily). This is important because each shard start costs one session.","category":"section"},{"location":"cookbook/08-sharding/#5.-Shard-Aware-Operations","page":"Sharding","title":"5. Shard-Aware Operations","text":"The Client automatically routes to the correct shard:\n\n# This sends VOICE_STATE_UPDATE to the shard handling this guild\nupdate_voice_state(client, guild_id; channel_id=voice_channel_id)\n\n# This sends to ALL shards (presence is global)\nupdate_presence(client; status=\"online\", activities=[\n    Dict(\"name\" => \"with $(client.num_shards) shards\", \"type\" => ActivityTypes.GAME)\n])\n\n# This routes to the correct shard\nrequest_guild_members(client, guild_id; query=\"\", limit=100)\n\nThe routing formula:\n\nshard_id = shard_for_guild(guild_id, client.num_shards)\nshard = client.shards[shard_id + 1]  # 1-indexed Julia array","category":"section"},{"location":"cookbook/08-sharding/#6.-Multi-Process-Sharding","page":"Sharding","title":"6. Multi-Process Sharding","text":"For very large bots (50k+ guilds), you may want separate Julia processes per shard cluster. Here's a pattern:","category":"section"},{"location":"cookbook/08-sharding/#Launcher-Script","page":"Sharding","title":"Launcher Script","text":"# launcher.jl — starts one process per shard cluster\nusing Distributed\n\ninfo = get_gateway_bot(\"Bot $(ENV[\"DISCORD_TOKEN\"])\")\ntotal_shards = info.shards\nshards_per_process = 4\n\nfor cluster_start in 0:shards_per_process:(total_shards - 1)\n    cluster_end = min(cluster_start + shards_per_process - 1, total_shards - 1)\n    shard_ids = cluster_start:cluster_end\n\n    @info \"Launching cluster\" shards=shard_ids\n    run(`julia --project=. shard_worker.jl\n        --total-shards=$total_shards\n        --shard-start=$cluster_start\n        --shard-end=$cluster_end`; wait=false)\nend","category":"section"},{"location":"cookbook/08-sharding/#Shard-Worker","page":"Sharding","title":"Shard Worker","text":"# shard_worker.jl — runs a subset of shards\nusing Accord\n\ntotal = parse(Int, ARGS[findfirst(a -> a == \"--total-shards\", ARGS) + 1])\nshard_start = parse(Int, ARGS[findfirst(a -> a == \"--shard-start\", ARGS) + 1])\nshard_end = parse(Int, ARGS[findfirst(a -> a == \"--shard-end\", ARGS) + 1])\nnum_local = shard_end - shard_start + 1\n\n@info \"Worker starting\" shards=\"$shard_start-$shard_end\" total=total\n\nclient = Client(ENV[\"DISCORD_TOKEN\"];\n    intents = IntentGuilds | IntentGuildMessages,\n    num_shards = total,\n    # Only connect the shards assigned to this process\n    # (requires custom shard range support)\n)\n\n# Register handlers...\nstart(client)","category":"section"},{"location":"cookbook/08-sharding/#7.-Monitoring-Shard-Health","page":"Sharding","title":"7. Monitoring Shard Health","text":"function shard_status(client)\n    for shard in client.shards\n        status = if isnothing(shard.task)\n            \"not started\"\n        elseif istaskdone(shard.task)\n            istaskfailed(shard.task) ? \"failed\" : \"stopped\"\n        else\n            \"running\"\n        end\n        @info \"Shard $(shard.id)/$(shard.total)\" status=status session_connected=shard.session.connected\n    end\nend\n\n# Call periodically\non(client, ReadyEvent) do c, event\n    @async begin\n        while c.running\n            sleep(60)\n            shard_status(c)\n        end\n    end\nend","category":"section"},{"location":"cookbook/08-sharding/#8.-Guild-Count-Across-Shards","page":"Sharding","title":"8. Guild Count Across Shards","text":"on(client, MessageCreate) do c, event\n    msg = event.message\n    ismissing(msg.content) && return\n\n    if msg.content == \"!guilds\"\n        total = length(c.state.guilds)\n        create_message(c, msg.channel_id;\n            content=\"I'm in **$total** guilds across **$(c.num_shards)** shards.\")\n    end\nend\n\n\n\nNext steps: Recipe 09 — Auto-Moderation or Recipe 11 — Architectural Patterns for production structure.","category":"section"},{"location":"cookbook/#cookbook-index","page":"Accord.jl Cookbook","title":"Accord.jl Cookbook","text":"Practical, copy-paste-ready recipes for building Discord bots in Julia with Accord.jl.","category":"section"},{"location":"cookbook/#Prerequisites","page":"Accord.jl Cookbook","title":"Prerequisites","text":"Julia 1.11+ (download)\nDiscord bot token — create one at the Discord Developer Portal\nAccord.jl installed: ] add Accord\n\n","category":"section"},{"location":"cookbook/#Getting-Started","page":"Accord.jl Cookbook","title":"Getting Started","text":"# Recipe What you'll build\n01 Your First Bot Hello world, ping/pong, intents, REPL mode\n02 Rich Messages Embeds, reactions, attachments, bulk operations","category":"section"},{"location":"cookbook/#Interactions","page":"Accord.jl Cookbook","title":"Interactions","text":"# Recipe What you'll build\n03 Slash Commands Commands with options, autocomplete, subcommands\n04 Buttons, Selects & Modals Interactive components, ticket system workflow\n10 Polls Creating polls, listening for votes, ending early","category":"section"},{"location":"cookbook/#Advanced-Features","page":"Accord.jl Cookbook","title":"Advanced Features","text":"# Recipe What you'll build\n05 Voice Playback, recording, transcription\n06 Permissions Computing permissions, @check guards, private channels\n07 Caching Cache strategies, per-resource config, memory tips\n08 Sharding Multi-shard bots for 2,500+ guilds\n09 Auto-Moderation Keyword filters, spam protection, alert channels","category":"section"},{"location":"cookbook/#Production","page":"Accord.jl Cookbook","title":"Production","text":"# Recipe What you'll build\n11 Architectural Patterns Project structure, middleware, @check guards, wait_for, state injection\n12 Performance Type stability, precompilation, async patterns\n13 Deployment Systemd, Docker, sysimages, health checks\n14 Troubleshooting Common errors, debug logging, gateway issues","category":"section"},{"location":"cookbook/#Advocacy-and-Capstone","page":"Accord.jl Cookbook","title":"Advocacy & Capstone","text":"# Recipe What you'll build\n15 Why Julia for Discord Bots? Performance, multiple dispatch, scientific computing\n16 AI Agent Bot LLM integration, streaming, tool use, memory","category":"section"},{"location":"cookbook/13-deploy/#Recipe-13-—-Deployment","page":"Deployment","title":"Recipe 13 — Deployment","text":"Difficulty: Intermediate What you will build: Production deployment with systemd, Docker, sysimages, and health checks.\n\nPrerequisites: Recipe 11\n\n","category":"section"},{"location":"cookbook/13-deploy/#1.-Environment-Management","page":"Deployment","title":"1. Environment Management","text":"","category":"section"},{"location":"cookbook/13-deploy/#.env-File","page":"Deployment","title":".env File","text":"warning: Token Exposure Risk\nNever commit tokens to version control. Tokens are credentials that grant access to your bot. If exposed:Malicious users could control your bot\nYour bot could be used for spam/abuse\nDiscord may reset the token and ban the applicationUse environment variables or a .env file (in .gitignore), never hardcode tokens.\n\n# .env — NEVER commit this file\nDISCORD_TOKEN=Bot XXXXXXXXXXXXXXXXXXXXXXXXXX.XXXXXX.XXXXXXXXXXXXXXXXXXXXXXXX\nOPENAI_API_KEY=sk-...\nDATABASE_URL=sqlite:///data/bot.db","category":"section"},{"location":"cookbook/13-deploy/#.gitignore","page":"Deployment","title":".gitignore","text":".env\n*.db\nManifest.toml\nbot_sysimage.so\n/data/\n/logs/","category":"section"},{"location":"cookbook/13-deploy/#Loading-in-Julia","page":"Deployment","title":"Loading in Julia","text":"function load_env(path=\".env\")\n    isfile(path) || return\n    for line in eachline(path)\n        stripped = strip(line)\n        (isempty(stripped) || startswith(stripped, '#')) && continue\n        eq_pos = findfirst('=', stripped)\n        isnothing(eq_pos) && continue\n        key = strip(stripped[1:eq_pos-1])\n        value = strip(stripped[eq_pos+1:end])\n        ENV[key] = value\n    end\nend","category":"section"},{"location":"cookbook/13-deploy/#2.-Systemd-Service","page":"Deployment","title":"2. Systemd Service","text":"","category":"section"},{"location":"cookbook/13-deploy/#Service-Unit-File","page":"Deployment","title":"Service Unit File","text":"# /etc/systemd/system/discord-bot.service\n[Unit]\nDescription=Accord.jl Discord Bot\nAfter=network-online.target\nWants=network-online.target\n\n[Service]\nType=simple\nUser=botuser\nGroup=botuser\nWorkingDirectory=/opt/mybot\nEnvironmentFile=/opt/mybot/.env\nExecStart=/usr/local/bin/julia --project=/opt/mybot --threads=4 /opt/mybot/bin/run.jl\nRestart=always\nRestartSec=10\nStandardOutput=journal\nStandardError=journal\nSyslogIdentifier=discord-bot\n\n# Security hardening\nNoNewPrivileges=yes\nProtectSystem=strict\nProtectHome=yes\nReadWritePaths=/opt/mybot/data /opt/mybot/logs\nPrivateTmp=yes\n\n[Install]\nWantedBy=multi-user.target","category":"section"},{"location":"cookbook/13-deploy/#With-Sysimage-(Fast-Startup)","page":"Deployment","title":"With Sysimage (Fast Startup)","text":"ExecStart=/usr/local/bin/julia --sysimage=/opt/mybot/bot_sysimage.so --project=/opt/mybot --threads=4 /opt/mybot/bin/run.jl","category":"section"},{"location":"cookbook/13-deploy/#Managing-the-Service","page":"Deployment","title":"Managing the Service","text":"sudo systemctl daemon-reload\nsudo systemctl enable discord-bot\nsudo systemctl start discord-bot\nsudo systemctl status discord-bot\nsudo journalctl -u discord-bot -f      # follow logs\nsudo journalctl -u discord-bot --since \"1 hour ago\"","category":"section"},{"location":"cookbook/13-deploy/#3.-Docker","page":"Deployment","title":"3. Docker","text":"","category":"section"},{"location":"cookbook/13-deploy/#Dockerfile","page":"Deployment","title":"Dockerfile","text":"# Multi-stage build for smaller image\n\n# Stage 1: Build sysimage\nFROM julia:1.11 AS builder\n\nWORKDIR /app\nCOPY Project.toml Manifest.toml ./\nRUN julia --project=. -e 'using Pkg; Pkg.instantiate(); Pkg.precompile()'\n\nCOPY . .\n\n# Optional: create sysimage for fast startup\nRUN julia --project=. -e '\n    using PackageCompiler\n    create_sysimage(\n        [\"Accord\", \"HTTP\", \"JSON3\"],\n        sysimage_path=\"bot_sysimage.so\",\n        precompile_execution_file=\"precompile_script.jl\",\n    )\n'\n\n# Stage 2: Runtime\nFROM julia:1.11-slim\n\n# Install ffmpeg for voice support\nRUN apt-get update && apt-get install -y --no-install-recommends ffmpeg && rm -rf /var/lib/apt/lists/*\n\nWORKDIR /app\n\n# Copy project and sysimage\nCOPY --from=builder /app /app\n\n# Create data directory\nRUN mkdir -p /app/data /app/logs\n\n# Run as non-root\nRUN useradd -m botuser\nUSER botuser\n\nHEALTHCHECK --interval=30s --timeout=5s --retries=3 \\\n    CMD julia -e 'exit(isfile(\"/app/data/healthcheck\") && time() - mtime(\"/app/data/healthcheck\") < 60 ? 0 : 1)'\n\nENTRYPOINT [\"julia\", \"--sysimage=/app/bot_sysimage.so\", \"--project=/app\", \"--threads=4\", \"bin/run.jl\"]","category":"section"},{"location":"cookbook/13-deploy/#Dockerfile-(Simple,-No-Sysimage)","page":"Deployment","title":"Dockerfile (Simple, No Sysimage)","text":"FROM julia:1.11\n\nRUN apt-get update && apt-get install -y --no-install-recommends ffmpeg && rm -rf /var/lib/apt/lists/*\n\nWORKDIR /app\nCOPY Project.toml Manifest.toml ./\nRUN julia --project=. -e 'using Pkg; Pkg.instantiate(); Pkg.precompile()'\n\nCOPY . .\nRUN mkdir -p /app/data\n\nENTRYPOINT [\"julia\", \"--project=/app\", \"--threads=4\", \"bin/run.jl\"]","category":"section"},{"location":"cookbook/13-deploy/#docker-compose.yml","page":"Deployment","title":"docker-compose.yml","text":"version: \"3.8\"\n\nservices:\n  bot:\n    build: .\n    env_file: .env\n    restart: always\n    volumes:\n      - bot-data:/app/data\n      - bot-logs:/app/logs\n    logging:\n      driver: json-file\n      options:\n        max-size: \"10m\"\n        max-file: \"3\"\n\nvolumes:\n  bot-data:\n  bot-logs:","category":"section"},{"location":"cookbook/13-deploy/#Running","page":"Deployment","title":"Running","text":"# Build and start\ndocker compose up -d --build\n\n# View logs\ndocker compose logs -f bot\n\n# Restart\ndocker compose restart bot\n\n# Update\ngit pull\ndocker compose up -d --build","category":"section"},{"location":"cookbook/13-deploy/#4.-PackageCompiler-Sysimage","page":"Deployment","title":"4. PackageCompiler Sysimage","text":"tip: Sysimage Creation for Faster Startup\nPackageCompiler.jl can create a custom sysimage that pre-compiles Accord.jl and its dependencies. This reduces startup time from ~10 seconds to ~1 second — critical for production deployments where quick restarts matter.\n\nCreate a sysimage for near-instant startup (~1s vs ~10s):\n\n# build_sysimage.jl\nusing PackageCompiler\n\ncreate_sysimage(\n    [\"Accord\", \"HTTP\", \"JSON3\"],\n    sysimage_path=\"bot_sysimage.so\",\n    precompile_execution_file=\"precompile_script.jl\",\n)\n\n# precompile_script.jl\nusing Accord\n\n# Exercise the code paths that matter\nclient = [`Client`](@ref)(\"Bot fake\"; intents=[`IntentGuilds`](@ref))\ntree = [`CommandTree`](@ref)()\n\n# Components\n[`embed`](@ref)(title=\"T\", color=0x5865F2)\n[`button`](@ref)(label=\"B\", custom_id=\"b\")\n[`action_row`](@ref)([[`button`](@ref)(label=\"X\", custom_id=\"x\")])\n[`string_select`](@ref)(custom_id=\"s\", options=[[`select_option`](@ref)(label=\"L\", value=\"V\")])\n[`text_input`](@ref)(custom_id=\"ti\", label=\"L\")\n[`command_option`](@ref)(type=3, name=\"n\", description=\"d\")\n\nprintln(\"Precompilation complete\")\n\nBuild:\n\njulia --project=. build_sysimage.jl","category":"section"},{"location":"cookbook/13-deploy/#5.-Health-Checks","page":"Deployment","title":"5. Health Checks","text":"","category":"section"},{"location":"cookbook/13-deploy/#Simple-File-Based-Health-Check","page":"Deployment","title":"Simple File-Based Health Check","text":"# In your bot, write a timestamp file periodically\n@async begin\n    while client.running\n        write(\"data/healthcheck\", string(time()))\n        sleep(30)\n    end\nend","category":"section"},{"location":"cookbook/13-deploy/#HTTP-Health-Endpoint","page":"Deployment","title":"HTTP Health Endpoint","text":"import HTTP\n\nfunction start_health_server(client; port=8080)\n    @async HTTP.serve(\"0.0.0.0\", port) do request\n        if request.target == \"/health\"\n            status = client.running ? 200 : 503\n            body = JSON3.write(Dict(\n                \"status\" => client.running ? \"ok\" : \"down\",\n                \"guilds\" => length(client.state.guilds),\n                \"uptime_s\" => round(Int, time() - start_time),\n            ))\n            return HTTP.Response(status, [\"Content-Type\" => \"application/json\"], body)\n        end\n        return HTTP.Response(404, \"Not found\")\n    end\nend\n\nconst start_time = time()\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    start_health_server(c)\n    @info \"Health endpoint running on :8080/health\"\nend","category":"section"},{"location":"cookbook/13-deploy/#6.-Log-Rotation","page":"Deployment","title":"6. Log Rotation","text":"","category":"section"},{"location":"cookbook/13-deploy/#With-systemd-(automatic-via-journald)","page":"Deployment","title":"With systemd (automatic via journald)","text":"# journald handles rotation automatically\n# Configure limits in /etc/systemd/journald.conf:\n# SystemMaxUse=500M\n# MaxRetentionSec=30day","category":"section"},{"location":"cookbook/13-deploy/#Manual-File-Logging","page":"Deployment","title":"Manual File Logging","text":"using Logging, Dates\n\nfunction setup_file_logging(path=\"logs/bot.log\")\n    mkpath(dirname(path))\n    io = open(path, \"a\")\n    logger = SimpleLogger(io, Logging.Info)\n    global_logger(logger)\n    return io\nend\n\n# Rotate daily\nfunction rotate_logs(base_path=\"logs/bot.log\")\n    date_str = Dates.format(today(), \"yyyy-mm-dd\")\n    archive = \"logs/bot-$(date_str).log\"\n    isfile(base_path) && mv(base_path, archive; force=true)\nend","category":"section"},{"location":"cookbook/13-deploy/#7.-Update-Workflow","page":"Deployment","title":"7. Update Workflow","text":"","category":"section"},{"location":"cookbook/13-deploy/#Manual-Deployment","page":"Deployment","title":"Manual Deployment","text":"# SSH into server\nssh botserver\n\n# Pull latest code\ncd /opt/mybot\ngit pull\n\n# Update dependencies\njulia --project=. -e 'using Pkg; Pkg.update(); Pkg.precompile()'\n\n# Rebuild sysimage (optional, takes a few minutes)\njulia --project=. build_sysimage.jl\n\n# Restart\nsudo systemctl restart discord-bot\nsudo journalctl -u discord-bot -f  # watch for errors","category":"section"},{"location":"cookbook/13-deploy/#Docker-Deployment","page":"Deployment","title":"Docker Deployment","text":"ssh botserver\ncd /opt/mybot\ngit pull\ndocker compose up -d --build\ndocker compose logs -f bot\n\n\n\nNext steps: Recipe 14 — Troubleshooting for debugging common issues.","category":"section"},{"location":"cookbook/09-automod/#Recipe-09-—-Auto-Moderation","page":"Auto-Moderation","title":"Recipe 09 — Auto-Moderation","text":"Difficulty: Intermediate What you will build: Keyword filters, spam protection, mention limits, and alert channels using Discord's Auto-Moderation system.\n\nPrerequisites: Recipe 01, Recipe 03\n\n","category":"section"},{"location":"cookbook/09-automod/#1.-How-Auto-Moderation-Works","page":"Auto-Moderation","title":"1. How Auto-Moderation Works","text":"note: AutoMod Rule Limits\nDiscord limits guilds to:6 keyword rules per guild (keyword filter + keyword preset combined)\n1 spam rule per guild\n1 mention spam rule per guildPlan your moderation strategy accordingly. Combine similar keywords into single rules rather than creating many small rules.\n\nDiscord's AutoMod system lets you create rules that automatically act on messages:\n\nTrigger — what to look for (keywords, spam, mention spam, presets)\nAction — what to do (block message, send alert, timeout user)\nExemptions — roles/channels that bypass the rule\n\nYour bot needs these Intents:\n\nclient = Client(token;\n    intents = IntentGuilds | IntentAutoModerationConfiguration | IntentAutoModerationExecution\n)","category":"section"},{"location":"cookbook/09-automod/#2.-Trigger-Types","page":"Auto-Moderation","title":"2. Trigger Types","text":"Type Constant Description\nKeyword AutoModTriggerTypes.KEYWORD (1) Match custom keywords/regex\nSpam AutoModTriggerTypes.SPAM (3) Generic spam detection\nKeyword Preset AutoModTriggerTypes.KEYWORD_PRESET (4) Discord's built-in word lists\nMention Spam AutoModTriggerTypes.MENTION_SPAM (5) Too many mentions\nMember Profile AutoModTriggerTypes.MEMBER_PROFILE (6) Profile content match","category":"section"},{"location":"cookbook/09-automod/#3.-Action-Types","page":"Auto-Moderation","title":"3. Action Types","text":"Type Constant Description\nBlock Message AutoModActionTypes.BLOCK_MESSAGE (1) Prevent the message from being sent\nSend Alert AutoModActionTypes.SEND_ALERT_MESSAGE (2) Send alert to a channel\nTimeout AutoModActionTypes.TIMEOUT (3) Timeout the user","category":"section"},{"location":"cookbook/09-automod/#4.-Creating-a-Keyword-Filter","page":"Auto-Moderation","title":"4. Creating a Keyword Filter","text":"ALERT_CHANNEL = Snowflake(999999999999999999)\n\nbody = Dict(\n    \"name\" => \"Bad Words Filter\",\n    \"event_type\" => AutoModEventTypes.MESSAGE_SEND,\n    \"trigger_type\" => AutoModTriggerTypes.KEYWORD,\n    \"trigger_metadata\" => Dict(\n        \"keyword_filter\" => [\"badword1\", \"badword2\", \"*slur*\"],\n        \"regex_patterns\" => [\"b[a@]d\\\\s*w[o0]rd\"],  # regex support\n        \"allow_list\" => [\"badword1_but_ok\"],          # exceptions\n    ),\n    \"actions\" => [\n        Dict(\n            \"type\" => AutoModActionTypes.BLOCK_MESSAGE,\n            \"metadata\" => Dict(\n                \"custom_message\" => \"This message was blocked by AutoMod.\"\n            )\n        ),\n        Dict(\n            \"type\" => AutoModActionTypes.SEND_ALERT_MESSAGE,\n            \"metadata\" => Dict(\n                \"channel_id\" => string(ALERT_CHANNEL)\n            )\n        ),\n    ],\n    \"enabled\" => true,\n    \"exempt_roles\" => [],     # roles that bypass this rule\n    \"exempt_channels\" => [],  # channels that bypass this rule\n)\n\nrule = create_auto_moderation_rule(client.ratelimiter, guild_id;\n    token=client.token, body=body)\n@info \"Created rule\" name=rule.name id=rule.id","category":"section"},{"location":"cookbook/09-automod/#Keyword-Matching-Patterns","page":"Auto-Moderation","title":"Keyword Matching Patterns","text":"Pattern Matches Doesn't Match\n\"test\" \"test\", \"testing\" \"atest\"\n\"*test\" \"atest\", \"test\" \"testa\"\n\"test*\" \"test\", \"testing\" \"atest\"\n\"*test*\" \"atest\", \"testing\", \"atesting\" —","category":"section"},{"location":"cookbook/09-automod/#5.-Preset-Keyword-Lists","page":"Auto-Moderation","title":"5. Preset Keyword Lists","text":"Discord provides built-in word lists:\n\nbody = Dict(\n    \"name\" => \"Content Filter\",\n    \"event_type\" => AutoModEventTypes.MESSAGE_SEND,\n    \"trigger_type\" => AutoModTriggerTypes.KEYWORD_PRESET,\n    \"trigger_metadata\" => Dict(\n        \"presets\" => [\n            AutoModKeywordPresetTypes.PROFANITY,       # 1\n            AutoModKeywordPresetTypes.SEXUAL_CONTENT,   # 2\n            AutoModKeywordPresetTypes.SLURS,            # 3\n        ],\n        \"allow_list\" => [\"damn\", \"hell\"],  # words to allow despite presets\n    ),\n    \"actions\" => [\n        Dict(\"type\" => AutoModActionTypes.BLOCK_MESSAGE),\n    ],\n    \"enabled\" => true,\n)\n\ncreate_auto_moderation_rule(client.ratelimiter, guild_id;\n    token=client.token, body=body)","category":"section"},{"location":"cookbook/09-automod/#6.-Mention-Spam-Protection","page":"Auto-Moderation","title":"6. Mention Spam Protection","text":"Block messages with excessive mentions:\n\nbody = Dict(\n    \"name\" => \"Mention Spam Protection\",\n    \"event_type\" => AutoModEventTypes.MESSAGE_SEND,\n    \"trigger_type\" => AutoModTriggerTypes.MENTION_SPAM,\n    \"trigger_metadata\" => Dict(\n        \"mention_total_limit\" => 5,                    # max mentions per message\n        \"mention_raid_protection_enabled\" => true,     # enable raid protection\n    ),\n    \"actions\" => [\n        Dict(\"type\" => AutoModActionTypes.BLOCK_MESSAGE),\n        Dict(\n            \"type\" => AutoModActionTypes.TIMEOUT,\n            \"metadata\" => Dict(\n                \"duration_seconds\" => 300  # 5 minute timeout\n            )\n        ),\n    ],\n    \"enabled\" => true,\n)\n\ncreate_auto_moderation_rule(client.ratelimiter, guild_id;\n    token=client.token, body=body)","category":"section"},{"location":"cookbook/09-automod/#7.-Listening-for-AutoMod-Actions","page":"Auto-Moderation","title":"7. Listening for AutoMod Actions","text":"When an AutoModRule triggers, you get an AutoModerationActionExecution event:\n\non(client, AutoModerationActionExecution) do c, event\n    @info \"AutoMod triggered\" rule_id=event.rule_id user_id=event.user_id\n\n    # event fields:\n    #   guild_id, action, rule_id, rule_trigger_type, user_id\n    #   channel_id, message_id, alert_system_message_id\n    #   content, matched_keyword, matched_content\n\n    if !ismissing(event.matched_keyword) && !ismissing(event.content)\n        @warn \"AutoMod match\" keyword=event.matched_keyword content=event.content user=event.user_id\n    end\nend","category":"section"},{"location":"cookbook/09-automod/#Custom-Alert-Embed","page":"Auto-Moderation","title":"Custom Alert Embed","text":"on(client, AutoModerationActionExecution) do c, event\n    ALERT_CHANNEL = Snowflake(999999999999999999)\n\n    matched = ismissing(event.matched_keyword) ? \"N/A\" : event.matched_keyword\n    content = ismissing(event.content) ? \"N/A\" : event.content\n    channel = ismissing(event.channel_id) ? \"N/A\" : \"<#$(event.channel_id)>\"\n\n    e = embed(\n        title=\"AutoMod Action\",\n        color=0xED4245,\n        fields=[\n            Dict(\"name\" => \"User\", \"value\" => \"<@$(event.user_id)>\", \"inline\" => true),\n            Dict(\"name\" => \"Channel\", \"value\" => channel, \"inline\" => true),\n            Dict(\"name\" => \"Rule ID\", \"value\" => string(event.rule_id), \"inline\" => true),\n            Dict(\"name\" => \"Matched Keyword\", \"value\" => matched),\n            Dict(\"name\" => \"Content\", \"value\" => length(content) > 200 ? content[1:200] * \"...\" : content),\n        ]\n    )\n    create_message(c, ALERT_CHANNEL; embeds=[e])\nend","category":"section"},{"location":"cookbook/09-automod/#8.-Managing-Rules","page":"Auto-Moderation","title":"8. Managing Rules","text":"","category":"section"},{"location":"cookbook/09-automod/#List-All-Rules","page":"Auto-Moderation","title":"List All Rules","text":"rules = list_auto_moderation_rules(client.ratelimiter, guild_id; token=client.token)\nfor rule in rules\n    @info \"Rule\" name=rule.name id=rule.id enabled=rule.enabled trigger_type=rule.trigger_type\nend","category":"section"},{"location":"cookbook/09-automod/#Modify-a-Rule","page":"Auto-Moderation","title":"Modify a Rule","text":"modify_auto_moderation_rule(client.ratelimiter, guild_id, rule_id;\n    token=client.token,\n    body=Dict(\n        \"name\" => \"Updated Filter\",\n        \"trigger_metadata\" => Dict(\n            \"keyword_filter\" => [\"newbadword1\", \"newbadword2\"],\n        ),\n    )\n)","category":"section"},{"location":"cookbook/09-automod/#Delete-a-Rule","page":"Auto-Moderation","title":"Delete a Rule","text":"delete_auto_moderation_rule(client.ratelimiter, guild_id, rule_id;\n    token=client.token)","category":"section"},{"location":"cookbook/09-automod/#Add-Exempt-Roles/Channels","page":"Auto-Moderation","title":"Add Exempt Roles/Channels","text":"modify_auto_moderation_rule(client.ratelimiter, guild_id, rule_id;\n    token=client.token,\n    body=Dict(\n        \"exempt_roles\" => [string(mod_role_id), string(admin_role_id)],\n        \"exempt_channels\" => [string(bot_testing_channel_id)],\n    )\n)","category":"section"},{"location":"cookbook/09-automod/#9.-Slash-Command-for-Managing-AutoMod","page":"Auto-Moderation","title":"9. Slash Command for Managing AutoMod","text":"options_automod = [\n    command_option(\n        type=ApplicationCommandOptionTypes.SUB_COMMAND,\n        name=\"list\",\n        description=\"List all AutoMod rules\"\n    ),\n    command_option(\n        type=ApplicationCommandOptionTypes.SUB_COMMAND,\n        name=\"toggle\",\n        description=\"Enable/disable a rule\",\n        options=[\n            command_option(type=ApplicationCommandOptionTypes.STRING, name=\"rule_id\", description=\"Rule ID\", required=true),\n            command_option(type=ApplicationCommandOptionTypes.BOOLEAN, name=\"enabled\", description=\"Enable or disable\", required=true),\n        ]\n    ),\n]\n\n@slash_command client \"automod\" \"Manage auto-moderation\" options_automod function(ctx)\n    data = ctx.interaction.data\n    ismissing(data) && return\n    ismissing(data.options) && return\n\n    sub = data.options[1]\n    guild_id = ctx.interaction.guild_id\n\n    if sub.name == \"list\"\n        defer(ctx; ephemeral=true)\n        rules = list_auto_moderation_rules(ctx.client.ratelimiter, guild_id; token=ctx.client.token)\n\n        if isempty(rules)\n            respond(ctx; content=\"No AutoMod rules configured.\")\n            return\n        end\n\n        fields = [\n            Dict(\n                \"name\" => \"$(rule.name) ($(rule.enabled ? \"ON\" : \"OFF\"))\",\n                \"value\" => \"ID: `$(rule.id)` | Trigger: $(rule.trigger_type)\",\n            )\n            for rule in rules\n        ]\n        e = embed(title=\"AutoMod Rules\", color=0x5865F2, fields=fields)\n        respond(ctx; embeds=[e])\n\n    elseif sub.name == \"toggle\"\n        sub_opts = Dict{String, Any}()\n        if !ismissing(sub.options)\n            for opt in sub.options\n                !ismissing(opt.value) && (sub_opts[opt.name] = opt.value)\n            end\n        end\n\n        rule_id = Snowflake(sub_opts[\"rule_id\"])\n        enabled = sub_opts[\"enabled\"]\n\n        modify_auto_moderation_rule(ctx.client.ratelimiter, guild_id, rule_id;\n            token=ctx.client.token, body=Dict(\"enabled\" => enabled))\n\n        respond(ctx; content=\"Rule `$rule_id` $(enabled ? \"enabled\" : \"disabled\").\", ephemeral=true)\n    end\nend\n\n\n\nNext steps: Recipe 10 — Polls for Discord's native poll system, or Recipe 11 — Architectural Patterns for production structure.","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Recipe-04-—-Buttons,-Selects-and-Modals","page":"Buttons, Selects & Modals","title":"Recipe 04 — Buttons, Selects & Modals","text":"Difficulty: Intermediate What you will build: Interactive buttons, select menus, modal dialogs, and a complete ticket system workflow.\n\nPrerequisites: Recipe 03\n\n","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#1.-Buttons","page":"Buttons, Selects & Modals","title":"1. Buttons","text":"","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Button-Styles","page":"Buttons, Selects & Modals","title":"Button Styles","text":"Style Constant Color Requires\nPrimary ButtonStyles.PRIMARY Blurple custom_id\nSecondary ButtonStyles.SECONDARY Grey custom_id\nSuccess ButtonStyles.SUCCESS Green custom_id\nDanger ButtonStyles.DANGER Red custom_id\nLink ButtonStyles.LINK Grey url (no handler)","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Sending-Buttons","page":"Buttons, Selects & Modals","title":"Sending Buttons","text":"@slash_command client \"buttons\" \"Show some buttons\" function(ctx)\n    components = [\n        action_row([\n            button(label=\"Click me!\", custom_id=\"btn_click\", style=ButtonStyles.PRIMARY),\n            button(label=\"Danger!\", custom_id=\"btn_danger\", style=ButtonStyles.DANGER),\n            button(label=\"Visit Site\", url=\"https://julialang.org\", style=ButtonStyles.LINK),\n        ])\n    ]\n    respond(ctx; content=\"Choose a button:\", components=components)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Handling-Button-Clicks","page":"Buttons, Selects & Modals","title":"Handling Button Clicks","text":"warning: 3-Second Interaction Response Deadline\nDiscord requires an initial response to button clicks, select menu choices, and modal submissions within 3 seconds. If your handler performs slow operations, call defer(ctx) first to acknowledge the interaction, then follow up with the actual response.\n\n@button_handler client \"btn_click\" function(ctx)\n    respond(ctx; content=\"You clicked the button!\", ephemeral=true)\nend\n\n@button_handler client \"btn_danger\" function(ctx)\n    respond(ctx; content=\"Danger zone!\", ephemeral=true)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Buttons-with-Emoji","page":"Buttons, Selects & Modals","title":"Buttons with Emoji","text":"button(\n    label=\"Approve\",\n    custom_id=\"approve\",\n    style=ButtonStyles.SUCCESS,\n    emoji=Dict(\"name\" => \"✅\"),\n)","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Disabling-Buttons-After-Click","page":"Buttons, Selects & Modals","title":"Disabling Buttons After Click","text":"@button_handler client \"confirm_action\" function(ctx)\n    # Respond with disabled buttons (UPDATE_MESSAGE for component interactions)\n    components = [\n        action_row([\n            button(label=\"Confirmed\", custom_id=\"confirm_action\", style=ButtonStyles.SUCCESS, disabled=true),\n        ])\n    ]\n    respond(ctx; content=\"Action confirmed!\", components=components)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#2.-String-Select-Menus","page":"Buttons, Selects & Modals","title":"2. String Select Menus","text":"@slash_command client \"colors\" \"Pick your favorite colors\" function(ctx)\n    sel = string_select(\n        custom_id=\"color_select\",\n        placeholder=\"Choose up to 3 colors...\",\n        min_values=1,\n        max_values=3,\n        options=[\n            select_option(label=\"Red\", value=\"red\", description=\"The color of fire\", emoji=Dict(\"name\" => \"🔴\")),\n            select_option(label=\"Green\", value=\"green\", description=\"The color of nature\", emoji=Dict(\"name\" => \"🟢\")),\n            select_option(label=\"Blue\", value=\"blue\", description=\"The color of sky\", emoji=Dict(\"name\" => \"🔵\")),\n            select_option(label=\"Yellow\", value=\"yellow\", description=\"The color of sun\", emoji=Dict(\"name\" => \"🟡\")),\n        ]\n    )\n    respond(ctx; content=\"Pick your colors:\", components=[action_row([sel])])\nend\n\n@select_handler client \"color_select\" function(ctx)\n    values = selected_values(ctx)\n    respond(ctx; content=\"You picked: **$(join(values, \", \"))**\", ephemeral=true)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#3.-Specialized-Select-Menus","page":"Buttons, Selects & Modals","title":"3. Specialized Select Menus","text":"","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#User-Select","page":"Buttons, Selects & Modals","title":"User Select","text":"sel = user_select(custom_id=\"pick_user\", placeholder=\"Select a user\")\nrespond(ctx; content=\"Pick a user:\", components=[action_row([sel])])","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Role-Select","page":"Buttons, Selects & Modals","title":"Role Select","text":"sel = role_select(custom_id=\"pick_role\", placeholder=\"Select a role\")\nrespond(ctx; content=\"Pick a role:\", components=[action_row([sel])])","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Mentionable-Select-(Users-Roles)","page":"Buttons, Selects & Modals","title":"Mentionable Select (Users + Roles)","text":"sel = mentionable_select(custom_id=\"pick_mention\", placeholder=\"Select user or role\")\nrespond(ctx; content=\"Pick someone:\", components=[action_row([sel])])","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Channel-Select","page":"Buttons, Selects & Modals","title":"Channel Select","text":"sel = channel_select(\n    custom_id=\"pick_channel\",\n    placeholder=\"Select a channel\",\n    channel_types=[[`ChannelTypes`](@ref).GUILD_TEXT, [`ChannelTypes`](@ref).GUILD_VOICE]\n)\nrespond(ctx; content=\"Pick a channel:\", components=[action_row([sel])])\n\nAll specialized selects use @select_handler and selected_values returns Snowflake ID strings.","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#4.-Modals-(Popup-Forms)","page":"Buttons, Selects & Modals","title":"4. Modals (Popup Forms)","text":"","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Showing-a-Modal","page":"Buttons, Selects & Modals","title":"Showing a Modal","text":"@slash_command client \"feedback\" \"Give feedback\" function(ctx)\n    show_modal(ctx;\n        title=\"Feedback Form\",\n        custom_id=\"feedback_modal\",\n        components=[\n            action_row([\n                text_input(\n                    custom_id=\"fb_subject\",\n                    label=\"Subject\",\n                    style=TextInputStyles.SHORT,\n                    placeholder=\"Brief summary...\",\n                    required=true,\n                    max_length=100,\n                ),\n            ]),\n            action_row([\n                text_input(\n                    custom_id=\"fb_body\",\n                    label=\"Details\",\n                    style=TextInputStyles.PARAGRAPH,\n                    placeholder=\"Tell us more...\",\n                    required=true,\n                    min_length=10,\n                    max_length=2000,\n                ),\n            ]),\n        ]\n    )\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#Handling-Modal-Submissions","page":"Buttons, Selects & Modals","title":"Handling Modal Submissions","text":"@modal_handler client \"feedback_modal\" function(ctx)\n    values = modal_values(ctx)  # Dict{String, String}\n    subject = values[\"fb_subject\"]\n    body = values[\"fb_body\"]\n\n    e = embed(\n        title=\"Feedback Received\",\n        color=0x57F287,\n        fields=[\n            Dict(\"name\" => \"Subject\", \"value\" => subject),\n            Dict(\"name\" => \"Details\", \"value\" => body),\n        ]\n    )\n    respond(ctx; embeds=[e], ephemeral=true)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#5.-Button-Modal-Flow","page":"Buttons, Selects & Modals","title":"5. Button → Modal Flow","text":"A button click can open a modal:\n\n@slash_command client \"report\" \"Report an issue\" function(ctx)\n    components = [\n        action_row([\n            button(label=\"Report Bug\", custom_id=\"report_bug\", style=ButtonStyles.DANGER, emoji=Dict(\"name\" => \"🐛\")),\n        ])\n    ]\n    respond(ctx; content=\"Click to report an issue:\", components=components)\nend\n\n@button_handler client \"report_bug\" function(ctx)\n    show_modal(ctx;\n        title=\"Bug Report\",\n        custom_id=\"bug_report_modal\",\n        components=[\n            action_row([text_input(custom_id=\"bug_title\", label=\"Bug Title\", style=TextInputStyles.SHORT, required=true)]),\n            action_row([text_input(custom_id=\"bug_desc\", label=\"Description\", style=TextInputStyles.PARAGRAPH, required=true)]),\n        ]\n    )\nend\n\n@modal_handler client \"bug_report_modal\" function(ctx)\n    values = modal_values(ctx)\n    e = embed(\n        title=\"Bug Report: $(values[\"bug_title\"])\",\n        description=values[\"bug_desc\"],\n        color=0xED4245,\n        footer=Dict(\"text\" => \"Reported by $(ctx.interaction.member.user.username)\")\n    )\n    respond(ctx; content=\"Bug report submitted!\", embeds=[e])\nend\n\nnote: Custom ID 100-Character Limit\nDiscord limits custom_id to 100 characters. Keep IDs short and use prefixes/suffixes efficiently. For complex state, store data in your bot's memory and reference it with a short ID.","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#6.-Dynamic-Custom-IDs","page":"Buttons, Selects & Modals","title":"6. Dynamic Custom IDs","text":"Use prefixed custom IDs to pass data through interactions:\n\n# When creating buttons, encode data in the custom_id\n@slash_command client \"poll_quick\" \"Quick yes/no poll\" function(ctx)\n    question = get_option(ctx, \"question\", \"Agree?\")\n    components = [\n        action_row([\n            button(label=\"Yes (0)\", custom_id=\"vote:yes:0\", style=ButtonStyles.SUCCESS),\n            button(label=\"No (0)\", custom_id=\"vote:no:0\", style=ButtonStyles.DANGER),\n        ])\n    ]\n    respond(ctx; content=\"**$question**\", components=components)\nend\n\n# Handle all \"vote:\" prefixed buttons (prefix matching)\n@button_handler client \"vote:\" function(ctx)\n    cid = custom_id(ctx)\n    parts = split(cid, \":\")\n    choice = parts[2]  # \"yes\" or \"no\"\n    count = parse(Int, parts[3]) + 1\n\n    # Update the button with incremented count\n    new_id = \"vote:$(choice):$(count)\"\n    respond(ctx; content=\"You voted **$choice**! (Total: $count)\", ephemeral=true)\nend","category":"section"},{"location":"cookbook/04-buttons-selects-modals/#7.-Complete-Example:-Ticket-System","page":"Buttons, Selects & Modals","title":"7. Complete Example: Ticket System","text":"A full workflow: slash command → button → modal → ticket channel.\n\nusing Accord\n\ntoken = ENV[\"DISCORD_TOKEN\"]\nclient = Client(token; intents=IntentGuilds)\n\n# Step 1: Post the ticket panel\n@slash_command client \"ticket_setup\" \"Set up a ticket panel\" function(ctx)\n    e = embed(\n        title=\"Support Tickets\",\n        description=\"Click the button below to create a support ticket.\",\n        color=0x5865F2,\n    )\n    components = [\n        action_row([\n            button(label=\"Create Ticket\", custom_id=\"ticket_create\", style=ButtonStyles.PRIMARY, emoji=Dict(\"name\" => \"🎫\")),\n        ])\n    ]\n    respond(ctx; embeds=[e], components=components)\nend\n\n# Step 2: Button opens a modal\n@button_handler client \"ticket_create\" function(ctx)\n    show_modal(ctx;\n        title=\"Create Support Ticket\",\n        custom_id=\"ticket_modal\",\n        components=[\n            action_row([\n                text_input(custom_id=\"ticket_subject\", label=\"Subject\", style=TextInputStyles.SHORT, required=true, placeholder=\"Brief description\"),\n            ]),\n            action_row([\n                text_input(custom_id=\"ticket_details\", label=\"Details\", style=TextInputStyles.PARAGRAPH, required=true, placeholder=\"Describe your issue...\"),\n            ]),\n        ]\n    )\nend\n\n# Step 3: Modal submission creates the ticket\n@modal_handler client \"ticket_modal\" function(ctx)\n    values = modal_values(ctx)\n    user = ctx.interaction.member.user\n\n    e = embed(\n        title=\"Ticket: $(values[\"ticket_subject\"])\",\n        description=values[\"ticket_details\"],\n        color=0xFEE75C,\n        footer=Dict(\"text\" => \"Opened by $(user.username)\"),\n    )\n    components = [\n        action_row([\n            button(label=\"Close Ticket\", custom_id=\"ticket_close\", style=ButtonStyles.DANGER),\n        ])\n    ]\n    respond(ctx; content=\"Ticket created!\", embeds=[e], components=components, ephemeral=true)\n\n    # Also post in a log channel (optional)\n    # LOG_CHANNEL = Snowflake(999999999999999999)\n    # create_message(ctx.client, LOG_CHANNEL; embeds=[e])\nend\n\n# Step 4: Close the ticket\n@button_handler client \"ticket_close\" function(ctx)\n    respond(ctx; content=\"Ticket closed by <@$(ctx.interaction.member.user.id)>.\")\nend\n\n# Wiring\non(client, [`ReadyEvent`](@ref)) do c, event\n    sync_commands!(c, c.command_tree)\n    @info \"Ticket bot ready!\"\nend\n\nstart(client)\n\n\n\nNext steps: Recipe 05 — Voice for audio playback and recording, or Recipe 10 — Polls for Discord's native poll system.","category":"section"},{"location":"api/#api-reference","page":"API Reference","title":"Accord.jl — API Reference","text":"Discord API v10 library for Julia. Version: 0.1.0 | API Base: https://discord.com/api/v10\n\n\n\nnote: Optional vs Nullable\nAccord.jl uses two distinct type aliases for Discord's optional fields:Optional{T} (Union{T, Missing}): Field may be absent from the JSON entirely. Check with ismissing(). Default value is missing.\nNullable{T} (Union{T, Nothing}): Field is present but may be JSON null. Check with isnothing(). Default value is nothing.This distinction mirrors Discord's API: some fields are omitted when not applicable, others are explicitly set to null.\n\n","category":"section"},{"location":"api/#1.-Client","page":"API Reference","title":"1. Client","text":"","category":"section"},{"location":"api/#2.-Events","page":"API Reference","title":"2. Events","text":"","category":"section"},{"location":"api/#3.-State-and-Caching","page":"API Reference","title":"3. State & Caching","text":"","category":"section"},{"location":"api/#4.-REST-Endpoints","page":"API Reference","title":"4. REST Endpoints","text":"","category":"section"},{"location":"api/#Messages","page":"API Reference","title":"Messages","text":"","category":"section"},{"location":"api/#Channels-and-Guilds","page":"API Reference","title":"Channels & Guilds","text":"","category":"section"},{"location":"api/#Threads","page":"API Reference","title":"Threads","text":"","category":"section"},{"location":"api/#Interactions","page":"API Reference","title":"Interactions","text":"","category":"section"},{"location":"api/#Other-REST","page":"API Reference","title":"Other REST","text":"","category":"section"},{"location":"api/#5.-Interactions-—-DSL-and-Macros","page":"API Reference","title":"5. Interactions — DSL & Macros","text":"","category":"section"},{"location":"api/#6.-Voice","page":"API Reference","title":"6. Voice","text":"","category":"section"},{"location":"api/#7.-Types","page":"API Reference","title":"7. Types","text":"","category":"section"},{"location":"api/#Core","page":"API Reference","title":"Core","text":"","category":"section"},{"location":"api/#8.-Enums,-Flags-and-Permissions","page":"API Reference","title":"8. Enums, Flags & Permissions","text":"","category":"section"},{"location":"api/#9.-Gateway-Internals","page":"API Reference","title":"9. Gateway Internals","text":"","category":"section"},{"location":"api/#Accord.Client","page":"API Reference","title":"Accord.Client","text":"Client\n\nUse this as the main entry point for your Discord bot to manage connections, events, and API calls.\n\nThe main Discord client that orchestrates gateway connections, REST API calls, and state caching.\n\nConstructor\n\nClient(token::String; intents=IntentAllNonPrivileged, num_shards=1, state=nothing, state_options...)\n\nFields\n\nstate_data — custom user state, accessible from handlers via ctx.state.\n\nExample\n\n# Inject custom state for database, config, etc.\nmy_state = (db=my_database, config=my_config)\nclient = Client(\"Bot YOUR_TOKEN_HERE\";\n    intents=IntentGuilds | IntentGuildMessages,\n    state=my_state\n)\n\non(client, MessageCreate) do c, event\n    event.message.content == \"ping\" && create_message(c, event.message.channel_id; content=\"pong\")\nend\nstart(client)\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.start","page":"API Reference","title":"Accord.start","text":"start(client::Client; blocking=true)\n\nUse this to connect your bot to Discord and begin processing events.\n\nConnect to Discord and start processing events. If blocking=true (default), this blocks until the client is stopped.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.stop","page":"API Reference","title":"Accord.stop","text":"stop(client::Client)\n\nUse this to gracefully shut down your bot and disconnect from Discord.\n\nDisconnect from Discord and stop processing events.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.on","page":"API Reference","title":"Accord.on","text":"on(handler, client, EventType)\n\nUse this to register callbacks that respond to Discord gateway events like messages or reactions.\n\nRegister an event handler. The handler receives (client, event).\n\nExample\n\non(client, MessageCreate) do c, event\n    println(\"Got message: \", event.message.content)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.on_error","page":"API Reference","title":"Accord.on_error","text":"on_error(handler, client)\n\nUse this to customize how your bot handles errors that occur during event processing.\n\nSet a custom error handler. Receives (client, event, error).\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.wait_until_ready","page":"API Reference","title":"Accord.wait_until_ready","text":"wait_until_ready(client::Client)\n\nUse this to pause execution until your bot is fully connected and ready.\n\nBlock until the client receives the READY event.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.wait_for","page":"API Reference","title":"Accord.wait_for","text":"wait_for(check, client, EventType; timeout=30.0)\n\nUse this to pause execution until a specific event occurs, useful for interactive commands or conversations.\n\nWait for a specific gateway event that matches a predicate. Uses Julia's Channel and Timer for an efficient, non-blocking wait that suspends only the current Task, not the entire bot.\n\nReturns the matching event, or nothing on timeout.\n\nArguments\n\ncheck::Function — predicate (event) -> Bool. Only matching events are captured.\nclient::Client — the bot client. See Client.\nEventType — the event type to listen for (e.g., MessageCreate).\ntimeout — seconds to wait before returning nothing (default: 30).\n\nExample\n\n@slash_command client \"quiz\" \"Start a quiz\" function(ctx)\n    respond(ctx; content=\"What color is the sky?\")\n\n    event = wait_for(client, MessageCreate; timeout=30) do evt\n        evt.message.author.id == ctx.user.id &&\n        evt.message.channel_id == ctx.channel_id\n    end\n\n    if isnothing(event)\n        followup(ctx; content=\"⏰ Time's up!\")\n    elseif event.message.content == \"blue\"\n        followup(ctx; content=\"✅ Correct!\")\n    else\n        followup(ctx; content=\"❌ Wrong!\")\n    end\nend\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.AbstractEvent","page":"API Reference","title":"Accord.AbstractEvent","text":"AbstractEvent\n\nBase type for all Discord gateway events. Use this type when registering catch-all event handlers.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ReadyEvent","page":"API Reference","title":"Accord.ReadyEvent","text":"ReadyEvent\n\nSent by Discord when the shard has successfully connected and identified. Contains information about the bot user and the guilds it is in. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ResumedEvent","page":"API Reference","title":"Accord.ResumedEvent","text":"ResumedEvent\n\nSent by Discord when a shard has successfully resumed a disconnected session. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelCreate","page":"API Reference","title":"Accord.ChannelCreate","text":"ChannelCreate\n\nSent when a new channel is created, relevant to the current user. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelUpdate","page":"API Reference","title":"Accord.ChannelUpdate","text":"ChannelUpdate\n\nSent when a channel is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelDelete","page":"API Reference","title":"Accord.ChannelDelete","text":"ChannelDelete\n\nSent when a channel relevant to the current user is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelPinsUpdate","page":"API Reference","title":"Accord.ChannelPinsUpdate","text":"ChannelPinsUpdate\n\nSent when a message is pinned or unpinned in a text channel. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadCreate","page":"API Reference","title":"Accord.ThreadCreate","text":"ThreadCreate\n\nSent when a thread is created, relevant to the current user, or when the current user is added to a thread. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadUpdate","page":"API Reference","title":"Accord.ThreadUpdate","text":"ThreadUpdate\n\nSent when a thread is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadDelete","page":"API Reference","title":"Accord.ThreadDelete","text":"ThreadDelete\n\nSent when a thread relevant to the current user is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadListSync","page":"API Reference","title":"Accord.ThreadListSync","text":"ThreadListSync\n\nSent when the current user gains access to a channel, containing all active threads in that channel. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadMemberUpdate","page":"API Reference","title":"Accord.ThreadMemberUpdate","text":"ThreadMemberUpdate\n\nSent when the thread member object for the current user is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ThreadMembersUpdate","page":"API Reference","title":"Accord.ThreadMembersUpdate","text":"ThreadMembersUpdate\n\nSent when anyone is added to or removed from a thread. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildCreate","page":"API Reference","title":"Accord.GuildCreate","text":"GuildCreate\n\nSent when a guild becomes available, or when the bot joins a new guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildUpdate","page":"API Reference","title":"Accord.GuildUpdate","text":"GuildUpdate\n\nSent when a guild's properties are updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildDelete","page":"API Reference","title":"Accord.GuildDelete","text":"GuildDelete\n\nSent when a guild becomes unavailable, or when the bot leaves a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildAuditLogEntryCreate","page":"API Reference","title":"Accord.GuildAuditLogEntryCreate","text":"GuildAuditLogEntryCreate\n\nSent when a new audit log entry is created in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildBanAdd","page":"API Reference","title":"Accord.GuildBanAdd","text":"GuildBanAdd\n\nSent when a user is banned from a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildBanRemove","page":"API Reference","title":"Accord.GuildBanRemove","text":"GuildBanRemove\n\nSent when a user is unbanned from a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildEmojisUpdate","page":"API Reference","title":"Accord.GuildEmojisUpdate","text":"GuildEmojisUpdate\n\nSent when a guild's emojis are updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildStickersUpdate","page":"API Reference","title":"Accord.GuildStickersUpdate","text":"GuildStickersUpdate\n\nSent when a guild's stickers are updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildIntegrationsUpdate","page":"API Reference","title":"Accord.GuildIntegrationsUpdate","text":"GuildIntegrationsUpdate\n\nSent when a guild's integrations are updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildMemberAdd","page":"API Reference","title":"Accord.GuildMemberAdd","text":"GuildMemberAdd\n\nSent when a new user joins a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildMemberRemove","page":"API Reference","title":"Accord.GuildMemberRemove","text":"GuildMemberRemove\n\nSent when a user is removed from a guild (leave/kick/ban). Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildMemberUpdate","page":"API Reference","title":"Accord.GuildMemberUpdate","text":"GuildMemberUpdate\n\nSent when a guild member's roles, nickname, avatar, or timeout status is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildMembersChunk","page":"API Reference","title":"Accord.GuildMembersChunk","text":"GuildMembersChunk\n\nSent in response to a Request Guild Members command. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildRoleCreate","page":"API Reference","title":"Accord.GuildRoleCreate","text":"GuildRoleCreate\n\nSent when a guild role is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildRoleUpdate","page":"API Reference","title":"Accord.GuildRoleUpdate","text":"GuildRoleUpdate\n\nSent when a guild role is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildRoleDelete","page":"API Reference","title":"Accord.GuildRoleDelete","text":"GuildRoleDelete\n\nSent when a guild role is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildScheduledEventCreate","page":"API Reference","title":"Accord.GuildScheduledEventCreate","text":"GuildScheduledEventCreate\n\nSent when a guild scheduled event is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildScheduledEventUpdate","page":"API Reference","title":"Accord.GuildScheduledEventUpdate","text":"GuildScheduledEventUpdate\n\nSent when a guild scheduled event is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildScheduledEventDelete","page":"API Reference","title":"Accord.GuildScheduledEventDelete","text":"GuildScheduledEventDelete\n\nSent when a guild scheduled event is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildScheduledEventUserAdd","page":"API Reference","title":"Accord.GuildScheduledEventUserAdd","text":"GuildScheduledEventUserAdd\n\nSent when a user subscribes to a guild scheduled event. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildScheduledEventUserRemove","page":"API Reference","title":"Accord.GuildScheduledEventUserRemove","text":"GuildScheduledEventUserRemove\n\nSent when a user unsubscribes from a guild scheduled event. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildSoundboardSoundCreate","page":"API Reference","title":"Accord.GuildSoundboardSoundCreate","text":"GuildSoundboardSoundCreate\n\nSent when a soundboard sound is created in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildSoundboardSoundUpdate","page":"API Reference","title":"Accord.GuildSoundboardSoundUpdate","text":"GuildSoundboardSoundUpdate\n\nSent when a soundboard sound is updated in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildSoundboardSoundDelete","page":"API Reference","title":"Accord.GuildSoundboardSoundDelete","text":"GuildSoundboardSoundDelete\n\nSent when a soundboard sound is deleted from a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildSoundboardSoundsUpdate","page":"API Reference","title":"Accord.GuildSoundboardSoundsUpdate","text":"GuildSoundboardSoundsUpdate\n\nSent when soundboard sounds are updated in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SoundboardSounds","page":"API Reference","title":"Accord.SoundboardSounds","text":"SoundboardSounds\n\nSent when the bot joins a voice channel, containing all soundboard sounds for that guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.IntegrationCreate","page":"API Reference","title":"Accord.IntegrationCreate","text":"IntegrationCreate\n\nSent when an integration is created in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.IntegrationUpdate","page":"API Reference","title":"Accord.IntegrationUpdate","text":"IntegrationUpdate\n\nSent when an integration is updated in a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.IntegrationDelete","page":"API Reference","title":"Accord.IntegrationDelete","text":"IntegrationDelete\n\nSent when an integration is deleted from a guild. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.InteractionCreate","page":"API Reference","title":"Accord.InteractionCreate","text":"InteractionCreate\n\nSent when a user uses an application command or message component. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.InviteCreate","page":"API Reference","title":"Accord.InviteCreate","text":"InviteCreate\n\nSent when a new invite to a channel is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.InviteDelete","page":"API Reference","title":"Accord.InviteDelete","text":"InviteDelete\n\nSent when an invite is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageCreate","page":"API Reference","title":"Accord.MessageCreate","text":"MessageCreate\n\nSent when a message is created in a channel. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageUpdate","page":"API Reference","title":"Accord.MessageUpdate","text":"MessageUpdate\n\nSent when a message is updated (edited). Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageDelete","page":"API Reference","title":"Accord.MessageDelete","text":"MessageDelete\n\nSent when a message is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageDeleteBulk","page":"API Reference","title":"Accord.MessageDeleteBulk","text":"MessageDeleteBulk\n\nSent when multiple messages are deleted at once (bulk delete). Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageReactionAdd","page":"API Reference","title":"Accord.MessageReactionAdd","text":"MessageReactionAdd\n\nSent when a user adds a reaction to a message. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageReactionRemove","page":"API Reference","title":"Accord.MessageReactionRemove","text":"MessageReactionRemove\n\nSent when a user removes a reaction from a message. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageReactionRemoveAll","page":"API Reference","title":"Accord.MessageReactionRemoveAll","text":"MessageReactionRemoveAll\n\nSent when a user explicitly removes all reactions from a message. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessageReactionRemoveEmoji","page":"API Reference","title":"Accord.MessageReactionRemoveEmoji","text":"MessageReactionRemoveEmoji\n\nSent when a bot removes all instances of a given emoji reaction from a message. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessagePollVoteAdd","page":"API Reference","title":"Accord.MessagePollVoteAdd","text":"MessagePollVoteAdd\n\nSent when a user votes in a poll. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.MessagePollVoteRemove","page":"API Reference","title":"Accord.MessagePollVoteRemove","text":"MessagePollVoteRemove\n\nSent when a user removes their vote from a poll. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.PresenceUpdate","page":"API Reference","title":"Accord.PresenceUpdate","text":"PresenceUpdate\n\nSent when a user's presence or info (username, avatar) is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.StageInstanceCreate","page":"API Reference","title":"Accord.StageInstanceCreate","text":"StageInstanceCreate\n\nSent when a Stage instance is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.StageInstanceUpdate","page":"API Reference","title":"Accord.StageInstanceUpdate","text":"StageInstanceUpdate\n\nSent when a Stage instance is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.StageInstanceDelete","page":"API Reference","title":"Accord.StageInstanceDelete","text":"StageInstanceDelete\n\nSent when a Stage instance is deleted (closed). Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.TypingStart","page":"API Reference","title":"Accord.TypingStart","text":"TypingStart\n\nSent when a user starts typing in a channel. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.UserUpdate","page":"API Reference","title":"Accord.UserUpdate","text":"UserUpdate\n\nSent when properties of the bot's user object change. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.VoiceStateUpdateEvent","page":"API Reference","title":"Accord.VoiceStateUpdateEvent","text":"VoiceStateUpdateEvent\n\nSent when a user joins/leaves/moves voice channels. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.VoiceServerUpdate","page":"API Reference","title":"Accord.VoiceServerUpdate","text":"VoiceServerUpdate\n\nSent when a guild's voice server is updated. Used for connecting to voice. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.VoiceChannelEffectSend","page":"API Reference","title":"Accord.VoiceChannelEffectSend","text":"VoiceChannelEffectSend\n\nSent when a voice channel effect (e.g. emoji, animation) is sent. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.WebhooksUpdate","page":"API Reference","title":"Accord.WebhooksUpdate","text":"WebhooksUpdate\n\nSent when a guild channel's webhooks are created, updated, or deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.EntitlementCreate","page":"API Reference","title":"Accord.EntitlementCreate","text":"EntitlementCreate\n\nSent when an entitlement is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.EntitlementUpdate","page":"API Reference","title":"Accord.EntitlementUpdate","text":"EntitlementUpdate\n\nSent when an entitlement is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.EntitlementDelete","page":"API Reference","title":"Accord.EntitlementDelete","text":"EntitlementDelete\n\nSent when an entitlement is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SubscriptionCreate","page":"API Reference","title":"Accord.SubscriptionCreate","text":"SubscriptionCreate\n\nSent when a subscription is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SubscriptionUpdate","page":"API Reference","title":"Accord.SubscriptionUpdate","text":"SubscriptionUpdate\n\nSent when a subscription is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SubscriptionDelete","page":"API Reference","title":"Accord.SubscriptionDelete","text":"SubscriptionDelete\n\nSent when a subscription is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AutoModerationRuleCreate","page":"API Reference","title":"Accord.AutoModerationRuleCreate","text":"AutoModerationRuleCreate\n\nSent when an AutoMod rule is created. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AutoModerationRuleUpdate","page":"API Reference","title":"Accord.AutoModerationRuleUpdate","text":"AutoModerationRuleUpdate\n\nSent when an AutoMod rule is updated. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AutoModerationRuleDelete","page":"API Reference","title":"Accord.AutoModerationRuleDelete","text":"AutoModerationRuleDelete\n\nSent when an AutoMod rule is deleted. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AutoModerationActionExecution","page":"API Reference","title":"Accord.AutoModerationActionExecution","text":"AutoModerationActionExecution\n\nSent when an AutoMod rule is triggered and an action is executed. Discord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.State","page":"API Reference","title":"Accord.State","text":"State\n\nUse this to access and manage cached Discord objects for your bot.\n\nHolds all cached Discord state.\n\nExample\n\nclient.state.guilds[id]\nclient.state.me.username\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Store","page":"API Reference","title":"Accord.Store","text":"Store{T}\n\nUse this to cache Discord objects like guilds, channels, and users with configurable eviction policies.\n\nA cache store for a specific resource type, keyed by Snowflake. Uses LRUCache.LRU for O(1) LRU eviction, plain Dict for other strategies.\n\nExample\n\nstore = Store{User}(CacheLRU(1000))\nstore[id] = user\nuser = store[id]\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CacheStrategy","page":"API Reference","title":"Accord.CacheStrategy","text":"Use this abstract type to define how Discord objects are cached in memory.\n\nCache strategy for a resource type.\n\nSubtypes\n\nCacheForever(): Keep entries indefinitely.\nCacheNever(): Do not cache entries.\nCacheLRU(maxsize): Keep only the most recently used entries.\nCacheTTL(ttl_seconds): Expire entries after a certain time.\n\nExample\n\nclient = Client(token; user_strategy=CacheLRU(1000))\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CacheForever","page":"API Reference","title":"Accord.CacheForever","text":"Keep entries indefinitely in memory.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CacheNever","page":"API Reference","title":"Accord.CacheNever","text":"Do not cache entries (REST fallback on every access).\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CacheLRU","page":"API Reference","title":"Accord.CacheLRU","text":"Keep only the maxsize most recently used entries.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CacheTTL","page":"API Reference","title":"Accord.CacheTTL","text":"Expire entries after ttl_seconds have passed.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.update_state!","page":"API Reference","title":"Accord.update_state!","text":"update_state!(state::State, event::AbstractEvent)\n\nUpdate the internal cache based on the incoming gateway event. Accord.jl handles this automatically for you.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_message","page":"API Reference","title":"Accord.create_message","text":"create_message(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict=Dict(), files=nothing) -> Message\n\nSend a message to a channel.\n\nUse this to post content, embeds, or files to a text channel or DM.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nbody::Dict: JSON body containing content, embeds, components, etc.\nfiles: Vector of File objects or pairs for attachments.\n\nPermissions\n\nRequires SEND_MESSAGES. Requires SEND_TTS_MESSAGES if tts is true.\n\nErrors\n\nHTTP 403 if missing permissions (e.g. strict channel overwrites).\nHTTP 404 if the channel does not exist.\nHTTP 400 if the message is empty or invalid.\n\nDiscord docs\n\n\n\n\n\ncreate_message(client::Client, channel_id::Snowflake; kwargs...) -> Message\n\nUse this to send messages to any channel your bot has access to.\n\nSend a message to a channel.\n\nArguments\n\ncontent::String: Message text content.\nembeds::Vector: Vector of embed dictionaries or objects.\ncomponents::Vector: Vector of action rows/components.\nfiles: Optional files to upload.\ntts::Bool: Whether to send as a text-to-speech message.\nmessage_reference: Optional dictionary to reply to a specific message.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_message","page":"API Reference","title":"Accord.edit_message","text":"edit_message(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String, body::Dict, files=nothing) -> Message\n\nEdit a previously sent message.\n\nUse this to update the content, embeds, or components of a message.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nbody::Dict: Fields to update. Set fields to nothing (null) to remove them.\nfiles: New attachments to append or replace.\n\nPermissions\n\nRequires MANAGE_MESSAGES if editing another user's message (which is generally not possible for content, only flags/suppression). You can always edit your own messages.\n\nErrors\n\nHTTP 403 if you try to edit someone else's message.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\nedit_message(client::Client, channel_id::Snowflake, message_id::Snowflake; kwargs...) -> Message\n\nUse this to modify a message your bot previously sent.\n\nEdit an existing message. kwargs correspond to the Discord API fields (content, embeds, etc.).\n\nExample\n\nedit_message(client, channel_id, message_id; content=\"Updated content!\")\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_message","page":"API Reference","title":"Accord.delete_message","text":"delete_message(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String, reason=nothing)\n\nDelete a message.\n\nUse this to remove a message permanently.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nreason::String: Audit log reason.\n\nPermissions\n\nRequires MANAGE_MESSAGES to delete other users' messages. You can always delete your own messages.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\ndelete_message(client::Client, channel_id::Snowflake, message_id::Snowflake; reason=nothing)\n\nUse this to remove a message from a channel.\n\nDelete a message.\n\nExample\n\ndelete_message(client, channel_id, message_id; reason=\"Spam\")\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.bulk_delete_messages","page":"API Reference","title":"Accord.bulk_delete_messages","text":"bulk_delete_messages(rl::RateLimiter, channel_id::Snowflake; token::String, message_ids::Vector{Snowflake}, reason=nothing)\n\nDelete multiple messages in a single request.\n\nUse this for moderation to quickly clear chat history. Can only delete messages that are less than 14 weeks old.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nmessage_ids::Vector{Snowflake}: List of message IDs to delete (2-100).\nreason::String: Audit log reason.\n\nPermissions\n\nRequires MANAGE_MESSAGES.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 400 if deleting < 2 or > 100 messages, or if messages are too old.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_channel_message","page":"API Reference","title":"Accord.get_channel_message","text":"get_channel_message(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String) -> Message\n\nRetrieve a specific message.\n\nUse this to get the current state of a message, including updated edits or reactions.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires READ_MESSAGE_HISTORY.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the channel or message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_channel_messages","page":"API Reference","title":"Accord.get_channel_messages","text":"get_channel_messages(rl::RateLimiter, channel_id::Snowflake; token::String, limit::Int=50, around=nothing, before=nothing, after=nothing) -> Vector{Message}\n\nRetrieve a list of messages from a channel.\n\nUse this to fetch message history for logs, analysis, or context.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nlimit::Int: Max number of messages to return (1-100, default 50).\naround::Snowflake: Get messages around this message ID.\nbefore::Snowflake: Get messages before this message ID.\nafter::Snowflake: Get messages after this message ID.\n\nPermissions\n\nRequires VIEW_CHANNEL and READ_MESSAGE_HISTORY.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.crosspost_message","page":"API Reference","title":"Accord.crosspost_message","text":"crosspost_message(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String) -> Message\n\nPublish a message from an Announcement Channel.\n\nUse this to push a message to all guilds that follow the announcement channel.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the announcement channel.\nmessage_id::Snowflake: The ID of the message to publish.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires SEND_MESSAGES and MANAGE_MESSAGES (or SEND_MESSAGES if it's your own message). Actually, for crossposting, it requires SEND_MESSAGES in the channel.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_reaction","page":"API Reference","title":"Accord.create_reaction","text":"create_reaction(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, emoji::String; token::String)\n\nAdd a reaction to a message.\n\nUse this to react with a unicode emoji (e.g., \"👍\") or a custom guild emoji.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nemoji::String: The emoji to react with. For custom emojis, use name:id.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires READ_MESSAGE_HISTORY and ADD_REACTIONS.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\ncreate_reaction(client::Client, channel_id::Snowflake, message_id::Snowflake, emoji::String)\n\nUse this to add an emoji reaction to a message on behalf of your bot.\n\nCreate a reaction on a message. The emoji parameter should be a URL-encoded string: \"👍\" or \"custom_emoji:123456\".\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_own_reaction","page":"API Reference","title":"Accord.delete_own_reaction","text":"delete_own_reaction(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, emoji::String; token::String)\n\nRemove the bot's own reaction.\n\nUse this to undo a reaction added by the bot.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nemoji::String: The emoji to remove.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nErrors\n\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_user_reaction","page":"API Reference","title":"Accord.delete_user_reaction","text":"delete_user_reaction(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, emoji::String, user_id::Snowflake; token::String)\n\nRemove a user's reaction.\n\nUse this for moderation to remove inappropriate reactions.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nemoji::String: The emoji to remove.\nuser_id::Snowflake: The ID of the user whose reaction to remove.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires MANAGE_MESSAGES.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message or user does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_all_reactions","page":"API Reference","title":"Accord.delete_all_reactions","text":"delete_all_reactions(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String)\n\nRemove all reactions from a message.\n\nUse this to clear a message of all emoji reactions.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires MANAGE_MESSAGES.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_all_reactions_for_emoji","page":"API Reference","title":"Accord.delete_all_reactions_for_emoji","text":"delete_all_reactions_for_emoji(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, emoji::String; token::String)\n\nRemove all reactions for a specific emoji.\n\nUse this to clear all votes for a single option or remove a specific emoji entirely.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nemoji::String: The emoji to remove.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires MANAGE_MESSAGES.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_reactions","page":"API Reference","title":"Accord.get_reactions","text":"get_reactions(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, emoji::String; token::String, limit::Int=25, type::Int=0) -> Vector{User}\n\nGet a list of users that reacted with an emoji.\n\nUse this to see who voted or reacted.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nemoji::String: The emoji to check.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nlimit::Int: Max number of users to return (1-100, default 25).\ntype::Int: 0 = normal, 1 = burst.\n\nErrors\n\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_answer_voters","page":"API Reference","title":"Accord.get_answer_voters","text":"get_answer_voters(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake, answer_id::Int; token::String, limit::Int=25) -> Dict\n\nGet users who voted for a specific poll answer.\n\nUse this to retrieve poll results.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\nanswer_id::Int: The ID of the answer choice (1-based index usually, but check Poll object).\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\nlimit::Int: Max number of users to return.\n\nErrors\n\nHTTP 404 if the message or answer does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.end_poll","page":"API Reference","title":"Accord.end_poll","text":"end_poll(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String) -> Message\n\nImmediately end a poll.\n\nUse this to close voting on a poll before its scheduled duration.\n\nArguments\n\nrl::RateLimiter: The rate limiter instance.\nchannel_id::Snowflake: The ID of the channel.\nmessage_id::Snowflake: The ID of the message.\n\nKeyword Arguments\n\ntoken::String: Bot authentication token.\n\nPermissions\n\nRequires MANAGE_MESSAGES (if not the author). Always allowed if you are the author.\n\nErrors\n\nHTTP 403 if missing permissions.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_channel","page":"API Reference","title":"Accord.get_channel","text":"get_channel(rl::RateLimiter, channel_id::Snowflake; token::String) -> DiscordChannel\n\nRetrieve a channel by its ID.\n\nThis is used when a bot needs to fetch channel information, such as when processing a command that references a channel or caching channel data.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the channel to retrieve.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot lacks permission to view the channel.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\nget_channel(client::Client, channel_id::Snowflake) -> DiscordChannel\n\nUse this to retrieve channel information, with automatic caching for performance.\n\nGet a channel by ID. Checks the local state cache first.\n\nExample\n\nchannel = get_channel(client, channel_id)\nprintln(\"Channel name: \", channel.name)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_channel","page":"API Reference","title":"Accord.modify_channel","text":"modify_channel(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict, reason=nothing) -> DiscordChannel\n\nUpdate a channel's settings.\n\nUse this when a bot needs to change channel properties like name, topic, position, or permission overwrites. Requires appropriate permissions based on the changes being made.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the channel to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Channel fields to update (name, type, position, topic, etc.).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS for most modifications. Thread modifications may require different permissions.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild","page":"API Reference","title":"Accord.get_guild","text":"get_guild(rl::RateLimiter, guild_id::Snowflake; token::String, with_counts::Bool=false) -> Guild\n\nRetrieve a guild by its ID.\n\nUse this when a bot needs to fetch guild information, such as guild settings, features, or member counts.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild to retrieve.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_counts::Bool — Include approximate member and presence counts.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\nget_guild(client::Client, guild_id::Snowflake) -> Guild\n\nUse this to retrieve server information, with automatic caching for performance.\n\nGet a guild by ID. Checks the local state cache first.\n\nExample\n\nguild = get_guild(client, guild_id)\nprintln(\"Server name: \", guild.name)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild","page":"API Reference","title":"Accord.modify_guild","text":"modify_guild(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Guild\n\nModify a guild's settings.\n\nUse this when a bot needs to update guild configuration such as name, icon, verification level, default notifications, or explicit content filter.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Guild fields to update.\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild","page":"API Reference","title":"Accord.delete_guild","text":"delete_guild(rl::RateLimiter, guild_id::Snowflake; token::String)\n\nDelete a guild permanently.\n\nUse this when a bot needs to delete a guild it owns. This action is irreversible.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nThe bot must be the owner of the guild.\n\nErrors\n\nHTTP 403 if the bot is not the guild owner.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_channels","page":"API Reference","title":"Accord.get_guild_channels","text":"get_guild_channels(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{DiscordChannel}\n\nGet all channels in a guild.\n\nUse this when a bot needs to list all channels in a guild, such as for channel management commands or initialization.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires VIEW_CHANNEL for channels the bot can see.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_channel","page":"API Reference","title":"Accord.create_guild_channel","text":"create_guild_channel(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> DiscordChannel\n\nCreate a new channel in a guild.\n\nUse this when a bot needs to create channels programmatically, such as for temporary channels, ticket systems, or dynamic channel creation.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Channel settings (name, type, parent, permission overwrites, etc.).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS.\n\nErrors\n\nHTTP 403 if missing required permissions or channel limit reached.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_channel_positions","page":"API Reference","title":"Accord.modify_guild_channel_positions","text":"modify_guild_channel_positions(rl::RateLimiter, guild_id::Snowflake; token::String, body::Vector)\n\nModify the positions of channels in a guild.\n\nUse this when a bot needs to reorder channels, such as for automatic category organization or dynamic channel sorting.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Vector — Array of channel position updates (id, position, lock_permissions).\n\nPermissions\n\nRequires MANAGE_CHANNELS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_guild_members","page":"API Reference","title":"Accord.list_guild_members","text":"list_guild_members(rl::RateLimiter, guild_id::Snowflake; token::String, limit::Int=1, after::Optional{Snowflake}=missing) -> Vector{Member}\n\nList members in a guild.\n\nUse this when a bot needs to retrieve guild members for member listing, searching, or batch processing operations.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum members to return (1-1000, default 1).\nafter::Snowflake — Get members after this user ID (for pagination).\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_member","page":"API Reference","title":"Accord.get_guild_member","text":"get_guild_member(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String) -> Member\n\nGet a guild member by user ID.\n\nUse this when a bot needs to fetch specific member information such as roles, nickname, join date, or permissions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the user.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the member or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.add_guild_member","page":"API Reference","title":"Accord.add_guild_member","text":"add_guild_member(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String, body::Dict) -> Member\n\nAdd a user to a guild using an OAuth2 access token.\n\nUse this when a bot needs to add users to guilds through OAuth2 authorization, such as for guild join systems or membership management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the user to add.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Must contain access_token and optionally nick and roles.\n\nPermissions\n\nRequires CREATE_INSTANT_INVITE.\n\nErrors\n\nHTTP 403 if missing required permissions or the user is already in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_member","page":"API Reference","title":"Accord.modify_guild_member","text":"modify_guild_member(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String, body::Dict, reason=nothing) -> Member\n\nModify attributes of a guild member.\n\nUse this when a bot needs to change a member's roles, nickname, timeout, or voice channel status.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the member to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Member fields to update (nick, roles, mute, deaf, etc.).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nMANAGE_NICKNAMES for changing nicknames.\nMANAGE_ROLES for managing roles.\nMODERATE_MEMBERS for timeouts.\nMOVE_MEMBERS for moving between voice channels.\n\nErrors\n\nHTTP 403 if missing required permissions or role hierarchy violation.\nHTTP 404 if the member or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_current_member","page":"API Reference","title":"Accord.modify_current_member","text":"modify_current_member(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Member\n\nModify the current bot member's attributes.\n\nUse this when a bot needs to change its own nickname in a guild.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Member fields to update (currently only nick is supported).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires CHANGE_NICKNAME or MANAGE_NICKNAMES.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.remove_guild_member","page":"API Reference","title":"Accord.remove_guild_member","text":"remove_guild_member(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String, reason=nothing)\n\nRemove a member from a guild (kick).\n\nUse this when a bot needs to kick users from the guild, such as for moderation commands or automated removal systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the member to remove.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the removal (optional).\n\nPermissions\n\nRequires KICK_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the member or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_bans","page":"API Reference","title":"Accord.get_guild_bans","text":"get_guild_bans(rl::RateLimiter, guild_id::Snowflake; token::String, limit::Int=1000) -> Vector{Ban}\n\nGet all bans in a guild.\n\nUse this when a bot needs to list banned users, such as for ban management commands or displaying ban lists to moderators.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum bans to return (default 1000).\n\nPermissions\n\nRequires BAN_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_ban","page":"API Reference","title":"Accord.get_guild_ban","text":"get_guild_ban(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String) -> Ban\n\nGet a specific ban for a user.\n\nUse this when a bot needs to check if a user is banned and see their ban reason, such as before attempting to unban or for ban information commands.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the user to check.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires BAN_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the user is not banned or the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_ban","page":"API Reference","title":"Accord.create_guild_ban","text":"create_guild_ban(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String, body::Dict=Dict(), reason=nothing)\n\nBan a user from a guild.\n\nUse this when a bot needs to ban users, such as for moderation commands or automated ban systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the user to ban.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Ban options (deletemessagedays, deletemessageseconds).\nreason::String — Audit log reason for the ban (optional).\n\nPermissions\n\nRequires BAN_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions or if the bot cannot ban the target.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.remove_guild_ban","page":"API Reference","title":"Accord.remove_guild_ban","text":"remove_guild_ban(rl::RateLimiter, guild_id::Snowflake, user_id::Snowflake; token::String, reason=nothing)\n\nUnban a user from a guild.\n\nUse this when a bot needs to remove bans, such as for unban commands, temporary bans, or ban appeal systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nuser_id::Snowflake — The ID of the user to unban.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the unban (optional).\n\nPermissions\n\nRequires BAN_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the user is not banned or the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.bulk_guild_ban","page":"API Reference","title":"Accord.bulk_guild_ban","text":"bulk_guild_ban(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Dict{String, Any}\n\nBan up to 200 users from a guild.\n\nUse this when a bot needs to ban multiple users at once, such as for raid protection or mass moderation actions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Contains user_ids array and optional delete_message_seconds.\nreason::String — Audit log reason for the bans (optional).\n\nPermissions\n\nRequires BAN_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_roles","page":"API Reference","title":"Accord.get_guild_roles","text":"get_guild_roles(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Role}\n\nGet all roles in a guild.\n\nUse this when a bot needs to list guild roles, such as for role management commands or permission checking.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_role","page":"API Reference","title":"Accord.get_guild_role","text":"get_guild_role(rl::RateLimiter, guild_id::Snowflake, role_id::Snowflake; token::String) -> Role\n\nGet a specific role by ID.\n\nUse this when a bot needs to retrieve detailed information about a single role, such as for role management or permission checking.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrole_id::Snowflake — The ID of the role.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the role or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_role","page":"API Reference","title":"Accord.create_guild_role","text":"create_guild_role(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict=Dict(), reason=nothing) -> Role\n\nCreate a new role in a guild.\n\nUse this when a bot needs to create roles programmatically, such as for reaction roles, self-assignable roles, or temporary role systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Role settings (name, permissions, color, hoist, mentionable, etc.).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_ROLES.\n\nErrors\n\nHTTP 403 if missing required permissions or role limit reached.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_role_positions","page":"API Reference","title":"Accord.modify_guild_role_positions","text":"modify_guild_role_positions(rl::RateLimiter, guild_id::Snowflake; token::String, body::Vector, reason=nothing) -> Vector{Role}\n\nModify the positions of roles in a guild.\n\nUse this when a bot needs to reorder roles, such as for role hierarchy management or sorting by activity/level.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Vector — Array of role position updates (id, position).\nreason::String — Audit log reason for the changes (optional).\n\nPermissions\n\nRequires MANAGE_ROLES.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_role","page":"API Reference","title":"Accord.modify_guild_role","text":"modify_guild_role(rl::RateLimiter, guild_id::Snowflake, role_id::Snowflake; token::String, body::Dict, reason=nothing) -> Role\n\nModify a guild role.\n\nUse this when a bot needs to update role properties such as name, color, permissions, or mentionability.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrole_id::Snowflake — The ID of the role to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Role fields to update.\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_ROLES and the bot's top role must be higher than the target role.\n\nErrors\n\nHTTP 403 if missing required permissions or role hierarchy violation.\nHTTP 404 if the role or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_role","page":"API Reference","title":"Accord.delete_guild_role","text":"delete_guild_role(rl::RateLimiter, guild_id::Snowflake, role_id::Snowflake; token::String, reason=nothing)\n\nDelete a guild role.\n\nUse this when a bot needs to remove roles, such as for cleanup of temporary roles or automated role removal.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrole_id::Snowflake — The ID of the role to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_ROLES and the bot's top role must be higher than the target role.\n\nErrors\n\nHTTP 403 if missing required permissions or role hierarchy violation.\nHTTP 404 if the role or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_prune_count","page":"API Reference","title":"Accord.get_guild_prune_count","text":"get_guild_prune_count(rl::RateLimiter, guild_id::Snowflake; token::String, days::Int=7, include_roles::String=\"\") -> Dict{String, Any}\n\nGet the number of members that would be pruned.\n\nUse this when a bot needs to preview the results of a prune operation without actually removing members.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\ndays::Int — Number of days of inactivity to count (1-30, default 7).\ninclude_roles — Comma-separated list of role IDs to include.\n\nPermissions\n\nRequires KICK_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.begin_guild_prune","page":"API Reference","title":"Accord.begin_guild_prune","text":"begin_guild_prune(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Dict{String, Any}\n\nPrune inactive members from a guild.\n\nUse this when a bot needs to remove members who haven't been active for a specified number of days.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Prune options (days, computeprunecount, include_roles, etc.).\nreason::String — Audit log reason for the prune (optional).\n\nPermissions\n\nRequires KICK_MEMBERS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_voice_regions","page":"API Reference","title":"Accord.get_guild_voice_regions","text":"get_guild_voice_regions(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{VoiceRegion}\n\nGet available voice regions for a guild.\n\nUse this when a bot needs to list voice regions available to the guild, which may differ from the global list due to VIP server status.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_invites","page":"API Reference","title":"Accord.get_guild_invites","text":"get_guild_invites(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Invite}\n\nGet all invites in a guild.\n\nUse this when a bot needs to list active invites for moderation, analytics, or invite management purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_integrations","page":"API Reference","title":"Accord.get_guild_integrations","text":"get_guild_integrations(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Integration}\n\nGet all integrations for a guild.\n\nUse this when a bot needs to list connected integrations such as Twitch, YouTube, or other third-party services.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_integration","page":"API Reference","title":"Accord.delete_guild_integration","text":"delete_guild_integration(rl::RateLimiter, guild_id::Snowflake, integration_id::Snowflake; token::String, reason=nothing)\n\nDelete an integration from a guild.\n\nUse this when a bot needs to remove third-party integrations from the guild.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nintegration_id::Snowflake — The ID of the integration to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the integration or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_widget_settings","page":"API Reference","title":"Accord.get_guild_widget_settings","text":"get_guild_widget_settings(rl::RateLimiter, guild_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet the guild widget settings.\n\nUse this when a bot needs to check the widget configuration, such as whether the widget is enabled and which channel it displays.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_widget","page":"API Reference","title":"Accord.modify_guild_widget","text":"modify_guild_widget(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Dict{String, Any}\n\nModify the guild widget settings.\n\nUse this when a bot needs to enable/disable the widget or change the widget channel.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Widget settings (enabled, channel_id).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_widget","page":"API Reference","title":"Accord.get_guild_widget","text":"get_guild_widget(rl::RateLimiter, guild_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet the guild widget JSON data.\n\nUse this when a bot needs to retrieve public widget data for the guild, which can be used to display online members and invite links.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the guild widget is disabled or the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_vanity_url","page":"API Reference","title":"Accord.get_guild_vanity_url","text":"get_guild_vanity_url(rl::RateLimiter, guild_id::Snowflake; token::String) -> Invite\n\nGet the vanity URL for a guild.\n\nUse this when a bot needs to retrieve or display a guild's custom invite URL.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild has no vanity URL.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_welcome_screen","page":"API Reference","title":"Accord.get_guild_welcome_screen","text":"get_guild_welcome_screen(rl::RateLimiter, guild_id::Snowflake; token::String) -> WelcomeScreen\n\nGet the welcome screen for a guild.\n\nUse this when a bot needs to display or cache the guild's welcome screen, which shows description and recommended channels for new members.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the guild has no welcome screen enabled.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_welcome_screen","page":"API Reference","title":"Accord.modify_guild_welcome_screen","text":"modify_guild_welcome_screen(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> WelcomeScreen\n\nModify the welcome screen for a guild.\n\nUse this when a bot needs to update the guild's welcome screen, such as changing the description or recommended channels.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Welcome screen settings (enabled, description, welcome_channels).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_onboarding","page":"API Reference","title":"Accord.get_guild_onboarding","text":"get_guild_onboarding(rl::RateLimiter, guild_id::Snowflake; token::String) -> Onboarding\n\nGet the onboarding configuration for a guild.\n\nUse this when a bot needs to retrieve the guild's onboarding prompts and settings for new member guidance.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_onboarding","page":"API Reference","title":"Accord.modify_guild_onboarding","text":"modify_guild_onboarding(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Onboarding\n\nModify the onboarding configuration for a guild.\n\nUse this when a bot needs to update the guild's onboarding prompts, default channels, or other new member guidance settings.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Onboarding configuration (prompts, defaultchannelids, etc.).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.start_thread_from_message","page":"API Reference","title":"Accord.start_thread_from_message","text":"start_thread_from_message(rl::RateLimiter, channel_id::Snowflake, message_id::Snowflake; token::String, body::Dict, reason=nothing) -> DiscordChannel\n\nCreate a new thread from an existing message.\n\nUse this when a bot needs to create a discussion thread around a specific message, such as for off-topic conversations or detailed discussions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the parent channel (must support threads).\nmessage_id::Snowflake — The ID of the message to start the thread from.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Thread settings (name, autoarchiveduration, ratelimitper_user).\nreason::String — Audit log reason for creating the thread (optional).\n\nPermissions\n\nRequires CREATE_PUBLIC_THREADS for public threads.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel or message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.start_thread_without_message","page":"API Reference","title":"Accord.start_thread_without_message","text":"start_thread_without_message(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict, reason=nothing) -> DiscordChannel\n\nCreate a new thread without an existing message.\n\nUse this when a bot needs to create a standalone thread, such as for announcements, support tickets, or scheduled discussions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the parent channel (must support threads).\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Thread settings (name, type, autoarchiveduration, etc.).\nreason::String — Audit log reason for creating the thread (optional).\n\nPermissions\n\nRequires CREATE_PUBLIC_THREADS for public threads or CREATE_PRIVATE_THREADS for private threads.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.start_thread_in_forum","page":"API Reference","title":"Accord.start_thread_in_forum","text":"start_thread_in_forum(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict, files=nothing, reason=nothing) -> DiscordChannel\n\nCreate a new post in a forum channel.\n\nUse this when a bot needs to create a forum post with optional attachments, such as for automated announcements, support tickets, or content sharing.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the forum channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Post settings (name, message, applied_tags).\nfiles — File attachments for the post (optional).\nreason::String — Audit log reason for creating the post (optional).\n\nPermissions\n\nRequires SEND_MESSAGES in the forum channel.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.join_thread","page":"API Reference","title":"Accord.join_thread","text":"join_thread(rl::RateLimiter, channel_id::Snowflake; token::String)\n\nAdd the bot user to a thread.\n\nUse this when a bot needs to join a thread to send messages or receive events from it, such as when participating in a conversation.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread (threads are also channels).\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the thread is private and the bot wasn't added.\nHTTP 404 if the thread does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.add_thread_member","page":"API Reference","title":"Accord.add_thread_member","text":"add_thread_member(rl::RateLimiter, channel_id::Snowflake, user_id::Snowflake; token::String)\n\nAdd another user to a thread.\n\nUse this when a bot needs to add a specific user to a thread, such as for moderation purposes or bringing someone into a conversation.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread.\nuser_id::Snowflake — The ID of the user to add.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_THREADS to add members to private threads.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the thread or user does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.leave_thread","page":"API Reference","title":"Accord.leave_thread","text":"leave_thread(rl::RateLimiter, channel_id::Snowflake; token::String)\n\nRemove the bot user from a thread.\n\nUse this when a bot no longer needs to participate in a thread or when cleaning up thread memberships.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the thread does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.remove_thread_member","page":"API Reference","title":"Accord.remove_thread_member","text":"remove_thread_member(rl::RateLimiter, channel_id::Snowflake, user_id::Snowflake; token::String)\n\nRemove a user from a thread.\n\nUse this when a bot needs to remove someone from a thread, such as for moderation purposes or managing private thread access.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread.\nuser_id::Snowflake — The ID of the user to remove.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_THREADS to remove members from private threads.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the thread or user does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_thread_member","page":"API Reference","title":"Accord.get_thread_member","text":"get_thread_member(rl::RateLimiter, channel_id::Snowflake, user_id::Snowflake; token::String, with_member::Bool=false) -> ThreadMember\n\nGet a thread member object for a user.\n\nUse this when a bot needs to check a user's thread membership status or retrieve their thread-specific member information.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread.\nuser_id::Snowflake — The ID of the user.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_member::Bool — Include guild member data in the response.\n\nPermissions\n\nRequires MANAGE_THREADS for private threads.\n\nErrors\n\nHTTP 403 if missing required permissions (for private threads).\nHTTP 404 if the thread or user does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_thread_members","page":"API Reference","title":"Accord.list_thread_members","text":"list_thread_members(rl::RateLimiter, channel_id::Snowflake; token::String, with_member::Bool=false, limit::Int=100) -> Vector{ThreadMember}\n\nGet all members of a thread.\n\nUse this when a bot needs to list participants in a thread, such as for thread management or notification purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the thread.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_member::Bool — Include guild member data for each member.\nlimit::Int — Maximum number of members to return (1-100, default 100).\n\nPermissions\n\nRequires MANAGE_THREADS for private threads.\n\nErrors\n\nHTTP 403 if missing required permissions (for private threads).\nHTTP 404 if the thread does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_public_archived_threads","page":"API Reference","title":"Accord.list_public_archived_threads","text":"list_public_archived_threads(rl::RateLimiter, channel_id::Snowflake; token::String, limit::Int=50) -> Dict{String, Any}\n\nGet archived public threads in a channel.\n\nUse this when a bot needs to browse or search through archived public threads, such as for thread discovery or archival features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the parent channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum threads to return (default 50).\n\nErrors\n\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_private_archived_threads","page":"API Reference","title":"Accord.list_private_archived_threads","text":"list_private_archived_threads(rl::RateLimiter, channel_id::Snowflake; token::String, limit::Int=50) -> Dict{String, Any}\n\nGet archived private threads in a channel.\n\nUse this when a bot needs to browse private archived threads that the bot has access to, such as for moderation or content management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the parent channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum threads to return (default 50).\n\nPermissions\n\nRequires MANAGE_THREADS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_joined_private_archived_threads","page":"API Reference","title":"Accord.list_joined_private_archived_threads","text":"list_joined_private_archived_threads(rl::RateLimiter, channel_id::Snowflake; token::String, limit::Int=50) -> Dict{String, Any}\n\nGet archived private threads that the bot has joined in a channel.\n\nUse this when a bot needs to list private threads it has access to through membership, such as for thread management or notification purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the parent channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum threads to return (default 50).\n\nErrors\n\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_active_guild_threads","page":"API Reference","title":"Accord.list_active_guild_threads","text":"list_active_guild_threads(rl::RateLimiter, guild_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet all active threads in a guild.\n\nUse this when a bot needs to list active threads for thread management, moderation, or archival purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_global_application_commands","page":"API Reference","title":"Accord.get_global_application_commands","text":"get_global_application_commands(rl::RateLimiter, application_id::Snowflake; token::String, with_localizations::Bool=false) -> Vector{ApplicationCommand}\n\nGet all global application commands for the bot.\n\nUse this when a bot needs to list or sync its global slash commands. Global commands are available in all guilds and take up to an hour to propagate.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_localizations::Bool — Include name and description localizations.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_global_application_command","page":"API Reference","title":"Accord.create_global_application_command","text":"create_global_application_command(rl::RateLimiter, application_id::Snowflake; token::String, body::Dict) -> ApplicationCommand\n\nCreate a new global application command.\n\nUse this when a bot needs to register a new global slash command, context menu command, or autocomplete command.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Command definition (name, description, type, options, etc.).\n\nErrors\n\nHTTP 400 if the command data is invalid or name/description requirements not met.\nHTTP 401 if the token is invalid.\nHTTP 429 if too many commands created (limit is 100 global commands).\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_global_application_command","page":"API Reference","title":"Accord.get_global_application_command","text":"get_global_application_command(rl::RateLimiter, application_id::Snowflake, command_id::Snowflake; token::String) -> ApplicationCommand\n\nGet a specific global application command.\n\nUse this when a bot needs to retrieve details of a specific global command, such as for editing or inspection.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ncommand_id::Snowflake — The ID of the command.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_global_application_command","page":"API Reference","title":"Accord.edit_global_application_command","text":"edit_global_application_command(rl::RateLimiter, application_id::Snowflake, command_id::Snowflake; token::String, body::Dict) -> ApplicationCommand\n\nEdit a global application command.\n\nUse this when a bot needs to update an existing global command's name, description, options, or other properties.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ncommand_id::Snowflake — The ID of the command to edit.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated command fields.\n\nErrors\n\nHTTP 400 if the updated data is invalid.\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_global_application_command","page":"API Reference","title":"Accord.delete_global_application_command","text":"delete_global_application_command(rl::RateLimiter, application_id::Snowflake, command_id::Snowflake; token::String)\n\nDelete a global application command.\n\nUse this when a bot needs to remove a global command. Deletion is irreversible and will immediately remove the command from all guilds.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ncommand_id::Snowflake — The ID of the command to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.bulk_overwrite_global_application_commands","page":"API Reference","title":"Accord.bulk_overwrite_global_application_commands","text":"bulk_overwrite_global_application_commands(rl::RateLimiter, application_id::Snowflake; token::String, body::Vector) -> Vector{ApplicationCommand}\n\nReplace all global application commands with a new set.\n\nUse this when a bot needs to perform a complete command sync, such as during startup or when updating all commands at once. This is more efficient than creating commands individually.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Vector — Array of command definitions to set.\n\nErrors\n\nHTTP 400 if any command data is invalid.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_application_commands","page":"API Reference","title":"Accord.get_guild_application_commands","text":"get_guild_application_commands(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake; token::String, with_localizations::Bool=false) -> Vector{ApplicationCommand}\n\nGet all application commands for a specific guild.\n\nUse this when a bot needs to list guild-specific commands, which take precedence over global commands in that guild.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_localizations::Bool — Include name and description localizations.\n\nPermissions\n\nRequires VIEW_CHANNEL in the guild.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild or application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_application_command","page":"API Reference","title":"Accord.create_guild_application_command","text":"create_guild_application_command(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake; token::String, body::Dict) -> ApplicationCommand\n\nCreate a guild-specific application command.\n\nUse this when a bot needs to register a command that is only available in a specific guild. Guild commands are available immediately (no propagation delay).\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Command definition.\n\nPermissions\n\nRequires VIEW_CHANNEL in the guild.\n\nErrors\n\nHTTP 400 if the command data is invalid.\nHTTP 403 if the bot is not in the guild.\nHTTP 429 if too many commands created (limit is 100 guild commands).\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_application_command","page":"API Reference","title":"Accord.get_guild_application_command","text":"get_guild_application_command(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake, command_id::Snowflake; token::String) -> ApplicationCommand\n\nGet a specific guild application command.\n\nUse this when a bot needs to retrieve details of a guild-specific command.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\ncommand_id::Snowflake — The ID of the command.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_guild_application_command","page":"API Reference","title":"Accord.edit_guild_application_command","text":"edit_guild_application_command(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake, command_id::Snowflake; token::String, body::Dict) -> ApplicationCommand\n\nEdit a guild-specific application command.\n\nUse this when a bot needs to update a guild command's properties.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\ncommand_id::Snowflake — The ID of the command to edit.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated command fields.\n\nErrors\n\nHTTP 400 if the updated data is invalid.\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_application_command","page":"API Reference","title":"Accord.delete_guild_application_command","text":"delete_guild_application_command(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake, command_id::Snowflake; token::String)\n\nDelete a guild-specific application command.\n\nUse this when a bot needs to remove a guild command. Changes are immediate.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\ncommand_id::Snowflake — The ID of the command to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the command does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.bulk_overwrite_guild_application_commands","page":"API Reference","title":"Accord.bulk_overwrite_guild_application_commands","text":"bulk_overwrite_guild_application_commands(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake; token::String, body::Vector) -> Vector{ApplicationCommand}\n\nReplace all guild application commands with a new set.\n\nUse this when a bot needs to perform a complete guild command sync. This is more efficient than updating commands individually and takes effect immediately.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Vector — Array of command definitions to set.\n\nErrors\n\nHTTP 400 if any command data is invalid.\nHTTP 403 if the bot is not in the guild.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_application_command_permissions","page":"API Reference","title":"Accord.get_guild_application_command_permissions","text":"get_guild_application_command_permissions(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake; token::String) -> Vector{Dict{String, Any}}\n\nGet permissions for all commands in a guild.\n\nUse this when a bot needs to list command permission overwrites for a guild, showing which roles and users can use specific commands.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires ADMINISTRATOR or application ownership.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild or application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_application_command_permissions","page":"API Reference","title":"Accord.get_application_command_permissions","text":"get_application_command_permissions(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake, command_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet permissions for a specific command in a guild.\n\nUse this when a bot needs to check the permission overwrites for a specific guild command.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\ncommand_id::Snowflake — The ID of the command.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires ADMINISTRATOR or application ownership.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the command or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_application_command_permissions","page":"API Reference","title":"Accord.edit_application_command_permissions","text":"edit_application_command_permissions(rl::RateLimiter, application_id::Snowflake, guild_id::Snowflake, command_id::Snowflake; token::String, body::Dict) -> Dict{String, Any}\n\nEdit permissions for a specific command in a guild.\n\nUse this when a bot needs to restrict or grant command access to specific roles or users in a guild.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nguild_id::Snowflake — The ID of the guild.\ncommand_id::Snowflake — The ID of the command.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Permission overwrites array.\n\nPermissions\n\nRequires ADMINISTRATOR.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the command or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_original_interaction_response","page":"API Reference","title":"Accord.get_original_interaction_response","text":"get_original_interaction_response(rl::RateLimiter, application_id::Snowflake, interaction_token::String; token::String) -> Message\n\nGet the original response message for an interaction.\n\nUse this when a bot needs to fetch the message that was sent as the initial interaction response, such as for editing or reference.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if no response message exists.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_original_interaction_response","page":"API Reference","title":"Accord.edit_original_interaction_response","text":"edit_original_interaction_response(rl::RateLimiter, application_id::Snowflake, interaction_token::String; token::String, body::Dict, files=nothing) -> Message\n\nEdit the original response message for an interaction.\n\nUse this when a bot needs to update the message that was sent as the initial response, such as to show updated information or results.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated message content.\nfiles — New file attachments (optional).\n\nErrors\n\nHTTP 400 if the message data is invalid.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_original_interaction_response","page":"API Reference","title":"Accord.delete_original_interaction_response","text":"delete_original_interaction_response(rl::RateLimiter, application_id::Snowflake, interaction_token::String; token::String)\n\nDelete the original response message for an interaction.\n\nUse this when a bot needs to remove the message that was sent as the initial response.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_followup_message","page":"API Reference","title":"Accord.create_followup_message","text":"create_followup_message(rl::RateLimiter, application_id::Snowflake, interaction_token::String; token::String, body::Dict, files=nothing) -> Message\n\nCreate a followup message for an interaction.\n\nUse this when a bot needs to send additional messages after the initial response, such as for multi-step interactions or additional notifications.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Message content.\nfiles — File attachments (optional).\n\nErrors\n\nHTTP 400 if the message data is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_followup_message","page":"API Reference","title":"Accord.get_followup_message","text":"get_followup_message(rl::RateLimiter, application_id::Snowflake, interaction_token::String, message_id::Snowflake; token::String) -> Message\n\nGet a specific followup message for an interaction.\n\nUse this when a bot needs to retrieve a previously sent followup message.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\nmessage_id::Snowflake — The ID of the followup message.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_followup_message","page":"API Reference","title":"Accord.edit_followup_message","text":"edit_followup_message(rl::RateLimiter, application_id::Snowflake, interaction_token::String, message_id::Snowflake; token::String, body::Dict, files=nothing) -> Message\n\nEdit a followup message for an interaction.\n\nUse this when a bot needs to update a previously sent followup message, such as to correct information or show updated status.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\nmessage_id::Snowflake — The ID of the followup message to edit.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated message content.\nfiles — New file attachments (optional).\n\nErrors\n\nHTTP 400 if the message data is invalid.\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_followup_message","page":"API Reference","title":"Accord.delete_followup_message","text":"delete_followup_message(rl::RateLimiter, application_id::Snowflake, interaction_token::String, message_id::Snowflake; token::String)\n\nDelete a followup message for an interaction.\n\nUse this when a bot needs to remove a previously sent followup message.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\ninteraction_token::String — The interaction token.\nmessage_id::Snowflake — The ID of the followup message to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the message does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_current_user","page":"API Reference","title":"Accord.get_current_user","text":"get_current_user(rl::RateLimiter; token::String) -> User\n\nGet the bot's own user object.\n\nUse this when a bot needs to retrieve its own user information, such as username, ID, avatar, and discriminator. This is commonly used during initialization to confirm authentication.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid or expired.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_user","page":"API Reference","title":"Accord.get_user","text":"get_user(rl::RateLimiter, user_id::Snowflake; token::String) -> User\n\nGet a user by ID.\n\nUse this when a bot needs to retrieve information about a specific user, such as username, avatar, or public flags. Only returns public information.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nuser_id::Snowflake — The ID of the user to retrieve.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the user does not exist.\n\nDiscord docs\n\n\n\n\n\nget_user(client::Client, user_id::Snowflake) -> User\n\nUse this to retrieve user information, with automatic caching for performance.\n\nGet a user by ID. Checks the local state cache first.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_current_user","page":"API Reference","title":"Accord.modify_current_user","text":"modify_current_user(rl::RateLimiter; token::String, body::Dict) -> User\n\nModify the bot's own user account settings.\n\nUse this when a bot needs to update its own profile, such as changing its username or avatar. Use with caution as username changes are rate limited.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — User fields to update (username, avatar base64).\n\nRate Limits\n\nUsername changes are heavily rate limited (typically twice per hour).\n\nErrors\n\nHTTP 400 if the username or avatar is invalid.\nHTTP 401 if the token is invalid.\nHTTP 429 if too many username changes attempted.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_current_user_guilds","page":"API Reference","title":"Accord.get_current_user_guilds","text":"get_current_user_guilds(rl::RateLimiter; token::String, limit::Int=200, before::Optional{Snowflake}=missing, after::Optional{Snowflake}=missing) -> Vector{Guild}\n\nGet the guilds the bot is a member of.\n\nUse this when a bot needs to list the servers it has joined, such as for guild management features or admin dashboards.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum guilds to return (1-200, default 200).\nbefore::Snowflake — Get guilds before this guild ID.\nafter::Snowflake — Get guilds after this guild ID.\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_dm","page":"API Reference","title":"Accord.create_dm","text":"create_dm(rl::RateLimiter; token::String, recipient_id::Snowflake) -> DiscordChannel\n\nCreate a direct message channel with a user.\n\nUse this when a bot needs to initiate a private conversation with a user, such as for sending DMs, confirmation messages, or support interactions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nrecipient_id::Snowflake — The ID of the user to create a DM with.\n\nNotes\n\nYou should not use this endpoint to spam users or send unsolicited messages.\nThe bot cannot DM users who have not enabled DMs from server members.\n\nErrors\n\nHTTP 400 if the user cannot be messaged.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_current_user_connections","page":"API Reference","title":"Accord.get_current_user_connections","text":"get_current_user_connections(rl::RateLimiter; token::String) -> Vector{Connection}\n\nGet the third-party connections linked to the bot's account.\n\nUse this when a bot needs to retrieve connected services such as Twitch, YouTube, Spotify, or other OAuth-linked platforms. Note that bots typically do not have connections, this is more useful for OAuth2 applications.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Authentication token (can be OAuth2 user token).\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_current_user_application_role_connection","page":"API Reference","title":"Accord.get_current_user_application_role_connection","text":"get_current_user_application_role_connection(rl::RateLimiter, application_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet the role connection metadata for the bot's account.\n\nUse this when a bot needs to retrieve Linked Role verification data for the current user (typically used with OAuth2 applications for role verification).\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Authentication token (typically OAuth2 user token).\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if no role connection exists.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.update_current_user_application_role_connection","page":"API Reference","title":"Accord.update_current_user_application_role_connection","text":"update_current_user_application_role_connection(rl::RateLimiter, application_id::Snowflake; token::String, body::Dict) -> Dict{String, Any}\n\nUpdate the role connection metadata for the bot's account.\n\nUse this when a bot needs to update Linked Role verification data, such as for applications that provide role verification based on external platform data.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Authentication token (typically OAuth2 user token).\nbody::Dict — Role connection metadata (platformname, platformusername, metadata).\n\nErrors\n\nHTTP 400 if the metadata is invalid.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_gateway_bot","page":"API Reference","title":"Accord.get_gateway_bot","text":"get_gateway_bot(token::String) -> (url, shards, session_start_limit)\n\nUse this to retrieve gateway connection info and determine how many shards your bot needs.\n\nFetch /gateway/bot to get recommended shard count and session limits.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_webhook","page":"API Reference","title":"Accord.create_webhook","text":"create_webhook(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict, reason=nothing) -> Webhook\n\nCreate a new webhook in a channel.\n\nUse this when a bot needs to create webhooks for external message posting, such as for GitHub notifications, RSS feeds, or third-party integrations.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the channel where the webhook will be created.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Webhook settings (name, avatar).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_WEBHOOKS.\n\nErrors\n\nHTTP 400 if the webhook name is invalid or too long (max 80 characters).\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_channel_webhooks","page":"API Reference","title":"Accord.get_channel_webhooks","text":"get_channel_webhooks(rl::RateLimiter, channel_id::Snowflake; token::String) -> Vector{Webhook}\n\nGet all webhooks in a channel.\n\nUse this when a bot needs to list webhooks for management, such as for webhook configuration commands or cleanup utilities.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_WEBHOOKS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the channel does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_webhooks","page":"API Reference","title":"Accord.get_guild_webhooks","text":"get_guild_webhooks(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Webhook}\n\nGet all webhooks in a guild.\n\nUse this when a bot needs to list all webhooks across a guild, such as for audit or bulk webhook management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_WEBHOOKS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_webhook","page":"API Reference","title":"Accord.get_webhook","text":"get_webhook(rl::RateLimiter, webhook_id::Snowflake; token::String) -> Webhook\n\nGet a webhook by ID.\n\nUse this when a bot needs to retrieve webhook details, such as for configuration checking or validation.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_WEBHOOKS in the webhook's channel.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_webhook_with_token","page":"API Reference","title":"Accord.get_webhook_with_token","text":"get_webhook_with_token(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String; token::String) -> Webhook\n\nGet a webhook using its token.\n\nUse this when external services need to fetch webhook information using only the webhook URL components (ID and token), without needing bot authentication.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token (for additional validation).\n\nErrors\n\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_webhook","page":"API Reference","title":"Accord.modify_webhook","text":"modify_webhook(rl::RateLimiter, webhook_id::Snowflake; token::String, body::Dict, reason=nothing) -> Webhook\n\nModify a webhook.\n\nUse this when a bot needs to update webhook settings such as name, avatar, or channel location.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated webhook fields (name, avatar, channel_id).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_WEBHOOKS in the webhook's channel.\n\nErrors\n\nHTTP 400 if the webhook name is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_webhook_with_token","page":"API Reference","title":"Accord.modify_webhook_with_token","text":"modify_webhook_with_token(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String; body::Dict, reason=nothing) -> Webhook\n\nModify a webhook using its token.\n\nUse this when external services need to update webhook settings without requiring bot authentication, using only the webhook credentials.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\n\nKeyword Arguments\n\nbody::Dict — Updated webhook fields.\nreason::String — Audit log reason (optional, requires bot auth).\n\nErrors\n\nHTTP 400 if the webhook name is invalid.\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_webhook","page":"API Reference","title":"Accord.delete_webhook","text":"delete_webhook(rl::RateLimiter, webhook_id::Snowflake; token::String, reason=nothing)\n\nDelete a webhook permanently.\n\nUse this when a bot needs to remove webhooks, such as for cleanup of unused webhooks or webhook management commands.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_WEBHOOKS in the webhook's channel.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_webhook_with_token","page":"API Reference","title":"Accord.delete_webhook_with_token","text":"delete_webhook_with_token(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String; reason=nothing)\n\nDelete a webhook using its token.\n\nUse this when external services need to delete webhooks without requiring bot authentication, using only the webhook credentials.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\n\nKeyword Arguments\n\nreason::String — Audit log reason (optional, requires bot auth).\n\nErrors\n\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.execute_webhook","page":"API Reference","title":"Accord.execute_webhook","text":"execute_webhook(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String; token::String, body::Dict, files=nothing, wait::Bool=false, thread_id=nothing) -> Union{Message, Response}\n\nExecute a webhook to send a message.\n\nUse this when a bot or external service needs to post messages via webhook, such as for cross-platform notifications or automated announcements.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Message content (content, embeds, components, etc.).\nfiles — File attachments (optional).\nwait::Bool — Wait for server confirmation and return the created message.\nthread_id — Send to a specific forum thread or channel thread.\n\nErrors\n\nHTTP 400 if the message data is invalid.\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the webhook does not exist.\nHTTP 429 if rate limited (webhooks have their own rate limits).\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_webhook_message","page":"API Reference","title":"Accord.get_webhook_message","text":"get_webhook_message(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String, message_id::Snowflake; token::String) -> Message\n\nGet a message sent by a webhook.\n\nUse this when a bot needs to retrieve a message that was previously sent via webhook, such as for editing or reference.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\nmessage_id::Snowflake — The ID of the message.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the message or webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_webhook_message","page":"API Reference","title":"Accord.edit_webhook_message","text":"edit_webhook_message(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String, message_id::Snowflake; token::String, body::Dict, files=nothing) -> Message\n\nEdit a message sent by a webhook.\n\nUse this when a bot or external service needs to update a previously sent webhook message, such as to correct information or show progress.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\nmessage_id::Snowflake — The ID of the message to edit.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated message content.\nfiles — New file attachments (optional).\n\nErrors\n\nHTTP 400 if the message data is invalid.\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the message or webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_webhook_message","page":"API Reference","title":"Accord.delete_webhook_message","text":"delete_webhook_message(rl::RateLimiter, webhook_id::Snowflake, webhook_token::String, message_id::Snowflake; token::String)\n\nDelete a message sent by a webhook.\n\nUse this when a bot needs to remove a previously sent webhook message.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nwebhook_id::Snowflake — The ID of the webhook.\nwebhook_token::String — The webhook token.\nmessage_id::Snowflake — The ID of the message to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the webhook token is invalid.\nHTTP 404 if the message or webhook does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_guild_emojis","page":"API Reference","title":"Accord.list_guild_emojis","text":"list_guild_emojis(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Emoji}\n\nGet all custom emojis in a guild.\n\nUse this when a bot needs to list available custom emojis, such as for emoji management commands or reaction role systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_emoji","page":"API Reference","title":"Accord.get_guild_emoji","text":"get_guild_emoji(rl::RateLimiter, guild_id::Snowflake, emoji_id::Snowflake; token::String) -> Emoji\n\nGet a specific custom emoji from a guild.\n\nUse this when a bot needs to retrieve information about a single emoji, such as its name, roles, or creator.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nemoji_id::Snowflake — The ID of the emoji.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 403 if the bot is not in the guild.\nHTTP 404 if the emoji or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_emoji","page":"API Reference","title":"Accord.create_guild_emoji","text":"create_guild_emoji(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> Emoji\n\nCreate a new custom emoji in a guild.\n\nUse this when a bot needs to upload custom emojis programmatically, such as for emoji management tools or automated emoji creation systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Emoji data (name, image base64, roles).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nEmoji Requirements\n\nImage must be at most 256KB in size.\nDimensions must be at least 128x128 pixels.\nSupports PNG, JPEG, or GIF formats (animated GIFs allowed with appropriate plan).\n\nErrors\n\nHTTP 400 if the image is too large or invalid format.\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_emoji","page":"API Reference","title":"Accord.modify_guild_emoji","text":"modify_guild_emoji(rl::RateLimiter, guild_id::Snowflake, emoji_id::Snowflake; token::String, body::Dict, reason=nothing) -> Emoji\n\nModify a custom emoji in a guild.\n\nUse this when a bot needs to update emoji properties such as name or role restrictions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nemoji_id::Snowflake — The ID of the emoji to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated emoji fields (name, roles).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 400 if the name is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the emoji or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_emoji","page":"API Reference","title":"Accord.delete_guild_emoji","text":"delete_guild_emoji(rl::RateLimiter, guild_id::Snowflake, emoji_id::Snowflake; token::String, reason=nothing)\n\nDelete a custom emoji from a guild.\n\nUse this when a bot needs to remove custom emojis, such as for emoji cleanup or management systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nemoji_id::Snowflake — The ID of the emoji to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the emoji or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_application_emojis","page":"API Reference","title":"Accord.list_application_emojis","text":"list_application_emojis(rl::RateLimiter, application_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet all custom emojis for an application.\n\nUse this when a bot needs to list application-owned emojis that can be used across all guilds the bot is in, such as for premium feature emojis.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_application_emoji","page":"API Reference","title":"Accord.get_application_emoji","text":"get_application_emoji(rl::RateLimiter, application_id::Snowflake, emoji_id::Snowflake; token::String) -> Emoji\n\nGet a specific application-owned emoji.\n\nUse this when a bot needs to retrieve details about an application emoji, such as for management or configuration purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nemoji_id::Snowflake — The ID of the emoji.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the emoji or application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_application_emoji","page":"API Reference","title":"Accord.create_application_emoji","text":"create_application_emoji(rl::RateLimiter, application_id::Snowflake; token::String, body::Dict) -> Emoji\n\nCreate a new application-owned emoji.\n\nUse this when a bot needs to upload emojis that can be used across all guilds the bot is in, useful for premium features or consistent branding.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Emoji data (name, image base64).\n\nEmoji Requirements\n\nImage must be at most 256KB in size.\nDimensions must be at least 128x128 pixels.\nSupports PNG, JPEG, or GIF formats.\n\nErrors\n\nHTTP 400 if the image is too large or invalid format.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_application_emoji","page":"API Reference","title":"Accord.modify_application_emoji","text":"modify_application_emoji(rl::RateLimiter, application_id::Snowflake, emoji_id::Snowflake; token::String, body::Dict) -> Emoji\n\nModify an application-owned emoji.\n\nUse this when a bot needs to update application emoji properties such as name.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nemoji_id::Snowflake — The ID of the emoji to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated emoji fields (name).\n\nErrors\n\nHTTP 400 if the name is invalid.\nHTTP 401 if the token is invalid.\nHTTP 404 if the emoji does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_application_emoji","page":"API Reference","title":"Accord.delete_application_emoji","text":"delete_application_emoji(rl::RateLimiter, application_id::Snowflake, emoji_id::Snowflake; token::String)\n\nDelete an application-owned emoji.\n\nUse this when a bot needs to remove application emojis, such as for cleanup or emoji management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nemoji_id::Snowflake — The ID of the emoji to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the emoji does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_sticker","page":"API Reference","title":"Accord.get_sticker","text":"get_sticker(rl::RateLimiter, sticker_id::Snowflake; token::String) -> Sticker\n\nGet a sticker by ID.\n\nUse this when a bot needs to retrieve sticker information, such as for sticker preview commands or content management systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nsticker_id::Snowflake — The ID of the sticker.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if the sticker does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_sticker_packs","page":"API Reference","title":"Accord.list_sticker_packs","text":"list_sticker_packs(rl::RateLimiter; token::String) -> Dict{String, Any}\n\nGet the list of default sticker packs available to all users.\n\nUse this when a bot needs to list standard Discord sticker packs, such as for sticker browsing features or recommendations.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_guild_stickers","page":"API Reference","title":"Accord.list_guild_stickers","text":"list_guild_stickers(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{Sticker}\n\nGet all custom stickers in a guild.\n\nUse this when a bot needs to list guild-specific stickers, such as for sticker management commands or content discovery.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_sticker","page":"API Reference","title":"Accord.get_guild_sticker","text":"get_guild_sticker(rl::RateLimiter, guild_id::Snowflake, sticker_id::Snowflake; token::String) -> Sticker\n\nGet a specific custom sticker from a guild.\n\nUse this when a bot needs to retrieve information about a single guild sticker.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsticker_id::Snowflake — The ID of the sticker.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the sticker or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_sticker","page":"API Reference","title":"Accord.modify_guild_sticker","text":"modify_guild_sticker(rl::RateLimiter, guild_id::Snowflake, sticker_id::Snowflake; token::String, body::Dict, reason=nothing) -> Sticker\n\nModify a custom sticker in a guild.\n\nUse this when a bot needs to update sticker properties such as name, description, or tags.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsticker_id::Snowflake — The ID of the sticker to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated sticker fields (name, description, tags).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 400 if the sticker data is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the sticker or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_sticker","page":"API Reference","title":"Accord.delete_guild_sticker","text":"delete_guild_sticker(rl::RateLimiter, guild_id::Snowflake, sticker_id::Snowflake; token::String, reason=nothing)\n\nDelete a custom sticker from a guild.\n\nUse this when a bot needs to remove custom stickers, such as for sticker cleanup or management systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsticker_id::Snowflake — The ID of the sticker to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the sticker or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_invite","page":"API Reference","title":"Accord.get_invite","text":"get_invite(rl::RateLimiter, invite_code::String; token::String, with_counts::Bool=false, with_expiration::Bool=false, guild_scheduled_event_id=nothing) -> Invite\n\nGet an invite by its code.\n\nUse this when a bot needs to retrieve invite information, such as for validating invite links, checking expiration, or getting guild/channel info.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\ninvite_code::String — The invite code (e.g., \"abc123\").\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_counts::Bool — Include approximate member and presence counts.\nwith_expiration::Bool — Include expiration timestamp.\nguild_scheduled_event_id — Include guild scheduled event information.\n\nErrors\n\nHTTP 404 if the invite does not exist or has expired.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_invite","page":"API Reference","title":"Accord.delete_invite","text":"delete_invite(rl::RateLimiter, invite_code::String; token::String, reason=nothing) -> Invite\n\nDelete/revoke an invite.\n\nUse this when a bot needs to revoke invite links, such as for moderation purposes, invite rotation systems, or security measures.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\ninvite_code::String — The invite code to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS in the invite's channel or MANAGE_GUILD for any invite in the guild.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the invite does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_audit_log","page":"API Reference","title":"Accord.get_guild_audit_log","text":"get_guild_audit_log(rl::RateLimiter, guild_id::Snowflake; token::String,\n    user_id=nothing, action_type=nothing, before=nothing, after=nothing, limit::Int=50) -> AuditLog\n\nGet the audit log for a guild.\n\nUse this when a bot needs to retrieve guild moderation history, such as for audit dashboards, logging systems, or tracking administrative actions.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nuser_id::Snowflake — Filter by user who made the changes.\naction_type::Int — Filter by action type (see AuditLogEventTypes).\nbefore::Snowflake — Filter entries before this entry ID.\nafter::Snowflake — Filter entries after this entry ID.\nlimit::Int — Maximum entries to return (1-100, default 50).\n\nPermissions\n\nRequires VIEW_AUDIT_LOG.\n\nRate Limits\n\nThis endpoint has stricter rate limits than most endpoints due to the sensitivity of audit log data.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_auto_moderation_rules","page":"API Reference","title":"Accord.list_auto_moderation_rules","text":"list_auto_moderation_rules(rl::RateLimiter, guild_id::Snowflake; token::String) -> Vector{AutoModRule}\n\nGet all AutoMod rules for a guild.\n\nUse this when a bot needs to list configured AutoMod rules, such as for moderation dashboards or rule management commands.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_auto_moderation_rule","page":"API Reference","title":"Accord.get_auto_moderation_rule","text":"get_auto_moderation_rule(rl::RateLimiter, guild_id::Snowflake, rule_id::Snowflake; token::String) -> AutoModRule\n\nGet a specific AutoMod rule.\n\nUse this when a bot needs to retrieve details of a single AutoMod rule, such as for editing or displaying rule information.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrule_id::Snowflake — The ID of the rule.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the rule or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_auto_moderation_rule","page":"API Reference","title":"Accord.create_auto_moderation_rule","text":"create_auto_moderation_rule(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> AutoModRule\n\nCreate a new AutoMod rule.\n\nUse this when a bot needs to set up automatic moderation rules, such as for content filtering, keyword detection, or spam prevention.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Rule configuration (name, eventtype, triggertype, actions, etc.).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nRule Limits\n\nMaximum 5 rules per guild for most trigger types.\nMaximum 6 MENTION_SPAM rules per guild.\n\nErrors\n\nHTTP 400 if the rule configuration is invalid.\nHTTP 403 if missing required permissions.\nHTTP 429 if too many rules created.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_auto_moderation_rule","page":"API Reference","title":"Accord.modify_auto_moderation_rule","text":"modify_auto_moderation_rule(rl::RateLimiter, guild_id::Snowflake, rule_id::Snowflake; token::String, body::Dict, reason=nothing) -> AutoModRule\n\nModify an existing AutoMod rule.\n\nUse this when a bot needs to update rule configuration, such as changing trigger conditions, actions, or exempt roles/channels.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrule_id::Snowflake — The ID of the rule to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated rule fields.\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 400 if the rule configuration is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the rule does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_auto_moderation_rule","page":"API Reference","title":"Accord.delete_auto_moderation_rule","text":"delete_auto_moderation_rule(rl::RateLimiter, guild_id::Snowflake, rule_id::Snowflake; token::String, reason=nothing)\n\nDelete an AutoMod rule.\n\nUse this when a bot needs to remove moderation rules, such as for rule management systems or temporary rule disabling.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nrule_id::Snowflake — The ID of the rule to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_GUILD.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the rule or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_scheduled_events","page":"API Reference","title":"Accord.list_scheduled_events","text":"list_scheduled_events(rl::RateLimiter, guild_id::Snowflake; token::String, with_user_count::Bool=false) -> Vector{ScheduledEvent}\n\nGet all scheduled events for a guild.\n\nUse this when a bot needs to list guild events, such as for event calendars, upcoming event notifications, or event management commands.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_user_count::Bool — Include subscriber count for each event.\n\nPermissions\n\nRequires VIEW_CHANNEL to see entity-associated events.\nSome event types may require additional permissions.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_scheduled_event","page":"API Reference","title":"Accord.create_guild_scheduled_event","text":"create_guild_scheduled_event(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> ScheduledEvent\n\nCreate a new scheduled event in a guild.\n\nUse this when a bot needs to create events programmatically, such as for event management systems, integration with external calendars, or automated scheduled activities.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Event data (name, description, scheduledstarttime, entity_type, etc.).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_EVENTS or ADMINISTRATOR.\n\nEvent Types\n\n1 (STAGE_INSTANCE) — Stage channel event\n2 (VOICE) — Voice channel event\n3 (EXTERNAL) — External event (URL-based)\n\nErrors\n\nHTTP 400 if the event data is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_scheduled_event","page":"API Reference","title":"Accord.get_guild_scheduled_event","text":"get_guild_scheduled_event(rl::RateLimiter, guild_id::Snowflake, event_id::Snowflake; token::String, with_user_count::Bool=false) -> ScheduledEvent\n\nGet a specific scheduled event.\n\nUse this when a bot needs to retrieve event details, such as for displaying event information or checking event status.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nevent_id::Snowflake — The ID of the event.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nwith_user_count::Bool — Include subscriber count.\n\nPermissions\n\nRequires VIEW_CHANNEL to see entity-associated events.\n\nErrors\n\nHTTP 404 if the event or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_scheduled_event","page":"API Reference","title":"Accord.modify_guild_scheduled_event","text":"modify_guild_scheduled_event(rl::RateLimiter, guild_id::Snowflake, event_id::Snowflake; token::String, body::Dict, reason=nothing) -> ScheduledEvent\n\nModify a scheduled event.\n\nUse this when a bot needs to update event details, such as changing the time, location, description, or status of an event.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nevent_id::Snowflake — The ID of the event to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated event fields.\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_EVENTS or ADMINISTRATOR.\n\nErrors\n\nHTTP 400 if the event data is invalid.\nHTTP 403 if missing required permissions or not the event creator.\nHTTP 404 if the event or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_scheduled_event","page":"API Reference","title":"Accord.delete_guild_scheduled_event","text":"delete_guild_scheduled_event(rl::RateLimiter, guild_id::Snowflake, event_id::Snowflake; token::String)\n\nDelete a scheduled event.\n\nUse this when a bot needs to cancel or remove events, such as for event management or cleanup systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nevent_id::Snowflake — The ID of the event to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_EVENTS or ADMINISTRATOR.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the event or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_scheduled_event_users","page":"API Reference","title":"Accord.get_guild_scheduled_event_users","text":"get_guild_scheduled_event_users(rl::RateLimiter, guild_id::Snowflake, event_id::Snowflake; token::String, limit::Int=100, with_member::Bool=false) -> Dict{String, Any}\n\nGet users subscribed to a scheduled event.\n\nUse this when a bot needs to list event attendees, such as for attendance tracking, reminder systems, or capacity management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nevent_id::Snowflake — The ID of the event.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nlimit::Int — Maximum users to return (1-100, default 100).\nwith_member::Bool — Include guild member data for each user.\n\nPermissions\n\nRequires MANAGE_EVENTS or ADMINISTRATOR.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the event or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_stage_instance","page":"API Reference","title":"Accord.create_stage_instance","text":"create_stage_instance(rl::RateLimiter; token::String, body::Dict, reason=nothing) -> StageInstance\n\nCreate a new Stage instance.\n\nUse this when a bot needs to start a Stage event programmatically, such as for scheduled stage events or automated broadcast systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Stage instance data (channelid, topic, privacylevel, sendstartnotification).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS and MOVE_MEMBERS in the Stage channel.\n\nPrivacy Levels\n\n1 (PUBLIC) — Stage visible to everyone\n2 (GUILD_ONLY) — Stage visible only to guild members\n\nErrors\n\nHTTP 400 if the stage data is invalid or channel is not a Stage channel.\nHTTP 403 if missing required permissions.\nHTTP 409 if a stage instance already exists for this channel.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_stage_instance","page":"API Reference","title":"Accord.get_stage_instance","text":"get_stage_instance(rl::RateLimiter, channel_id::Snowflake; token::String) -> StageInstance\n\nGet the Stage instance for a Stage channel.\n\nUse this when a bot needs to retrieve information about an active Stage, such as the topic, privacy level, or associated guild scheduled event.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the Stage channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 404 if no stage instance exists for this channel.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_stage_instance","page":"API Reference","title":"Accord.modify_stage_instance","text":"modify_stage_instance(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict, reason=nothing) -> StageInstance\n\nModify a Stage instance.\n\nUse this when a bot needs to update the topic, privacy level, or other properties of an active Stage.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the Stage channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated stage fields (topic, privacy_level).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS and MOVE_MEMBERS in the Stage channel.\n\nErrors\n\nHTTP 400 if the stage data is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if no stage instance exists for this channel.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_stage_instance","page":"API Reference","title":"Accord.delete_stage_instance","text":"delete_stage_instance(rl::RateLimiter, channel_id::Snowflake; token::String, reason=nothing)\n\nDelete a Stage instance (close the Stage).\n\nUse this when a bot needs to end a Stage event, such as after a scheduled event concludes or for moderation purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the Stage channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_CHANNELS and MOVE_MEMBERS in the Stage channel.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if no stage instance exists for this channel.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_default_soundboard_sounds","page":"API Reference","title":"Accord.list_default_soundboard_sounds","text":"list_default_soundboard_sounds(rl::RateLimiter; token::String) -> Vector{SoundboardSound}\n\nGet the list of default soundboard sounds available to all users.\n\nUse this when a bot needs to list Discord's built-in soundboard sounds, such as for sound previews or integration features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_guild_soundboard_sounds","page":"API Reference","title":"Accord.list_guild_soundboard_sounds","text":"list_guild_soundboard_sounds(rl::RateLimiter, guild_id::Snowflake; token::String) -> Dict{String, Any}\n\nGet all custom soundboard sounds for a guild.\n\nUse this when a bot needs to list guild-specific soundboard sounds, such as for sound management or discovery features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_soundboard_sound","page":"API Reference","title":"Accord.get_guild_soundboard_sound","text":"get_guild_soundboard_sound(rl::RateLimiter, guild_id::Snowflake, sound_id::Snowflake; token::String) -> SoundboardSound\n\nGet a specific guild soundboard sound.\n\nUse this when a bot needs to retrieve information about a single soundboard sound, such as for editing or management.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsound_id::Snowflake — The ID of the sound.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the sound or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_soundboard_sound","page":"API Reference","title":"Accord.create_guild_soundboard_sound","text":"create_guild_soundboard_sound(rl::RateLimiter, guild_id::Snowflake; token::String, body::Dict, reason=nothing) -> SoundboardSound\n\nCreate a new soundboard sound in a guild.\n\nUse this when a bot needs to upload custom soundboard sounds programmatically, such as for sound management tools or automated sound creation.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Sound data (name, sound base64, volume, emoji_id/name).\nreason::String — Audit log reason for the creation (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nSound Requirements\n\nMust be MP3 or OGG format.\nMax duration: 5 seconds.\nMax file size: 512KB.\n\nErrors\n\nHTTP 400 if the sound data is invalid or file too large.\nHTTP 403 if missing required permissions.\nHTTP 429 if sound limit reached for the guild.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_soundboard_sound","page":"API Reference","title":"Accord.modify_guild_soundboard_sound","text":"modify_guild_soundboard_sound(rl::RateLimiter, guild_id::Snowflake, sound_id::Snowflake; token::String, body::Dict, reason=nothing) -> SoundboardSound\n\nModify a guild soundboard sound.\n\nUse this when a bot needs to update sound properties such as name, volume, or associated emoji.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsound_id::Snowflake — The ID of the sound to modify.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Updated sound fields (name, volume, emojiid, emojiname).\nreason::String — Audit log reason for the change (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 400 if the sound data is invalid.\nHTTP 403 if missing required permissions.\nHTTP 404 if the sound or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_soundboard_sound","page":"API Reference","title":"Accord.delete_guild_soundboard_sound","text":"delete_guild_soundboard_sound(rl::RateLimiter, guild_id::Snowflake, sound_id::Snowflake; token::String, reason=nothing)\n\nDelete a guild soundboard sound.\n\nUse this when a bot needs to remove soundboard sounds, such as for sound management or cleanup systems.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nguild_id::Snowflake — The ID of the guild.\nsound_id::Snowflake — The ID of the sound to delete.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nreason::String — Audit log reason for the deletion (optional).\n\nPermissions\n\nRequires MANAGE_GUILD_EXPRESSIONS.\n\nErrors\n\nHTTP 403 if missing required permissions.\nHTTP 404 if the sound or guild does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.send_soundboard_sound","page":"API Reference","title":"Accord.send_soundboard_sound","text":"send_soundboard_sound(rl::RateLimiter, channel_id::Snowflake; token::String, body::Dict)\n\nSend a soundboard sound to a voice channel.\n\nUse this when a bot needs to trigger a soundboard sound in a voice channel, such as for automated announcements or interactive voice features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\nchannel_id::Snowflake — The ID of the voice channel.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Contains sound_id of the sound to play.\n\nPermissions\n\nRequires SEND_MESSAGES and the bot must be connected to the voice channel.\n\nErrors\n\nHTTP 400 if the sound ID is invalid.\nHTTP 403 if missing required permissions or not in the voice channel.\nHTTP 404 if the channel or sound does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_voice_regions","page":"API Reference","title":"Accord.list_voice_regions","text":"list_voice_regions(rl::RateLimiter; token::String) -> Vector{VoiceRegion}\n\nGet all available voice regions.\n\nUse this when a bot needs to list voice regions for server configuration, voice channel setup, or region selection features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nNote\n\nThis returns the global list of voice regions. Some regions may be VIP-only or deprecated. Use get_guild_voice_regions for guild-specific regions.\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_skus","page":"API Reference","title":"Accord.list_skus","text":"list_skus(rl::RateLimiter, application_id::Snowflake; token::String) -> Vector{SKU}\n\nGet all SKUs (Stock Keeping Units) for an application.\n\nUse this when a bot needs to list available premium products or subscription plans offered by the application, such as for store displays or upgrade flows.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nSKU Types\n\n2 (DURABLE) — One-time purchase\n3 (CONSUMABLE) — Consumable purchase\n5 (SUBSCRIPTION) — Subscription\n6 (SUBSCRIPTION_GROUP) — Subscription group\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.list_entitlements","page":"API Reference","title":"Accord.list_entitlements","text":"list_entitlements(rl::RateLimiter, application_id::Snowflake; token::String,\n    user_id=nothing, sku_ids=nothing, before=nothing, after=nothing, limit::Int=100,\n    guild_id=nothing, exclude_ended::Bool=false, exclude_deleted::Bool=true) -> Vector{Entitlement}\n\nGet all entitlements for an application.\n\nUse this when a bot needs to list user purchases and subscriptions, such as for checking premium status, managing subscriptions, or customer support.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nuser_id::Snowflake — Filter by user ID.\nsku_ids::Vector{Snowflake} — Filter by specific SKU IDs.\nbefore::Snowflake — Get entitlements before this ID.\nafter::Snowflake — Get entitlements after this ID.\nlimit::Int — Maximum entitlements to return (1-100, default 100).\nguild_id::Snowflake — Filter by guild ID.\nexclude_ended::Bool — Exclude ended entitlements.\nexclude_deleted::Bool — Exclude deleted entitlements.\n\nEntitlement Types\n\n1 — Application subscription\n2 — Application entitlement\n3 — Application gift\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_test_entitlement","page":"API Reference","title":"Accord.create_test_entitlement","text":"create_test_entitlement(rl::RateLimiter, application_id::Snowflake; token::String, body::Dict) -> Entitlement\n\nCreate a test entitlement for development purposes.\n\nUse this when developing premium features and testing entitlement checking without making actual purchases. Only works in development mode.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Test entitlement data (skuid, userid, guild_id, etc.).\n\nNote\n\nTest entitlements are only available in development mode and do not appear in production or billing systems.\n\nErrors\n\nHTTP 400 if the request data is invalid.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_test_entitlement","page":"API Reference","title":"Accord.delete_test_entitlement","text":"delete_test_entitlement(rl::RateLimiter, application_id::Snowflake, entitlement_id::Snowflake; token::String)\n\nDelete a test entitlement.\n\nUse this when cleaning up test data or resetting test scenarios during development.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nentitlement_id::Snowflake — The ID of the test entitlement.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the entitlement does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.consume_entitlement","page":"API Reference","title":"Accord.consume_entitlement","text":"consume_entitlement(rl::RateLimiter, application_id::Snowflake, entitlement_id::Snowflake; token::String)\n\nConsume an entitlement.\n\nUse this when a bot needs to mark an entitlement as consumed, such as for consumable purchases or one-time use premium features.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nentitlement_id::Snowflake — The ID of the entitlement to consume.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the entitlement does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_entitlement","page":"API Reference","title":"Accord.get_entitlement","text":"get_entitlement(rl::RateLimiter, application_id::Snowflake, entitlement_id::Snowflake; token::String) -> Entitlement\n\nGet a specific entitlement.\n\nUse this when a bot needs to retrieve details about a single entitlement, such as for verification or customer support purposes.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\nentitlement_id::Snowflake — The ID of the entitlement.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the entitlement does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_guild_templates","page":"API Reference","title":"Accord.get_guild_templates","text":"Use this to retrieve all guild templates available for a specific server.\n\nGet all templates for a guild.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_template","page":"API Reference","title":"Accord.create_guild_template","text":"Use this to create a new template from the current state of a guild.\n\nCreate a guild template.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.sync_guild_template","page":"API Reference","title":"Accord.sync_guild_template","text":"Use this to update a template to match the current state of the guild.\n\nSync the template to the guild's current state.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_guild_template","page":"API Reference","title":"Accord.modify_guild_template","text":"Use this to change the name or description of an existing guild template.\n\nModify a guild template's metadata.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.delete_guild_template","page":"API Reference","title":"Accord.delete_guild_template","text":"Use this to remove a guild template permanently.\n\nDelete a guild template.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.create_guild_from_template","page":"API Reference","title":"Accord.create_guild_from_template","text":"Use this to create a new server using an existing template as a starting point.\n\nCreate a new guild from a template.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_current_application","page":"API Reference","title":"Accord.get_current_application","text":"get_current_application(rl::RateLimiter; token::String) -> Dict{String, Any}\n\nGet the bot's own application information.\n\nUse this when a bot needs to retrieve its application details, such as name, description, icon, public flags, and interaction endpoint URL. This is useful for verifying configuration or displaying application information.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nErrors\n\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modify_current_application","page":"API Reference","title":"Accord.modify_current_application","text":"modify_current_application(rl::RateLimiter; token::String, body::Dict) -> Dict{String, Any}\n\nModify the bot's own application settings.\n\nUse this when a bot needs to update its application configuration, such as description, interaction endpoint URL, flags, or tags. Changes affect how the application appears to users.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Dict — Application fields to update (description, icon, flags, etc.).\n\nUpdatable Fields\n\ncustom_install_url — Custom authorization URL\ndescription — Application description\nicon — Base64-encoded icon\ncover_image — Base64-encoded cover image\ninteractions_endpoint_url — URL for receiving interactions\nflags — Public flags (GATEWAYPRESENCELIMITED, etc.)\ntags — Array of tags describing the app\n\nErrors\n\nHTTP 400 if any field is invalid.\nHTTP 401 if the token is invalid.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_application_role_connection_metadata_records","page":"API Reference","title":"Accord.get_application_role_connection_metadata_records","text":"get_application_role_connection_metadata_records(rl::RateLimiter, application_id::Snowflake; token::String) -> Vector{Dict{String, Any}}\n\nGet the role connection metadata records for an application.\n\nUse this when a bot needs to retrieve the configuration for Linked Roles, which allow users to obtain roles based on external platform data.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\n\nMetadata Types\n\nINTEGER_LESS_THAN_OR_EQUAL — Integer ≤ comparison\nINTEGER_GREATER_THAN_OR_EQUAL — Integer ≥ comparison\nINTEGER_EQUAL — Integer = comparison\nINTEGER_NOT_EQUAL — Integer ≠ comparison\nDATETIME_LESS_THAN_OR_EQUAL — Unix timestamp ≤ comparison\nDATETIME_GREATER_THAN_OR_EQUAL — Unix timestamp ≥ comparison\nBOOLEAN_EQUAL — Boolean = comparison\nBOOLEAN_NOT_EQUAL — Boolean ≠ comparison\n\nErrors\n\nHTTP 401 if the token is invalid.\nHTTP 404 if the application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.update_application_role_connection_metadata_records","page":"API Reference","title":"Accord.update_application_role_connection_metadata_records","text":"update_application_role_connection_metadata_records(rl::RateLimiter, application_id::Snowflake; token::String, body::Vector) -> Vector{Dict{String, Any}}\n\nUpdate the role connection metadata records for an application.\n\nUse this when a bot needs to configure Linked Role requirements, defining what external data can be used to grant roles to users.\n\nArguments\n\nrl::RateLimiter — The rate limiter instance for request throttling.\napplication_id::Snowflake — The ID of the application.\n\nKeyword Arguments\n\ntoken::String — Bot authentication token.\nbody::Vector — Array of metadata record definitions.\n\nRecord Fields\n\ntype — The type of metadata value (INTEGER, BOOLEAN, DATETIME)\nkey — Unique key for this metadata field\nname — Display name for the metadata field\nname_localizations — Localized names (optional)\ndescription — Description of the field\ndescription_localizations — Localized descriptions (optional)\n\nErrors\n\nHTTP 400 if the metadata configuration is invalid.\nHTTP 401 if the token is invalid.\nHTTP 404 if the application does not exist.\n\nDiscord docs\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.InteractionContext","page":"API Reference","title":"Accord.InteractionContext","text":"InteractionContext\n\nUse this in your slash command handlers to access interaction data and send responses.\n\nWraps an Interaction with convenience methods for responding. Holds a reference to the Client.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.CommandTree","page":"API Reference","title":"Accord.CommandTree","text":"CommandTree\n\nOrganizes and routes slash commands, components, and modal handlers. The client.command_tree field holds the instance used by the bot.\n\nFields\n\ncommands::Dict{String, CommandDefinition}: Map of command names to definitions.\ncomponent_handlers::Dict{String, Function}: Map of custom_ids to component handlers.\nmodal_handlers::Dict{String, Function}: Map of custom_ids to modal handlers.\nautocomplete_handlers::Dict{String, Function}: Map of command names to autocomplete handlers.\n\nSee register_command!, sync_commands!.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.sync_commands!","page":"API Reference","title":"Accord.sync_commands!","text":"sync_commands!(client, tree::CommandTree; guild_id=nothing)\n\nUpload registered commands to Discord.\n\nUse this to update the command list visible to users. Global commands can take up to 1 hour to propagate, while guild commands are instant.\n\nArguments\n\nclient: The Client instance.\ntree::CommandTree: The command tree containing commands to sync.\n\nKeyword Arguments\n\nguild_id::Optional{Snowflake}: If provided, only sync commands for this specific guild. If omitted, syncs global commands AND all guild-specific commands registered in the tree.\n\nExample\n\non(client, ReadyEvent) do c, event\n    sync_commands!(c, c.command_tree)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.register_command!","page":"API Reference","title":"Accord.register_command!","text":"register_command!(tree::CommandTree, name::String, description::String, handler::Function; type=1, options=[], guild_id=missing, checks=[])\n\nRegister a new application command (slash command).\n\nUse this to define a command that users can invoke via /name. The handler function should accept a single argument: the InteractionContext.\n\nArguments\n\ntree::CommandTree: The command tree to register into (usually client.command_tree).\nname::String: The command name (lowercase, no spaces).\ndescription::String: Help text shown to the user.\nhandler::Function: Function called when command is invoked.\n\nKeyword Arguments\n\ntype::Int: Command type (default: 1 for Chat Input). See ApplicationCommandTypes.\noptions::Vector: List of arguments/parameters for the command.\nguild_id::Optional{Snowflake}: If provided, registers as a guild-specific command (faster updates) instead of global.\nchecks::Vector{Function}: List of functions ctx -> Bool that must return true for the command to run.\n\nExample\n\nregister_command!(client.command_tree, \"ping\", \"Checks latency\", ctx -> begin\n    reply(ctx, \"Pong!\")\nend)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.register_component!","page":"API Reference","title":"Accord.register_component!","text":"register_component!(tree::CommandTree, custom_id::String, handler::Function)\n\nRegister a handler for a Message Component (button or select menu).\n\nUse this to handle interactions from buttons or dropdowns. The custom_id can be an exact match or a prefix (if no exact match is found).\n\nArguments\n\ntree::CommandTree: The command tree.\ncustom_id::String: The identifier string assigned to the component.\nhandler::Function: Function ctx -> Any called when the component is used.\n\nExample\n\n# Register a button handler\nregister_component!(client.command_tree, \"click_one\", ctx -> begin\n    reply(ctx, \"Button clicked!\")\nend)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.register_modal!","page":"API Reference","title":"Accord.register_modal!","text":"register_modal!(tree::CommandTree, custom_id::String, handler::Function)\n\nRegister a handler for a Modal submission.\n\nUse this to process form data submitted by users via Modals.\n\nArguments\n\ntree::CommandTree: The command tree.\ncustom_id::String: The identifier string assigned to the modal.\nhandler::Function: Function ctx -> Any called when the modal is submitted.\n\nExample\n\nregister_modal!(client.command_tree, \"feedback_form\", ctx -> begin\n    input = ctx.interaction.data.components[1].components[1].value\n    reply(ctx, \"Received: $input\")\nend)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.register_autocomplete!","page":"API Reference","title":"Accord.register_autocomplete!","text":"register_autocomplete!(tree::CommandTree, command_name::String, handler::Function)\n\nRegister an autocomplete handler for a slash command option.\n\nUse this to provide dynamic choices as the user types an argument.\n\nArguments\n\ntree::CommandTree: The command tree.\ncommand_name::String: The name of the command to attach autocomplete to.\nhandler::Function: Function ctx -> Any called on autocomplete interaction.\n\nExample\n\nregister_autocomplete!(client.command_tree, \"search\", ctx -> begin\n    # ... logic to return choices ...\nend)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.dispatch_interaction!","page":"API Reference","title":"Accord.dispatch_interaction!","text":"dispatch_interaction!(tree::CommandTree, client, interaction::Interaction)\n\nRoute an incoming interaction to the appropriate handler.\n\nInternal function called by the InteractionCreate event handler. It matches the interaction type and ID to a registered handler in the tree.\n\nArguments\n\ntree::CommandTree: The command tree.\nclient: The Client instance.\ninteraction::Interaction: The interaction object received from the gateway.\n\nReturns\n\nThe result of the handler function, or nothing if no handler was found.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.@slash_command","page":"API Reference","title":"Accord.@slash_command","text":"@slash_command client [guild_id] name description [options] handler\n\nUse this macro to define slash commands that users can invoke with \"/command\".\n\nRegister a slash command with the client's command tree.\n\nExample\n\n@slash_command client \"greet\" \"Say hello\" function(ctx)\n    respond(ctx; content=\"Hello!\")\nend\n\n@slash_command client \"double\" \"Double a number\" [\n    @option Integer \"number\" \"Number to double\" required=true\n] function(ctx)\n    n = get_option(ctx, \"number\", 0)\n    respond(ctx; content=\"Result: $(n * 2)\")\nend\n\n# Guild-specific command:\n@slash_command client :guild_id \"info\" \"Server info\" function(ctx)\n    respond(ctx; content=\"Guild command!\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@user_command","page":"API Reference","title":"Accord.@user_command","text":"@user_command client [guild_id] name handler\n\nUse this macro to add right-click context menu commands on users.\n\nRegister a User Context Menu command (right-click on a user). Context menu commands have no description or options.\n\nExample\n\n@user_command client \"User Info\" function(ctx)\n    user = target(ctx)\n    respond(ctx; content=\"User: $(user.username)\")\nend\n\n# Guild-specific:\n@user_command client guild_id \"Warn User\" function(ctx)\n    user = target(ctx)\n    respond(ctx; content=\"Warned $(user.username)\", ephemeral=true)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@message_command","page":"API Reference","title":"Accord.@message_command","text":"@message_command client [guild_id] name handler\n\nUse this macro to add right-click context menu commands on messages.\n\nRegister a Message Context Menu command (right-click on a message). Context menu commands have no description or options.\n\nExample\n\n@message_command client \"Bookmark\" function(ctx)\n    msg = target(ctx)\n    respond(ctx; content=\"Bookmarked message $(msg.id)\", ephemeral=true)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@button_handler","page":"API Reference","title":"Accord.@button_handler","text":"@button_handler client custom_id handler\n\nUse this macro to handle clicks on buttons with a specific custom_id.\n\nRegister a button click handler.\n\nExample\n\n@button_handler client \"my_button\" function(ctx)\n    respond(ctx; content=\"Button clicked!\", ephemeral=true)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@select_handler","page":"API Reference","title":"Accord.@select_handler","text":"@select_handler client custom_id handler\n\nUse this macro to handle selections from dropdown menus.\n\nRegister a select menu handler.\n\nExample\n\n@select_handler client \"color_select\" function(ctx)\n    values = selected_values(ctx)\n    respond(ctx; content=\"You selected: $(join(values, \", \"))\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@modal_handler","page":"API Reference","title":"Accord.@modal_handler","text":"@modal_handler client custom_id handler\n\nUse this macro to handle form submissions from modal dialogs.\n\nRegister a modal submission handler.\n\nExample\n\n@modal_handler client \"feedback_form\" function(ctx)\n    values = modal_values(ctx)\n    respond(ctx; content=\"Thanks for your feedback: $(values[\"feedback\"])\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@autocomplete","page":"API Reference","title":"Accord.@autocomplete","text":"@autocomplete client command_name handler\n\nUse this macro to provide dynamic autocomplete suggestions as users type command options.\n\nRegister an autocomplete handler for a slash command.\n\nExample\n\n@autocomplete client \"search\" function(ctx)\n    query = get_option(ctx, \"query\", \"\")\n    choices = [Dict(\"name\" => r, \"value\" => r) for r in search_results(query)]\n    body = Dict(\"type\" => InteractionCallbackTypes.APPLICATION_COMMAND_AUTOCOMPLETE_RESULT,\n                \"data\" => Dict(\"choices\" => choices))\n    create_interaction_response(ctx.client.ratelimiter, ctx.interaction.id, ctx.interaction.token;\n        token=ctx.client.token, body)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@check","page":"API Reference","title":"Accord.@check","text":"@check check_function\n\nUse this macro to add permission checks or guards before a command executes.\n\nAdd a pre-execution check (guard) to the next @slash_command, @user_command, or @message_command. Checks are stacked — multiple @check macros accumulate and are all drained when a command macro is invoked.\n\nCheck functions receive an InteractionContext and return true (pass) or false (deny). If a check fails, the command handler is never called and a default \"permission denied\" ephemeral message is sent.\n\nBuilt-in checks\n\nhas_permissions(perms...) — require specific permissions\nis_owner() — require guild owner\nis_in_guild() — require guild context (not DMs)\ncooldown(seconds; per=:user) — rate-limit per user/guild/channel/global\n\nExample\n\n@check has_permissions(:MANAGE_GUILD)\n@check is_owner()\n@slash_command client \"nuke\" \"Owner-only danger command\" function(ctx)\n    respond(ctx; content=\"Boom!\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@option","page":"API Reference","title":"Accord.@option","text":"@option Type name description [kwargs...]\n\nUse this macro to define command options with types and validation rules.\n\nCreate a command option dict using a concise syntax. Type is one of: String, Integer, Boolean, User, Channel, Role, Mentionable, Number, or Attachment.\n\nExamples\n\n@option String \"query\" \"Search query\" required=true\n@option Integer \"count\" \"How many\" required=true min_value=1 max_value=25\n@option Channel \"target\" \"Target channel\"\n\n# Use inside @slash_command:\n@slash_command client \"search\" \"Search for items\" [\n    @option String \"query\" \"Search query\" required=true\n    @option Integer \"limit\" \"Max results\" min_value=1 max_value=25\n] function(ctx)\n    q = get_option(ctx, \"query\", \"\")\n    respond(ctx; content=\"Searching for: $q\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.@on_message","page":"API Reference","title":"Accord.@on_message","text":"@on_message client handler\n\nUse this macro to easily register a handler for incoming text messages.\n\nRegister a MessageCreate handler that automatically skips bot messages and messages with missing author or content.\n\nThe handler receives (client, message) — the Message object directly.\n\nExample\n\n@on_message client (c, msg) -> begin\n    msg.content == \"!ping\" && reply(c, msg; content=\"Pong!\")\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/#Accord.respond","page":"API Reference","title":"Accord.respond","text":"respond(ctx; content=\"\", embeds=[], components=[], ephemeral=false, tts=false, files=nothing)\n\nUse this to send an immediate response to a slash command or component interaction.\n\nSend an interaction response. Automatically chooses between creating a new response or editing a deferred one.\n\nMust be called within 3 seconds of receiving the interaction, unless defer was called.\n\nExample\n\n@slash_command client \"hello\" \"Say hello\" function(ctx)\n    respond(ctx; content=\"Hello, world!\", ephemeral=true)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.defer","page":"API Reference","title":"Accord.defer","text":"defer(ctx; ephemeral=false)\n\nUse this when you need more than 3 seconds to process a command before responding.\n\nAcknowledge the interaction and defer the response (shows a \"thinking...\" indicator). This gives you 15 minutes to call respond or edit_response.\n\nExample\n\n@slash_command client \"slow\" \"Slow command\" function(ctx)\n    defer(ctx)\n    sleep(5)\n    respond(ctx; content=\"Done!\")\nend\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.followup","page":"API Reference","title":"Accord.followup","text":"followup(ctx; content=\"\", embeds=[], components=[], ephemeral=false, files=nothing)\n\nUse this to send additional messages after the initial response to an interaction.\n\nSend a followup message to an interaction after the initial response.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.edit_response","page":"API Reference","title":"Accord.edit_response","text":"edit_response(ctx; content=nothing, embeds=nothing, components=nothing, files=nothing)\n\nUse this to modify your bot's response after it has already been sent.\n\nEdit the original interaction response.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.show_modal","page":"API Reference","title":"Accord.show_modal","text":"show_modal(ctx; title::String, custom_id::String, components::Vector)\n\nUse this to display a popup form for users to input data.\n\nShow a modal dialog to the user.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_options","page":"API Reference","title":"Accord.get_options","text":"get_options(ctx::InteractionContext) -> Dict{String, Any}\n\nUse this to retrieve all command options that the user provided when invoking a slash command.\n\nGet all interaction data options as a dictionary mapping option names to values.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.get_option","page":"API Reference","title":"Accord.get_option","text":"get_option(ctx, name, default=nothing)\n\nUse this to retrieve a specific command option value by its name.\n\nGet a specific option value by name from the interaction data.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.custom_id","page":"API Reference","title":"Accord.custom_id","text":"custom_id(ctx) -> String\n\nUse this to identify which button, select menu, or modal was interacted with.\n\nGet the custom_id for component interactions (buttons, selects) or modal submissions.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.selected_values","page":"API Reference","title":"Accord.selected_values","text":"selected_values(ctx) -> Vector{String}\n\nUse this to retrieve the values selected by the user in a select menu component.\n\nGet the selected values for a select menu interaction.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.modal_values","page":"API Reference","title":"Accord.modal_values","text":"modal_values(ctx) -> Dict{String, String}\n\nUse this to retrieve the values entered by the user in a modal form submission.\n\nGet modal component values as a dictionary mapping custom_id to the input value.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.target","page":"API Reference","title":"Accord.target","text":"target(ctx::InteractionContext)\n\nUse this to get the user or message that was right-clicked in a context menu command.\n\nGet the target of a context menu interaction (User or Message command). Returns the resolved User or Message object, or nothing if unavailable.\n\nFor User commands (ApplicationCommandTypes.USER), returns a User. For Message commands (ApplicationCommandTypes.MESSAGE), returns a Message.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.run_checks","page":"API Reference","title":"Accord.run_checks","text":"run_checks(checks::Vector{Function}, ctx::InteractionContext) -> Bool\n\nUse this internal function to execute all permission checks before running a command handler.\n\nRun all check functions against a context. Returns true if all pass. If a check fails and the interaction hasn't been responded to, sends a default ephemeral error message.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.drain_pending_checks!","page":"API Reference","title":"Accord.drain_pending_checks!","text":"drain_pending_checks!() -> Vector{Function}\n\nUse this internal function to retrieve and clear accumulated permission checks.\n\nDrain all pending checks accumulated by @check macros. Called internally by @slash_command.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.VoiceClient","page":"API Reference","title":"Accord.VoiceClient","text":"VoiceClient\n\nUse this to connect your bot to voice channels and play audio.\n\nManages a voice connection to a Discord voice channel. Handles the full connection flow: gateway → voice WS → UDP → audio.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.connect!","page":"API Reference","title":"Accord.connect!","text":"connect!(vc::VoiceClient) -> VoiceClient\n\nUse this to establish a connection to a voice channel before playing audio.\n\nConnect to the voice channel. This performs the full handshake:\n\nSend VOICESTATEUPDATE to gateway\nWait for VOICESTATEUPDATE and VOICESERVERUPDATE events\nConnect to voice WebSocket\nPerform IP discovery\nSelect protocol and establish session\n\nExample\n\nvc = VoiceClient(client, guild_id, channel_id)\nconnect!(vc)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.disconnect!","page":"API Reference","title":"Accord.disconnect!","text":"disconnect!(vc::VoiceClient)\n\nUse this to leave a voice channel and clean up resources.\n\nDisconnect from the voice channel.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.update_voice_state","page":"API Reference","title":"Accord.update_voice_state","text":"update_voice_state(client, guild_id; channel_id=nothing, self_mute=false, self_deaf=false)\n\nUse this to make your bot join, leave, or move between voice channels.\n\nSend a gateway command to update voice state (join/leave/move voice channels).\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.AudioPlayer","page":"API Reference","title":"Accord.AudioPlayer","text":"AudioPlayer\n\nUse this to manage audio playback in voice channels including play, pause, and stop operations.\n\nControls playback of audio to a voice connection.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.play!","page":"API Reference","title":"Accord.play!","text":"play!(player, source, send_fn)\n\nUse this to begin playing audio from a source through a voice connection.\n\nStart playing an audio source. send_fn(opus_data) is called for each encoded frame.\n\n\n\n\n\nplay!(vc::VoiceClient, source::AbstractAudioSource)\n\nUse this to start playing audio in a connected voice channel.\n\nPlay audio from the given source.\n\nExample\n\nsource = FFmpegSource(\"music.mp3\")\nplay!(vc, source)\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.stop!","page":"API Reference","title":"Accord.stop!","text":"Use this to immediately stop audio playback and clean up the source.\n\nStop playback.\n\n\n\n\n\nstop!(vc::VoiceClient)\n\nUse this to stop playing audio in a voice channel.\n\nStop audio playback.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.pause!","page":"API Reference","title":"Accord.pause!","text":"Use this to temporarily pause audio playback without releasing resources.\n\nPause playback.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.resume!","page":"API Reference","title":"Accord.resume!","text":"Use this to continue playing audio after a pause.\n\nResume playback.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.is_playing","page":"API Reference","title":"Accord.is_playing","text":"Use this to determine whether audio is currently being played.\n\nCheck if the player is currently playing.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.PCMSource","page":"API Reference","title":"Accord.PCMSource","text":"PCMSource\n\nUse this to play raw PCM audio data through the voice connection.\n\nAudio source from raw PCM Int16 data (48kHz, stereo).\n\nExample\n\npcm_data = zeros(Int16, 48000 * 2 * 5)  # 5 seconds of silence\nsource = PCMSource(pcm_data)\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.FileSource","page":"API Reference","title":"Accord.FileSource","text":"FileSource\n\nUse this to play audio from raw PCM files on disk.\n\nAudio source from a raw PCM file (48kHz, 16-bit signed LE, stereo).\n\nExample\n\nsource = FileSource(\"audio.raw\")\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.FFmpegSource","page":"API Reference","title":"Accord.FFmpegSource","text":"FFmpegSource\n\nUse this to play audio files in any format supported by FFmpeg.\n\nAudio source that uses FFmpeg to decode any audio format to PCM. Requires ffmpeg to be available in PATH.\n\nExample\n\nsource = FFmpegSource(\"song.mp3\")\nsource_low_vol = FFmpegSource(\"song.mp3\"; volume=0.5)\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SilenceSource","page":"API Reference","title":"Accord.SilenceSource","text":"SilenceSource\n\nUse this to send silent frames and maintain the voice connection without playing audio.\n\nGenerates silence frames. Useful for keeping the voice connection alive.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.OpusEncoder","page":"API Reference","title":"Accord.OpusEncoder","text":"Use this to encode PCM audio to Opus format for voice transmission.\n\nOpus encoder handle.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.OpusDecoder","page":"API Reference","title":"Accord.OpusDecoder","text":"Use this to decode Opus audio back to PCM format.\n\nOpus decoder handle.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.opus_encode","page":"API Reference","title":"Accord.opus_encode","text":"opus_encode(encoder, pcm) -> Vector{UInt8}\n\nUse this to compress PCM audio into Opus format for efficient voice transmission.\n\nEncode PCM audio (Int16 samples) to Opus. pcm should contain frame_size * channels samples.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.opus_decode","page":"API Reference","title":"Accord.opus_decode","text":"opus_decode(decoder, data, frame_size) -> Vector{Int16}\n\nUse this to decompress Opus audio back into PCM format for playback or processing.\n\nDecode Opus data to PCM audio (Int16 samples).\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.set_bitrate!","page":"API Reference","title":"Accord.set_bitrate!","text":"Use this to adjust the audio quality and bandwidth usage of the Opus encoder.\n\nSet the bitrate for an Opus encoder.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.set_signal!","page":"API Reference","title":"Accord.set_signal!","text":"Use this to optimize the encoder for either music or voice content.\n\nSet the signal type for an Opus encoder (OPUSSIGNALMUSIC or OPUSSIGNALVOICE).\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.init_sodium","page":"API Reference","title":"Accord.init_sodium","text":"Initialize libsodium (must be called once).\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.random_nonce","page":"API Reference","title":"Accord.random_nonce","text":"Generate a random nonce of the specified length.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.Snowflake","page":"API Reference","title":"Accord.Snowflake","text":"Snowflake\n\nUse this type to work with Discord's unique identifier format for all Discord objects.\n\nDiscord Snowflake ID type — a UInt64 wrapper with timestamp extraction. Discord sends snowflakes as JSON strings; we parse them to UInt64.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.timestamp","page":"API Reference","title":"Accord.timestamp","text":"Use this to find out when a Discord object was created based on its ID.\n\nExtract the creation timestamp from a Snowflake.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.worker_id","page":"API Reference","title":"Accord.worker_id","text":"Use this for debugging or analyzing how Discord distributes ID generation across workers.\n\nExtract the internal worker ID.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.process_id","page":"API Reference","title":"Accord.process_id","text":"Use this for debugging or analyzing how Discord distributes ID generation across processes.\n\nExtract the internal process ID.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.increment","page":"API Reference","title":"Accord.increment","text":"Use this for debugging or understanding the sequence of IDs generated within the same millisecond.\n\nExtract the increment.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.User","page":"API Reference","title":"Accord.User","text":"User\n\nUse this struct to access information about any Discord user, including bot users and guild members.\n\nRepresents a Discord user.\n\nFields\n\nid: The user's snowflake ID.\nusername: The user's username.\ndiscriminator: The user's 4-digit discord-tag (optional).\nglobal_name: The user's display name (optional).\navatar: The user's avatar hash.\nbot: Whether the user is a bot.\nsystem: Whether the user is an Official Discord System user.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Member","page":"API Reference","title":"Accord.Member","text":"Member\n\nA guild member. This struct is received whenever information about a guild member is available, such as in message events, voice state updates, or when fetching guild members.\n\nDiscord docs\n\nFields\n\nuser::Optional{User} — user object for the guild member. Only present if the member was fetched or is the bot itself.\nnick::Optional{String} — guild-specific nickname for the member, if set.\navatar::Optional{String} — member's guild-specific avatar hash, if set.\nroles::Vector{Snowflake} — array of role IDs that the member has.\njoined_at::String — ISO8601 timestamp when the user joined the guild.\npremium_since::Optional{String} — ISO8601 timestamp when the user started boosting the guild, if applicable.\ndeaf::Optional{Bool} — whether the user is deafened in voice channels.\nmute::Optional{Bool} — whether the user is muted in voice channels.\nflags::Int — guild member flags represented as a bit set. See GuildMemberFlags module.\npending::Optional{Bool} — whether the user has not yet passed the guild's Membership Screening requirements.\npermissions::Optional{String} — total permissions of the member in the channel, including overwrites. Returned when in the interaction object.\ncommunication_disabled_until::Optional{String} — ISO8601 timestamp until the user's timeout expires, if applicable. When present, the user cannot interact with the guild.\navatar_decoration_data::Optional{Any} — data for the member's guild avatar decoration.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Role","page":"API Reference","title":"Accord.Role","text":"Role\n\nA role in a guild. Roles are used to group users and grant them permissions. Every guild member has at least the @everyone role.\n\nDiscord docs\n\nFields\n\nid::Snowflake — unique role ID.\nname::String — role name. For the @everyone role, this is the guild name.\ncolor::Int — integer representation of hexadecimal color code.\nhoist::Bool — whether the role is pinned in the user listing.\nicon::Optional{String} — role icon hash. Only present if the role has an icon.\nunicode_emoji::Optional{String} — role unicode emoji. Only present if the role has a unicode emoji.\nposition::Int — position of this role in the role list. Higher values appear first.\npermissions::String — permission bit set as a string. See Permissions bitfield type.\nmanaged::Bool — whether this role is managed by an integration.\nmentionable::Bool — whether this role is mentionable.\ntags::Optional{RoleTags} — tags describing extra attributes of the role. Only present for special roles like boosters or bot roles.\nflags::Int — role flags combined as a bitfield.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.DiscordChannel","page":"API Reference","title":"Accord.DiscordChannel","text":"DiscordChannel\n\nRepresents a guild or DM channel within Discord. This is a central structure that bots interact with constantly when sending messages, managing permissions, or handling events.\n\nDiscord docs\n\nFields\n\nid::Snowflake — unique ID of the channel.\ntype::Int — type of channel. See ChannelTypes module for values.\nguild_id::Optional{Snowflake} — ID of the guild the channel belongs to. May be missing for some channel objects received over gateway guild dispatches.\nposition::Optional{Int} — sorting position of the channel. Only present for guild channels.\npermission_overwrites::Optional{Vector{Overwrite}} — explicit permission overwrites for members and roles. Only present for guild channels.\nname::Optional{String} — name of the channel (1-100 characters). Not present for DM channels.\ntopic::Optional{String} — channel topic (0-1024 characters for GUILD_FORUM and GUILD_MEDIA channels, 0-4096 for all others). Not present for all channel types.\nnsfw::Optional{Bool} — whether the channel is NSFW. Only present for guild channels.\nlast_message_id::Optional{Snowflake} — ID of the last message sent in this channel. May not point to an existing message. Not present for all channel types.\nbitrate::Optional{Int} — bitrate (in bits) of the voice channel. Only for voice channels.\nuser_limit::Optional{Int} — user limit of the voice channel. Only for voice channels.\nrate_limit_per_user::Optional{Int} — amount of seconds a user has to wait before sending another message (0-21600). Not present for all channel types.\nrecipients::Optional{Vector{User}} — recipients of the DM. Only present for DM and group DM channels.\nicon::Optional{String} — icon hash of the group DM. Only present for group DM channels.\nowner_id::Optional{Snowflake} — ID of the creator of the group DM or thread. Present for group DMs and threads.\napplication_id::Optional{Snowflake} — application ID of the group DM creator if bot-created. Present for group DMs.\nmanaged::Optional{Bool} — for group DM channels, whether the channel is managed by an application.\nparent_id::Optional{Snowflake} — ID of the parent category or thread. Present for channel categories, threads, and some child channels.\nlast_pin_timestamp::Optional{String} — ISO8601 timestamp of when the last pinned message was pinned. May be null.\nrtc_region::Optional{String} — voice region ID for the voice channel; automatic when set to nothing. Only for voice channels.\nvideo_quality_mode::Optional{Int} — camera video quality mode of the voice channel. See VideoQualityModes (1 = auto, 2 = full).\nmessage_count::Optional{Int} — approximate count of messages in a thread; stops counting at 50. Only for threads.\nmember_count::Optional{Int} — approximate count of members in a thread; stops counting at 50. Only for threads.\nthread_metadata::Optional{ThreadMetadata} — thread-specific fields. Only for threads.\nmember::Optional{ThreadMember} — thread member object for the current user if they have joined the thread. Only present for threads.\ndefault_auto_archive_duration::Optional{Int} — default duration for newly created threads. Only for text and forum/media channels.\npermissions::Optional{String} — computed permissions for the invoking user in the channel, including overwrites. Only included when part of the resolved set received from an interaction.\nflags::Optional{Int} — channel flags combined as a bitfield. See ChannelFlags module.\ntotal_message_sent::Optional{Int} — number of messages ever sent in a thread. Similar to message_count but won't decrease when messages are deleted. Only for threads.\navailable_tags::Optional{Vector{ForumTag}} — set of tags that can be used in a GUILD_FORUM or GUILD_MEDIA channel. Only for those channel types.\napplied_tags::Optional{Vector{Snowflake}} — IDs of the set of tags applied to a thread in a GUILD_FORUM or GUILD_MEDIA channel. Max 5. Only for threads in those channel types.\ndefault_reaction_emoji::Optional{DefaultReaction} — emoji to show in the add reaction button on a thread in a GUILD_FORUM or GUILD_MEDIA channel. Only for those channel types.\ndefault_thread_rate_limit_per_user::Optional{Int} — initial rate_limit_per_user to enable on newly created threads. Only for forum and text channels.\ndefault_sort_order::Optional{Int} — default sort order type used to order posts in GUILD_FORUM and GUILD_MEDIA channels. See SortOrderTypes module.\ndefault_forum_layout::Optional{Int} — default forum layout view used to display posts in GUILD_FORUM channels. See ForumLayoutTypes module.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Message","page":"API Reference","title":"Accord.Message","text":"Message\n\nUse this struct to work with messages sent in Discord channels, including content, attachments, and reactions.\n\nRepresents a message sent in a channel within Discord.\n\nFields\n\nid: The message ID.\nchannel_id: The channel ID.\nauthor: The user who sent the message (optional).\ncontent: The message text content.\ntimestamp: The time the message was sent.\nattachments: Vector of attachments.\nembeds: Vector of embeds.\nreactions: Vector of reactions.\npinned: Whether the message is pinned.\ntype: The type of message.\nreferenced_message: The message being replied to (if any).\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Embed","page":"API Reference","title":"Accord.Embed","text":"Embed\n\nA rich embed object that can be sent with messages. Embeds provide a structured way to present content with titles, descriptions, images, fields, and more.\n\nDiscord docs\n\nFields\n\ntitle::Optional{String} — title of the embed. Max 256 characters.\ntype::Optional{String} — type of embed (always \"rich\" for webhook embeds).\ndescription::Optional{String} — description of the embed. Max 4096 characters.\nurl::Optional{String} — URL of the embed.\ntimestamp::Optional{String} — ISO8601 timestamp of the embed content.\ncolor::Optional{Int} — color code of the embed as an integer.\nfooter::Optional{EmbedFooter} — footer information.\nimage::Optional{EmbedImage} — image information.\nthumbnail::Optional{EmbedThumbnail} — thumbnail information.\nvideo::Optional{EmbedVideo} — video information.\nprovider::Optional{EmbedProvider} — provider information.\nauthor::Optional{EmbedAuthor} — author information.\nfields::Optional{Vector{EmbedField}} — fields information. Max 25 fields.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Interaction","page":"API Reference","title":"Accord.Interaction","text":"Interaction\n\nAn interaction is the message that your application receives when a user uses an application command or a message component.\n\nDiscord docs\n\nFields\n\nid::Snowflake — unique ID of the interaction.\napplication_id::Snowflake — ID of the application this interaction is for.\ntype::Int — type of interaction. See InteractionTypes module.\ndata::Optional{InteractionData} — command data payload. Only present for application command, message component, and modal submit types.\nguild_id::Optional{Snowflake} — guild that the interaction was sent from. May be missing for some interaction types.\nchannel::Optional{DiscordChannel} — channel that the interaction was sent from. Only present in certain interaction types.\nchannel_id::Optional{Snowflake} — channel that the interaction was sent from. May be missing for some interaction types.\nmember::Optional{Member} — guild member data for the invoking user, including permissions. Only present when invoked in a guild.\nuser::Optional{User} — user object for the invoking user, if invoked in a DM.\ntoken::String — continuation token for responding to the interaction. Valid for 15 minutes.\nversion::Int — read-only property, always 1.\nmessage::Optional{Message} — for components, the message they were attached to. Not present for application command interactions.\napp_permissions::Optional{String} — set of permissions the app or bot has within the channel the interaction was sent from.\nlocale::Optional{String} — selected language of the invoking user. Only present for application command interactions.\nguild_locale::Optional{String} — guild's preferred locale, if invoked in a guild.\nentitlements::Optional{Vector{Any}} — for monetized apps, entitlements the user has.\nauthorizing_integration_owners::Optional{Any} — mapping of installation contexts that the interaction was authorized for to related user or guild IDs.\ncontext::Optional{Int} — context where the interaction was triggered from. See InteractionContextTypes module.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Emoji","page":"API Reference","title":"Accord.Emoji","text":"Emoji\n\nRepresents an emoji, which can be a standard Unicode emoji or a custom guild emoji.\n\nDiscord docs\n\nFields\n\nid::Nullable{Snowflake} — emoji ID. nothing for standard Unicode emojis.\nname::Nullable{String} — emoji name. For custom emojis, this is the custom name. For standard emojis, this may be nothing in reaction objects.\nroles::Optional{Vector{Snowflake}} — roles allowed to use this emoji. Only for custom guild emojis.\nuser::Optional{User} — user that created this emoji. Only for custom guild emojis.\nrequire_colons::Optional{Bool} — whether this emoji must be wrapped in colons. Only for custom guild emojis.\nmanaged::Optional{Bool} — whether this emoji is managed by an integration. Only for custom guild emojis.\nanimated::Optional{Bool} — whether this emoji is animated. Only for custom guild emojis.\navailable::Optional{Bool} — whether this emoji can be used. May be false due to loss of Server Boosts. Only for custom guild emojis.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Reaction","page":"API Reference","title":"Accord.Reaction","text":"Reaction\n\nA reaction to a message. Represents the count and users who reacted with a specific emoji.\n\nDiscord docs\n\nFields\n\ncount::Int — total number of times this emoji has been used to react.\ncount_details::Optional{ReactionCountDetails} — reaction count details for each type (normal/super).\nme::Bool — whether the current user reacted using this emoji.\nme_burst::Bool — whether the current user super-reacted using this emoji.\nemoji::Optional{Emoji} — emoji information.\nburst_colors::Vector{String} — HEX colors used for super reaction.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AutoModRule","page":"API Reference","title":"Accord.AutoModRule","text":"AutoModRule\n\nA rule which defines the trigger and actions for auto moderation.\n\nDiscord docs\n\nFields\n\nid::Snowflake — Unique ID of the rule.\nguild_id::Snowflake — ID of the guild which this rule belongs to.\nname::String — Rule name (1-255 characters).\ncreator_id::Snowflake — User which first created this rule.\nevent_type::Int — Event type indicating in what event context a rule should be checked. See AutoModEventTypes module.\ntrigger_type::Int — Trigger type indicating what type of information to check for. See AutoModTriggerTypes module.\ntrigger_metadata::Optional{AutoModTriggerMetadata} — Additional data used to determine whether a rule should be triggered.\nactions::Vector{AutoModAction} — Actions which will execute when the rule is triggered.\nenabled::Bool — Whether the rule is enabled.\nexempt_roles::Vector{Snowflake} — Role IDs that should not be affected by the rule (Maximum 20).\nexempt_channels::Vector{Snowflake} — Channel IDs that should not be affected by the rule (Maximum 50).\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Guild","page":"API Reference","title":"Accord.Guild","text":"Guild\n\nUse this struct to access information about a Discord server (guild), including channels, roles, and member counts.\n\nRepresents a Discord guild (server).\n\nFields\n\nid: The guild's snowflake ID.\nname: Guild name (2-100 characters, excluding trailing/leading whitespace).\nicon: Icon hash.\nowner_id: ID of the guild owner.\npermissions: Total permissions for the user in the guild (excludes overwrites).\nroles: Roles in the guild.\nemojis: Custom guild emojis.\nfeatures: Enabled guild features.\napproximate_member_count: Approximate number of members in this guild.\napproximate_presence_count: Approximate number of online members in this guild.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Presence","page":"API Reference","title":"Accord.Presence","text":"Presence\n\nA user's presence is their current status and activity. Received via PRESENCE_UPDATE gateway events.\n\nDiscord docs\n\nFields\n\nuser::Any — user whose presence is being updated. May be a partial User object.\nguild_id::Optional{Snowflake} — ID of the guild this presence is for.\nstatus::String — user's current status. One of: online, dnd, idle, invisible, offline.\nactivities::Vector{Activity} — user's current activities.\nclient_status::Optional{ClientStatus} — user's platform-specific status (desktop, mobile, web).\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.Attachment","page":"API Reference","title":"Accord.Attachment","text":"Attachment\n\nA file attached to a message. Received when a user uploads files or when the bot receives messages with attachments.\n\nDiscord docs\n\nFields\n\nid::Snowflake — attachment ID.\nfilename::String — name of the file attached.\ntitle::Optional{String} — title of the file (for audio files).\ndescription::Optional{String} — description for the file (max 1024 characters).\ncontent_type::Optional{String} — MIME type of the content.\nsize::Int — size of the file in bytes.\nurl::String — source URL of the file.\nproxy_url::String — proxied URL of the file.\nheight::Optional{Int} — height of the file (if image).\nwidth::Optional{Int} — width of the file (if image).\nephemeral::Optional{Bool} — whether this attachment is ephemeral. Ephemeral attachments will automatically be removed after a set period of time.\nduration_secs::Optional{Float64} — duration of the audio file (currently for voice messages).\nwaveform::Optional{String} — base64 encoded bytearray representing a sampled waveform (currently for voice messages).\nflags::Optional{Int} — attachment flags combined as a bitfield.\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelTypes","page":"API Reference","title":"Accord.ChannelTypes","text":"ChannelTypes\n\nConstants for the various types of channels in Discord.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.InteractionTypes","page":"API Reference","title":"Accord.InteractionTypes","text":"InteractionTypes\n\nConstants for the various types of interactions in Discord.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.InteractionCallbackTypes","page":"API Reference","title":"Accord.InteractionCallbackTypes","text":"InteractionCallbackTypes\n\nConstants for the various ways to respond to an interaction.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ApplicationCommandTypes","page":"API Reference","title":"Accord.ApplicationCommandTypes","text":"ApplicationCommandTypes\n\nConstants for the various types of application commands.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ApplicationCommandOptionTypes","page":"API Reference","title":"Accord.ApplicationCommandOptionTypes","text":"ApplicationCommandOptionTypes\n\nConstants for the various types of options for application commands.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ComponentTypes","page":"API Reference","title":"Accord.ComponentTypes","text":"ComponentTypes\n\nConstants for the various types of message components.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ButtonStyles","page":"API Reference","title":"Accord.ButtonStyles","text":"ButtonStyles\n\nConstants for the various visual styles of buttons.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.TextInputStyles","page":"API Reference","title":"Accord.TextInputStyles","text":"TextInputStyles\n\nConstants for the various visual styles of text inputs in modals.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ActivityTypes","page":"API Reference","title":"Accord.ActivityTypes","text":"ActivityTypes\n\nConstants for the various types of presence activities.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.MessageTypes","page":"API Reference","title":"Accord.MessageTypes","text":"MessageTypes\n\nConstants for the various types of messages in Discord.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.VerificationLevels","page":"API Reference","title":"Accord.VerificationLevels","text":"VerificationLevels\n\nConstants for the various guild verification levels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.DefaultMessageNotificationLevels","page":"API Reference","title":"Accord.DefaultMessageNotificationLevels","text":"DefaultMessageNotificationLevels\n\nConstants for the various guild default message notification levels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ExplicitContentFilterLevels","page":"API Reference","title":"Accord.ExplicitContentFilterLevels","text":"ExplicitContentFilterLevels\n\nConstants for the various guild explicit content filter levels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.MFALevels","page":"API Reference","title":"Accord.MFALevels","text":"MFALevels\n\nConstants for the various guild multi-factor authentication levels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.NSFWLevels","page":"API Reference","title":"Accord.NSFWLevels","text":"NSFWLevels\n\nConstants for the various guild NSFW levels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.PremiumTiers","page":"API Reference","title":"Accord.PremiumTiers","text":"PremiumTiers\n\nConstants for the various guild premium (Boost) tiers.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.PremiumTypes","page":"API Reference","title":"Accord.PremiumTypes","text":"PremiumTypes\n\nConstants for the various user premium (Nitro) types.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.StatusTypes","page":"API Reference","title":"Accord.StatusTypes","text":"StatusTypes\n\nConstants for the various presence status strings.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.WebhookTypes","page":"API Reference","title":"Accord.WebhookTypes","text":"WebhookTypes\n\nConstants for the various types of webhooks.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.AuditLogEventTypes","page":"API Reference","title":"Accord.AuditLogEventTypes","text":"AuditLogEventTypes\n\nConstants for the various types of events recorded in the audit log.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.AutoModTriggerTypes","page":"API Reference","title":"Accord.AutoModTriggerTypes","text":"AutoModTriggerTypes\n\nConstants for the various types of triggers for auto moderation rules.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.AutoModEventTypes","page":"API Reference","title":"Accord.AutoModEventTypes","text":"AutoModEventTypes\n\nConstants for the various event contexts where auto moderation rules are checked.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.AutoModActionTypes","page":"API Reference","title":"Accord.AutoModActionTypes","text":"AutoModActionTypes\n\nConstants for the various actions that auto moderation rules can take.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.AutoModKeywordPresetTypes","page":"API Reference","title":"Accord.AutoModKeywordPresetTypes","text":"AutoModKeywordPresetTypes\n\nConstants for the various built-in word lists for auto moderation.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.SortOrderTypes","page":"API Reference","title":"Accord.SortOrderTypes","text":"SortOrderTypes\n\nConstants for the various sort orders for forum and media channels.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ForumLayoutTypes","page":"API Reference","title":"Accord.ForumLayoutTypes","text":"ForumLayoutTypes\n\nConstants for the various forum layout views.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.StickerTypes","page":"API Reference","title":"Accord.StickerTypes","text":"StickerTypes\n\nConstants for the various types of stickers.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.StickerFormatTypes","page":"API Reference","title":"Accord.StickerFormatTypes","text":"StickerFormatTypes\n\nConstants for the various formats of stickers.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.InviteTargetTypes","page":"API Reference","title":"Accord.InviteTargetTypes","text":"InviteTargetTypes\n\nConstants for the various types of targets for voice channel invites.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ScheduledEventPrivacyLevels","page":"API Reference","title":"Accord.ScheduledEventPrivacyLevels","text":"ScheduledEventPrivacyLevels\n\nConstants for the various privacy levels of guild scheduled events.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ScheduledEventStatuses","page":"API Reference","title":"Accord.ScheduledEventStatuses","text":"ScheduledEventStatuses\n\nConstants for the various statuses of guild scheduled events.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.ScheduledEventEntityTypes","page":"API Reference","title":"Accord.ScheduledEventEntityTypes","text":"ScheduledEventEntityTypes\n\nConstants for the various types of entities associated with guild scheduled events.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.StageInstancePrivacyLevels","page":"API Reference","title":"Accord.StageInstancePrivacyLevels","text":"StageInstancePrivacyLevels\n\nConstants for the various privacy levels of Stage instances.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.OnboardingModes","page":"API Reference","title":"Accord.OnboardingModes","text":"OnboardingModes\n\nConstants for the various guild onboarding modes.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.SKUTypes","page":"API Reference","title":"Accord.SKUTypes","text":"SKUTypes\n\nConstants for the various types of SKUs.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.EntitlementTypes","page":"API Reference","title":"Accord.EntitlementTypes","text":"EntitlementTypes\n\nConstants for the various types of entitlements.\n\nDiscord docs\n\n\n\n\n\n","category":"module"},{"location":"api/#Accord.Intents","page":"API Reference","title":"Accord.Intents","text":"Intents\n\nGateway intents allow you to subscribe to specific buckets of events sent by Discord. Privileged intents (Members, Presences, MessageContent) must be enabled in the Developer Portal.\n\nDiscord docs\n\nExample\n\n# Combine intents using the | operator\nintents = IntentGuilds | IntentGuildMessages | IntentMessageContent\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.IntentGuilds","page":"API Reference","title":"Accord.IntentGuilds","text":"Enables GUILDCREATE, GUILDUPDATE, GUILDDELETE, GUILDROLE*, CHANNEL, THREAD_, STAGEINSTANCE* events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildMembers","page":"API Reference","title":"Accord.IntentGuildMembers","text":"Enables GUILDMEMBERADD, GUILDMEMBERUPDATE, GUILDMEMBERREMOVE, THREADMEMBERSUPDATE events. Privileged Intent.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildModeration","page":"API Reference","title":"Accord.IntentGuildModeration","text":"Enables GUILDAUDITLOGENTRYCREATE, GUILDBANADD, GUILDBANREMOVE events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildExpressions","page":"API Reference","title":"Accord.IntentGuildExpressions","text":"Enables GUILDEMOJISUPDATE, GUILDSTICKERSUPDATE, GUILDSOUNDBOARDSOUND_* events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildIntegrations","page":"API Reference","title":"Accord.IntentGuildIntegrations","text":"Enables GUILDINTEGRATIONSUPDATE, INTEGRATIONCREATE, INTEGRATIONUPDATE, INTEGRATION_DELETE events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildWebhooks","page":"API Reference","title":"Accord.IntentGuildWebhooks","text":"Enables WEBHOOKS_UPDATE events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildInvites","page":"API Reference","title":"Accord.IntentGuildInvites","text":"Enables INVITECREATE, INVITEDELETE events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildVoiceStates","page":"API Reference","title":"Accord.IntentGuildVoiceStates","text":"Enables VOICESTATEUPDATE events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildPresences","page":"API Reference","title":"Accord.IntentGuildPresences","text":"Enables PRESENCE_UPDATE events. Privileged Intent.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildMessages","page":"API Reference","title":"Accord.IntentGuildMessages","text":"Enables MESSAGECREATE, MESSAGEUPDATE, MESSAGEDELETE, MESSAGEDELETE_BULK events in guilds.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildMessageReactions","page":"API Reference","title":"Accord.IntentGuildMessageReactions","text":"Enables MESSAGEREACTIONADD, MESSAGEREACTIONREMOVE, MESSAGEREACTIONREMOVEALL, MESSAGEREACTIONREMOVEEMOJI events in guilds.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildMessageTyping","page":"API Reference","title":"Accord.IntentGuildMessageTyping","text":"Enables TYPING_START events in guilds.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentDirectMessages","page":"API Reference","title":"Accord.IntentDirectMessages","text":"Enables MESSAGECREATE, MESSAGEUPDATE, MESSAGEDELETE, CHANNELPINS_UPDATE events in DMs.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentDirectMessageReactions","page":"API Reference","title":"Accord.IntentDirectMessageReactions","text":"Enables MESSAGEREACTIONADD, MESSAGEREACTIONREMOVE, MESSAGEREACTIONREMOVEALL, MESSAGEREACTIONREMOVEEMOJI events in DMs.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentDirectMessageTyping","page":"API Reference","title":"Accord.IntentDirectMessageTyping","text":"Enables TYPING_START events in DMs.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentMessageContent","page":"API Reference","title":"Accord.IntentMessageContent","text":"Enables access to message content (content, embeds, attachments, components) in events. Privileged Intent.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildScheduledEvents","page":"API Reference","title":"Accord.IntentGuildScheduledEvents","text":"Enables GUILDSCHEDULEDEVENT_* events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentAutoModerationConfiguration","page":"API Reference","title":"Accord.IntentAutoModerationConfiguration","text":"Enables AUTOMODERATIONRULE_* events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentAutoModerationExecution","page":"API Reference","title":"Accord.IntentAutoModerationExecution","text":"Enables AUTOMODERATIONACTION_EXECUTION events.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentGuildMessagePolls","page":"API Reference","title":"Accord.IntentGuildMessagePolls","text":"Enables MESSAGEPOLLVOTE_* events in guilds.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentDirectMessagePolls","page":"API Reference","title":"Accord.IntentDirectMessagePolls","text":"Enables MESSAGEPOLLVOTE_* events in DMs.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentAllNonPrivileged","page":"API Reference","title":"Accord.IntentAllNonPrivileged","text":"All non-privileged intents combined.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.IntentAll","page":"API Reference","title":"Accord.IntentAll","text":"All intents combined, including privileged ones.\n\n\n\n\n\n","category":"constant"},{"location":"api/#Accord.Permissions","page":"API Reference","title":"Accord.Permissions","text":"Permissions\n\nDiscord permissions are stored as a bitmask. Accord.jl provides constant values for each permission. Use has_flag to check if a set of permissions contains a specific one.\n\nDiscord docs\n\nExample\n\n# Check for a specific permission\nif has_flag(member_perms, PermAdministrator)\n    println(\"User is an admin\")\nend\n\n# Combine permissions\nrequired = PermSendMessages | PermEmbedLinks\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.has_flag","page":"API Reference","title":"Accord.has_flag","text":"Use this to verify if a user has specific permissions or if certain flags are enabled.\n\nCheck if a has all flags in b set.\n\n\n\n\n\n","category":"function"},{"location":"api/#Accord.MessageFlags","page":"API Reference","title":"Accord.MessageFlags","text":"MessageFlags\n\nBitfield representing extra attributes of a message, such as whether it is ephemeral or crossposted.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.UserFlags","page":"API Reference","title":"Accord.UserFlags","text":"UserFlags\n\nBitfield representing public flags on a user's account, such as whether they are a Discord employee or a partner.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SystemChannelFlags","page":"API Reference","title":"Accord.SystemChannelFlags","text":"SystemChannelFlags\n\nBitfield representing which standard system notifications are disabled in a guild's system channel.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.ChannelFlags","page":"API Reference","title":"Accord.ChannelFlags","text":"ChannelFlags\n\nBitfield representing extra attributes of a channel, such as whether it is pinned in a forum.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.GuildMemberFlags","page":"API Reference","title":"Accord.GuildMemberFlags","text":"GuildMemberFlags\n\nBitfield representing attributes of a guild member, such as whether they have completed onboarding.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.RoleFlags","page":"API Reference","title":"Accord.RoleFlags","text":"RoleFlags\n\nBitfield representing attributes of a role, such as whether it is displayed in an onboarding prompt.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.AttachmentFlags","page":"API Reference","title":"Accord.AttachmentFlags","text":"AttachmentFlags\n\nBitfield representing attributes of an attachment, such as whether it is a remix.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"api/#Accord.SKUFlags","page":"API Reference","title":"Accord.SKUFlags","text":"SKUFlags\n\nBitfield representing attributes of a SKU, such as whether it is a user or guild subscription.\n\nDiscord docs\n\n\n\n\n\n","category":"type"},{"location":"cookbook/15-why-julia/#Recipe-15-—-Why-Julia-for-Discord-Bots?","page":"Why Julia?","title":"Recipe 15 — Why Julia for Discord Bots?","text":"Difficulty: Conceptual What you will learn: Why Julia is a compelling alternative to Python for building Discord bots, with honest trade-offs.\n\n","category":"section"},{"location":"cookbook/15-why-julia/#1.-The-Phoenix-Moment","page":"Why Julia?","title":"1. The Phoenix Moment","text":"When the Elixir community built Phoenix, many PHP developers skeptically asked \"why would I switch?\" — then they experienced real concurrency, pattern matching, and fault tolerance. The answer became obvious.\n\nJulia offers a similar leap for Python bot developers: not just incremental improvement, but fundamentally different capabilities.","category":"section"},{"location":"cookbook/15-why-julia/#2.-Performance:-No-GIL,-Real-Parallelism","page":"Why Julia?","title":"2. Performance: No GIL, Real Parallelism","text":"note: True Parallelism Without the GIL\nUnlike Python's Global Interpreter Lock (GIL) which prevents true parallelism, Julia has no GIL. CPU-bound tasks can run on multiple threads simultaneously, making Julia ideal for bots that perform computations, data processing, or ML inference.\n\nPython's Global Interpreter Lock (GIL) means your bot is single-threaded, no matter how many cores your server has. Julia has no GIL.\n\n# Julia: true parallel execution\non(client, [`MessageCreate`](@ref)) do c, event\n    Threads.@spawn begin\n        # This runs on a separate thread — truly parallel\n        result = heavy_computation(event.message.content)\n        [`create_message`](@ref)(c, event.message.channel_id; content=result)\n    end\nend\n\n# Python: GIL prevents true parallelism\n@bot.event\nasync def on_message(message):\n    # asyncio is concurrent but NOT parallel\n    # CPU-bound work blocks the entire event loop\n    result = heavy_computation(message.content)  # blocks everything\n    await message.channel.send(result)\n\nStart Julia with --threads=auto and every CPU core works for your bot.","category":"section"},{"location":"cookbook/15-why-julia/#Benchmark:-Fibonacci(40)","page":"Why Julia?","title":"Benchmark: Fibonacci(40)","text":"Language Time Notes\nPython (CPython) ~45s GIL prevents threading\nPython (asyncio) ~45s asyncio doesn't help CPU work\nJulia ~0.5s JIT-compiled, type-inferred\nJulia (4 threads) ~0.15s True parallelism","category":"section"},{"location":"cookbook/15-why-julia/#3.-Multiple-Dispatch:-Type-Based-Event-Routing","page":"Why Julia?","title":"3. Multiple Dispatch: Type-Based Event Routing","text":"Accord.jl uses Julia's type system for event dispatch — no string matching or decorator chains:\n\n# Julia: the type system IS the routing\non(client, [`MessageCreate`](@ref)) do c, event\n    # Only called for MessageCreate events\nend\n\non(client, [`GuildMemberAdd`](@ref)) do c, event\n    # Only called for GuildMemberAdd events\nend\n\n# Even cache updates use dispatch:\n[`update_state!`](@ref)(state, event::[`GuildCreate`](@ref))    # handles guild creation\n[`update_state!`](@ref)(state, event::[`ChannelDelete`](@ref))  # handles channel deletion\n[`update_state!`](@ref)(state, event::[`AbstractEvent`](@ref))  # fallback\n\n# Python: string-based routing with decorators\n@bot.event\nasync def on_message(message):      # string \"on_message\" → function\n    pass\n\n@bot.event\nasync def on_member_join(member):   # string \"on_member_join\" → function\n    pass\n\nMultiple dispatch means you can extend behavior without modifying existing code — fundamental to Julia's design.","category":"section"},{"location":"cookbook/15-why-julia/#4.-Type-Safety","page":"Why Julia?","title":"4. Type Safety","text":"Accord.jl catches bugs at compile time that Python misses at runtime:\n\n# Snowflake: can't accidentally pass a string where an ID is needed\nchannel_id = [`Snowflake`](@ref)(123456789012345678)\n[`create_message`](@ref)(client, channel_id; content=\"typed!\")\n\n# Permission flags: bitfield type prevents integer mistakes\nperms = [`PermSendMessages`](@ref) | [`PermEmbedLinks`](@ref)\n[`has_flag`](@ref)(perms, [`PermAdministrator`](@ref))  # false — type-safe check\n\n# Optional{T}: explicit handling of missing fields\nif !ismissing(msg.content)\n    # content is guaranteed to be String here\n    process(msg.content)\nend","category":"section"},{"location":"cookbook/15-why-julia/#5.-Scientific-Computing-Integration-(The-Killer-Feature)","page":"Why Julia?","title":"5. Scientific Computing Integration (The Killer Feature)","text":"This is where Julia truly separates from Python. No FFI, no subprocess calls — first-class scientific computing in the same language as your bot:","category":"section"},{"location":"cookbook/15-why-julia/#Machine-Learning-Bot","page":"Why Julia?","title":"Machine Learning Bot","text":"using Accord\nusing Flux  # Julia's ML framework\n\n# Load a trained model\nmodel = Chain(Dense(784, 128, relu), Dense(128, 10), softmax)\n# ... load weights ...\n\n@slash_command client \"classify\" \"Classify a digit\" function(ctx)\n    # Get attached image, preprocess, run inference\n    # All in pure Julia — no Python subprocess needed\n    img = load_image(attachment_url)\n    prediction = Flux.onecold(model(img))\n    [`respond`](@ref)(ctx; content=\"I think that's a **$prediction**!\")\nend","category":"section"},{"location":"cookbook/15-why-julia/#Chart-Bot","page":"Why Julia?","title":"Chart Bot","text":"using Accord\nusing CairoMakie  # publication-quality plots\n\n@slash_command client \"chart\" \"Generate a chart\" function(ctx)\n    [`defer`](@ref)(ctx)\n\n    fig = Figure(size=(800, 400))\n    ax = Axis(fig[1,1], title=\"Server Activity\")\n    barplot!(ax, 1:7, rand(7), color=:steelblue)\n\n    # Save to buffer and send\n    io = IOBuffer()\n    save(io, fig; pt_per_unit=1)\n    [`respond`](@ref)(ctx; content=\"Here's your chart:\", files=[(\"chart.png\", take!(io))])\nend","category":"section"},{"location":"cookbook/15-why-julia/#Scientific-Computing-Bot","page":"Why Julia?","title":"Scientific Computing Bot","text":"using Accord\nusing DifferentialEquations  # world-class ODE solvers\n\noptions_simulate = [\n    [`command_option`](@ref)(type=ApplicationCommandOptionTypes.NUMBER, name=\"rate\", description=\"Growth rate\", required=true),\n]\n\n@slash_command client \"simulate\" \"Simulate a system\" options_simulate function(ctx)\n    [`defer`](@ref)(ctx)\n    rate = [`get_option`](@ref)(ctx, \"rate\", 1.0)::Number\n\n    # Solve an ODE — in the same process as the bot\n    f(u, p, t) = rate * u\n    prob = ODEProblem(f, 1.0, (0.0, 5.0))\n    sol = solve(prob)\n\n    [`respond`](@ref)(ctx; content=\"Final value at t=5: **$(round(sol.u[end], digits=3))**\")\nend\n\nIn Python, you'd need subprocess calls to Julia/R/MATLAB or complex FFI bindings. In Julia, it's all native.","category":"section"},{"location":"cookbook/15-why-julia/#6.-REPL-Driven-Development","page":"Why Julia?","title":"6. REPL-Driven Development","text":"Non-blocking mode gives you a live REPL connected to Discord:\n\nstart(client; blocking=false)\n[`wait_until_ready`](@ref)(client)\n\n# Test things live:\n[`create_message`](@ref)(client, [`Snowflake`](@ref)(ch_id); content=\"Testing!\")\n\n# Inspect state:\nclient.state.me.username\nlength(client.state.guilds)\n\n# Hot-reload handlers (just redefine):\non(client, [`MessageCreate`](@ref)) do c, event\n    # This replaces the previous handler\n    @info \"New handler!\" content=event.message.content\nend\n\nNo restart cycle. No waiting for reconnection. Change code and see results instantly.","category":"section"},{"location":"cookbook/15-why-julia/#7.-Package-Management","page":"Why Julia?","title":"7. Package Management","text":"Julia's built-in package manager is simple and reproducible:\n\n# Project.toml — declares dependencies\n[deps]\nAccord = \"xxx-xxx\"\nHTTP = \"...\"\n\n# Manifest.toml — exact resolved versions (auto-generated)\n# Committed for reproducible builds\n\nNo virtualenv, no pip freeze, no requirements.txt vs setup.py vs pyproject.toml confusion. One system, always works.","category":"section"},{"location":"cookbook/15-why-julia/#8.-Honest-Trade-Offs","page":"Why Julia?","title":"8. Honest Trade-Offs","text":"Julia isn't perfect for every use case. Here's what to expect:","category":"section"},{"location":"cookbook/15-why-julia/#JIT-Compilation-Latency-(Time-to-First-X)","page":"Why Julia?","title":"JIT Compilation Latency (Time-to-First-X)","text":"First bot startup takes 10-15 seconds as Julia compiles code. Mitigations:\n\nPackageCompiler.jl sysimage reduces this to ~1 second (see Recipe 13)\nSubsequent event handling is near-instant\nIn production, startup time is negligible (bot runs for weeks/months)","category":"section"},{"location":"cookbook/15-why-julia/#Smaller-Ecosystem","page":"Why Julia?","title":"Smaller Ecosystem","text":"Feature Python (discord.py) Julia (Accord.jl)\nLibrary maturity 8+ years New\nStackOverflow answers Thousands Few\nThird-party extensions Many (cogs, utils) Build your own\nDocumentation Extensive This cookbook!","category":"section"},{"location":"cookbook/15-why-julia/#Learning-Curve","page":"Why Julia?","title":"Learning Curve","text":"If your team only knows Python, there's a learning curve. Key differences:\n\n1-indexed arrays\nmissing vs nothing vs undef\nMultiple dispatch instead of classes\nMacros (powerful but unfamiliar)","category":"section"},{"location":"cookbook/15-why-julia/#9.-Migration-Guide:-discord.py-Accord.jl","page":"Why Julia?","title":"9. Migration Guide: discord.py → Accord.jl","text":"","category":"section"},{"location":"cookbook/15-why-julia/#Client-Setup","page":"Why Julia?","title":"Client Setup","text":"# discord.py\nimport discord\nbot = discord.Bot(intents=discord.Intents.default())\n\n# Accord.jl\nusing Accord\nclient = [`Client`](@ref)(token; intents=[`IntentAllNonPrivileged`](@ref))","category":"section"},{"location":"cookbook/15-why-julia/#Event-Handlers","page":"Why Julia?","title":"Event Handlers","text":"# discord.py\n@bot.event\nasync def on_message(message):\n    if message.content == \"!ping\":\n        await message.channel.send(\"Pong!\")\n\n# Accord.jl\non(client, [`MessageCreate`](@ref)) do c, event\n    msg = event.message\n    ismissing(msg.content) && return\n    msg.content == \"!ping\" && [`create_message`](@ref)(c, msg.channel_id; content=\"Pong!\")\nend","category":"section"},{"location":"cookbook/15-why-julia/#Slash-Commands","page":"Why Julia?","title":"Slash Commands","text":"# discord.py\n@bot.slash_command()\nasync def greet(ctx, name: str):\n    await ctx.respond(f\"Hello, {name}!\")\n\n# Accord.jl\ntree = [`CommandTree`](@ref)()\n[`register_command!`](@ref)(tree, \"greet\", \"Say hello\", function(ctx)\n    name = [`get_option`](@ref)(ctx, \"name\", \"World\")\n    [`respond`](@ref)(ctx; content=\"Hello, $name!\")\nend; options=[\n    [`command_option`](@ref)(type=ApplicationCommandOptionTypes.STRING, name=\"name\", description=\"Name\", required=true),\n])","category":"section"},{"location":"cookbook/15-why-julia/#Embeds","page":"Why Julia?","title":"Embeds","text":"# discord.py\nembed = discord.Embed(title=\"Info\", color=0x5865F2)\nembed.add_field(name=\"Field\", value=\"Value\")\nawait ctx.send(embed=embed)\n\n# Accord.jl\ne = [`embed`](@ref)(title=\"Info\", color=0x5865F2, fields=[\n    Dict(\"name\" => \"Field\", \"value\" => \"Value\"),\n])\n[`create_message`](@ref)(client, channel_id; embeds=[e])","category":"section"},{"location":"cookbook/15-why-julia/#Permissions","page":"Why Julia?","title":"Permissions","text":"# discord.py\n@bot.command()\n@commands.has_permissions(ban_members=True)\nasync def ban(ctx, member):\n    await member.ban()\n\n# Accord.jl\n[`register_command!`](@ref)(tree, \"ban\", \"Ban a user\", function(ctx)\n    perms = get_member_permissions(ctx.client, ctx.interaction.guild_id, ctx.interaction.member.user.id)\n    [`has_flag`](@ref)(perms, [`PermBanMembers`](@ref)) || return [`respond`](@ref)(ctx; content=\"No permission\", ephemeral=true)\n    # ... ban logic\nend)","category":"section"},{"location":"cookbook/15-why-julia/#10.-When-to-Choose-Julia","page":"Why Julia?","title":"10. When to Choose Julia","text":"Choose Julia when:\n\nYou need real computational power (ML, scientific computing, data processing)\nYou want true parallelism without the GIL\nYou value type safety and multiple dispatch\nYour bot generates charts, runs simulations, or processes data\nYou're already in the Julia ecosystem\n\nStick with Python when:\n\nYou need maximum community support and tutorials\nYour bot is purely CRUD with no computation\nYour team only knows Python and learning Julia isn't feasible\nYou need specific discord.py extensions with no Julia equivalent\n\n\n\nNext steps: Recipe 16 — AI Agent Bot to build the ultimate showcase: an LLM-powered Discord bot in Julia.","category":"section"},{"location":"cookbook/10-polls/#Recipe-10-—-Polls","page":"Polls","title":"Recipe 10 — Polls","text":"Difficulty: Beginner What you will build: Discord-native polls with vote tracking, result checking, and early endings.\n\nPrerequisites: Recipe 01, Recipe 03\n\n","category":"section"},{"location":"cookbook/10-polls/#1.-How-Discord-Polls-Work","page":"Polls","title":"1. How Discord Polls Work","text":"Polls are sent as part of a Message via the poll field. Users vote using Discord's native UI — no buttons needed.\n\nRequired intent for vote events:\n\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentGuildMessagePolls\n)","category":"section"},{"location":"cookbook/10-polls/#2.-Creating-a-Poll","page":"Polls","title":"2. Creating a Poll","text":"note: Poll Duration and Answer Limits\nDiscord imposes limits on polls:Duration: 1 to 336 hours (14 days maximum)\nAnswers: Maximum 10 answer choices per poll\nQuestion: Maximum 300 characters\nAnswer text: Maximum 55 characters\n\nPolls use the poll body in create_message:\n\nbody = Dict{String, Any}(\n    \"poll\" => Dict(\n        \"question\" => Dict(\"text\" => \"What's your favorite language?\"),\n        \"answers\" => [\n            Dict(\"answer_id\" => 1, \"poll_media\" => Dict(\"text\" => \"Julia\")),\n            Dict(\"answer_id\" => 2, \"poll_media\" => Dict(\"text\" => \"Python\")),\n            Dict(\"answer_id\" => 3, \"poll_media\" => Dict(\"text\" => \"Rust\")),\n            Dict(\"answer_id\" => 4, \"poll_media\" => Dict(\"text\" => \"Other\")),\n        ],\n        \"duration\" => 24,            # hours (1-336, max 14 days)\n        \"allow_multiselect\" => false, # single choice\n        \"layout_type\" => 1,           # DEFAULT layout\n    )\n)\n\n# Must call the REST endpoint directly for poll body\ndiscord_post(client.ratelimiter, \"/channels/$(channel_id)/messages\";\n    token=client.token, body=body)","category":"section"},{"location":"cookbook/10-polls/#Poll-with-Emoji","page":"Polls","title":"Poll with Emoji","text":"Dict(\n    \"poll\" => Dict(\n        \"question\" => Dict(\"text\" => \"Pick a fruit\"),\n        \"answers\" => [\n            Dict(\"answer_id\" => 1, \"poll_media\" => Dict(\"text\" => \"Apple\", \"emoji\" => Dict(\"name\" => \"🍎\"))),\n            Dict(\"answer_id\" => 2, \"poll_media\" => Dict(\"text\" => \"Banana\", \"emoji\" => Dict(\"name\" => \"🍌\"))),\n            Dict(\"answer_id\" => 3, \"poll_media\" => Dict(\"text\" => \"Cherry\", \"emoji\" => Dict(\"name\" => \"🍒\"))),\n        ],\n        \"duration\" => 1,\n        \"allow_multiselect\" => true,\n    )\n)","category":"section"},{"location":"cookbook/10-polls/#3.-Listening-for-Votes","page":"Polls","title":"3. Listening for Votes","text":"on(client, [`MessagePollVoteAdd`](@ref)) do c, event\n    @info \"Vote added\" user=event.user_id message=event.message_id answer=event.answer_id\nend\n\non(client, [`MessagePollVoteRemove`](@ref)) do c, event\n    @info \"Vote removed\" user=event.user_id message=event.message_id answer=event.answer_id\nend","category":"section"},{"location":"cookbook/10-polls/#Track-Votes-in-Real-Time","page":"Polls","title":"Track Votes in Real Time","text":"# Simple in-memory vote tracker\nconst vote_counts = Dict{[`Snowflake`](@ref), Dict{Int, Int}}()  # message_id → answer_id → count\n\non(client, [`MessagePollVoteAdd`](@ref)) do c, event\n    msg_votes = get!(vote_counts, event.message_id, Dict{Int, Int}())\n    msg_votes[event.answer_id] = get(msg_votes, event.answer_id, 0) + 1\nend\n\non(client, MessagePollVoteRemove) do c, event\n    msg_votes = get!(vote_counts, event.message_id, Dict{Int, Int}())\n    msg_votes[event.answer_id] = max(0, get(msg_votes, event.answer_id, 0) - 1)\nend","category":"section"},{"location":"cookbook/10-polls/#4.-Getting-Poll-Results","page":"Polls","title":"4. Getting Poll Results","text":"# Get voters for a specific answer\nvoters = get_answer_voters(client.ratelimiter, channel_id, message_id, 1;\n    token=client.token, limit=100)\n\n# voters is a Dict with \"users\" key\nfor user_data in voters[\"users\"]\n    @info \"Voter\" id=user_data[\"id\"] username=user_data[\"username\"]\nend","category":"section"},{"location":"cookbook/10-polls/#5.-Ending-a-Poll-Early","page":"Polls","title":"5. Ending a Poll Early","text":"# End the poll and finalize results\nresult_msg = end_poll(client.ratelimiter, channel_id, message_id;\n    token=client.token)\n@info \"Poll ended\" message_id=result_msg.id","category":"section"},{"location":"cookbook/10-polls/#6.-Practical-Example:-Poll-Bot-with-Slash-Commands","page":"Polls","title":"6. Practical Example: Poll Bot with Slash Commands","text":"using Accord\n\ntoken = ENV[\"DISCORD_TOKEN\"]\nclient = Client(token;\n    intents = IntentGuilds | IntentGuildMessages | IntentGuildMessagePolls\n)\n\n# /poll \"Question?\" \"Option A\" \"Option B\" [\"Option C\"] [\"Option D\"]\noptions_poll = [\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"question\", description=\"Poll question\", required=true),\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"option1\", description=\"First option\", required=true),\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"option2\", description=\"Second option\", required=true),\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"option3\", description=\"Third option\"),\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"option4\", description=\"Fourth option\"),\n    command_option(type=ApplicationCommandOptionTypes.INTEGER, name=\"hours\", description=\"Duration in hours (default: 24)\", min_value=1, max_value=336),\n    command_option(type=ApplicationCommandOptionTypes.BOOLEAN, name=\"multiselect\", description=\"Allow multiple votes?\"),\n]\n\n@slash_command client \"poll\" \"Create a poll\" options_poll function(ctx)\n    question = get_option(ctx, \"question\", \"\")\n    opt1 = get_option(ctx, \"option1\", \"\")\n    opt2 = get_option(ctx, \"option2\", \"\")\n    opt3 = get_option(ctx, \"option3\", nothing)\n    opt4 = get_option(ctx, \"option4\", nothing)\n    hours = get_option(ctx, \"hours\", 24)\n    multi = get_option(ctx, \"multiselect\", false)\n\n    answers = [\n        Dict(\"answer_id\" => 1, \"poll_media\" => Dict(\"text\" => opt1)),\n        Dict(\"answer_id\" => 2, \"poll_media\" => Dict(\"text\" => opt2)),\n    ]\n    !isnothing(opt3) && push!(answers, Dict(\"answer_id\" => 3, \"poll_media\" => Dict(\"text\" => opt3)))\n    !isnothing(opt4) && push!(answers, Dict(\"answer_id\" => 4, \"poll_media\" => Dict(\"text\" => opt4)))\n\n    # Create the poll in the channel\n    channel_id = ctx.interaction.channel_id\n    body = Dict{String, Any}(\n        \"poll\" => Dict(\n            \"question\" => Dict(\"text\" => question),\n            \"answers\" => answers,\n            \"duration\" => hours,\n            \"allow_multiselect\" => multi,\n            \"layout_type\" => 1,\n        )\n    )\n\n    defer(ctx)\n    discord_post(ctx.client.ratelimiter, \"/channels/$(channel_id)/messages\";\n        token=ctx.client.token, body=body)\n    respond(ctx; content=\"Poll created!\", ephemeral=true)\nend\n\n# /endpoll <message_id>\noptions_end = [\n    command_option(type=ApplicationCommandOptionTypes.STRING, name=\"message_id\", description=\"Message ID of the poll\", required=true),\n]\n\n@slash_command client \"endpoll\" \"End a poll early\" options_end function(ctx)\n    msg_id = Snowflake(get_option(ctx, \"message_id\", \"\"))\n    channel_id = ctx.interaction.channel_id\n\n    end_poll(ctx.client.ratelimiter, channel_id, msg_id; token=ctx.client.token)\n    respond(ctx; content=\"Poll ended!\", ephemeral=true)\nend\n\n# Vote tracking\non(client, MessagePollVoteAdd) do c, event\n    @info \"Vote\" user=event.user_id answer=event.answer_id message=event.message_id\nend\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    sync_commands!(c, c.command_tree)\n    @info \"Poll bot ready!\"\nend\n\nstart(client)\n\n\n\nNext steps: Recipe 11 — Architectural Patterns for structuring a production bot.","category":"section"},{"location":"cookbook/11-architectural-patterns/#Recipe-11-—-Architectural-Patterns","page":"Architectural Patterns","title":"Recipe 11 — Architectural Patterns","text":"Difficulty: Intermediate What you will build: Production project structure with modular commands, middleware, error handling, config management, and database integration.\n\nPrerequisites: Recipe 03, Recipe 04\n\n","category":"section"},{"location":"cookbook/11-architectural-patterns/#1.-Production-Project-Structure","page":"Architectural Patterns","title":"1. Production Project Structure","text":"tip: Recommended Project Structure\nOrganize your bot into logical modules: commands, handlers, services, and utilities. This makes testing easier and allows multiple developers to work on different features simultaneously. Keep configuration separate from code, and never commit secrets.\n\nMyBot/\n├── Project.toml\n├── Manifest.toml\n├── .env                    # tokens (never commit)\n├── .gitignore\n├── config.toml             # bot configuration\n├── src/\n│   ├── MyBot.jl            # main module\n│   ├── commands/\n│   │   ├── general.jl      # /ping, /help, /info\n│   │   ├── moderation.jl   # /ban, /kick, /warn\n│   │   └── fun.jl          # /poll, /roll, /quote\n│   ├── handlers/\n│   │   ├── messages.jl     # MessageCreate handlers\n│   │   └── members.jl      # GuildMemberAdd/Remove handlers\n│   ├── services/\n│   │   ├── database.jl     # database access layer\n│   │   └── api.jl          # external API clients\n│   └── utils/\n│       ├── config.jl       # config loading\n│       ├── embeds.jl       # embed templates\n│       └── checks.jl       # permission checks\n├── bin/\n│   └── run.jl              # entry point\n└── test/\n    └── runtests.jl","category":"section"},{"location":"cookbook/11-architectural-patterns/#2.-Main-Module-Pattern","page":"Architectural Patterns","title":"2. Main Module Pattern","text":"# src/MyBot.jl\nmodule MyBot\n\nusing Accord\nusing Dates\n\n# Configuration\ninclude(\"utils/config.jl\")\n\n# Utilities\ninclude(\"utils/embeds.jl\")\ninclude(\"utils/checks.jl\")\n\n# Services\ninclude(\"services/database.jl\")\n\n# Commands\ninclude(\"commands/general.jl\")\ninclude(\"commands/moderation.jl\")\ninclude(\"commands/fun.jl\")\n\n# Event handlers\ninclude(\"handlers/messages.jl\")\ninclude(\"handlers/members.jl\")\n\n# Bot setup\nfunction create_bot(config)\n    client = Client(config[\"token\"];\n        intents = IntentGuilds | IntentGuildMessages | IntentMessageContent | IntentGuildMembers,\n        user_strategy = CacheLRU(config[\"cache\"][\"max_users\"]),\n    )\n\n    # Register all commands (macros will register them to client.command_tree)\n    register_general_commands!(client, config)\n    register_moderation_commands!(client, config)\n    register_fun_commands!(client, config)\n\n    # Register event handlers\n    register_message_handlers!(client, config)\n    register_member_handlers!(client, config)\n\n    # Sync commands on ready\n    on(client, [`ReadyEvent`](@ref)) do c, event\n        sync_commands!(c, c.command_tree; guild_id=get(config, \"dev_guild_id\", nothing))\n        @info \"Bot ready!\" user=event.user.username\n    end\n\n    # Note: Client automatically routes interactions to c.command_tree\n\n    return client\nend\n\nend # module","category":"section"},{"location":"cookbook/11-architectural-patterns/#3.-Modular-Command-Registration","page":"Architectural Patterns","title":"3. Modular Command Registration","text":"# src/commands/general.jl\n\nfunction register_general_commands!(client, config)\n\n    @slash_command client \"ping\" \"Check bot latency\" function(ctx)\n        t = time()\n        defer(ctx)\n        ms = round(Int, (time() - t) * 1000)\n        e = embed(title=\"Pong!\", description=\"Latency: **$(ms) ms**\", color=0x57F287)\n        respond(ctx; embeds=[e])\n    end\n\n    @slash_command client \"info\" \"Bot information\" function(ctx)\n        guilds = length(ctx.client.state.guilds)\n        e = embed(\n            title=\"Bot Info\",\n            color=0x5865F2,\n            fields=[\n                Dict(\"name\" => \"Guilds\", \"value\" => string(guilds), \"inline\" => true),\n                Dict(\"name\" => \"Julia\", \"value\" => string(VERSION), \"inline\" => true),\n                Dict(\"name\" => \"Accord.jl\", \"value\" => string(Accord.ACCORD_VERSION), \"inline\" => true),\n            ]\n        )\n        respond(ctx; embeds=[e])\n    end\n\nend\n\n# src/commands/moderation.jl\n\nfunction register_moderation_commands!(client, config)\n\n    options = [\n        command_option(type=ApplicationCommandOptionTypes.USER, name=\"user\", description=\"User to kick\", required=true),\n        command_option(type=ApplicationCommandOptionTypes.STRING, name=\"reason\", description=\"Reason for kick\"),\n    ]\n\n    # Clean: guards are declared outside the handler\n    @check has_permissions(:KICK_MEMBERS)\n    @slash_command client \"kick\" \"Kick a member\" options function(ctx)\n        target = Snowflake(get_option(ctx, \"user\", \"\"))\n        reason = get_option(ctx, \"reason\", \"No reason\")\n\n        remove_guild_member(ctx.client.ratelimiter, ctx.interaction.guild_id, target;\n            token=ctx.client.token, reason=reason)\n\n        respond(ctx; content=\"Kicked <@$(target)>. Reason: $reason\")\n    end\n\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#4.-Error-Handling","page":"Architectural Patterns","title":"4. Error Handling","text":"","category":"section"},{"location":"cookbook/11-architectural-patterns/#Global-Error-Handler","page":"Architectural Patterns","title":"Global Error Handler","text":"warning: Blocking the Event Loop with Synchronous Operations\nNever perform blocking operations (like sleep(), file I/O without async, or long computations) directly in event handlers. This blocks the entire event loop and prevents the bot from receiving new events. Always wrap slow operations in @async or Threads.@spawn.\n\non_error(client) do c, event, error\n    # Log the error with full context\n    @error \"Handler error\" event_type=typeof(event) exception=(error, catch_backtrace())\n\n    # Optionally notify a channel\n    ERROR_CHANNEL = [`Snowflake`](@ref)(config[\"error_channel_id\"])\n    try\n        e = embed(\n            title=\"Bot Error\",\n            description=\"```\\n$(sprint(showerror, error))\\n```\",\n            color=0xED4245,\n            fields=[\n                Dict(\"name\" => \"Event\", \"value\" => string(typeof(event))),\n            ],\n            footer=Dict(\"text\" => string(now())),\n        )\n        create_message(c, ERROR_CHANNEL; embeds=[e])\n    catch\n        # Don't let error reporting errors crash the bot\n    end\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#Per-Handler-Try-Catch","page":"Architectural Patterns","title":"Per-Handler Try-Catch","text":"@slash_command client \"risky\" \"A command that might fail\" function(ctx)\n    try\n        result = some_external_api_call()\n        respond(ctx; content=\"Result: $result\")\n    catch e\n        @error \"Command failed\" exception=e\n        respond(ctx; content=\"Something went wrong. Please try again later.\", ephemeral=true)\n    end\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#Structured-Logging","page":"Architectural Patterns","title":"Structured Logging","text":"using Logging\n\n# Set up logging with timestamps\nlogger = ConsoleLogger(stderr, Logging.Info)\nglobal_logger(logger)\n\n# Enable debug logging for Accord\nENV[\"JULIA_DEBUG\"] = \"Accord\"","category":"section"},{"location":"cookbook/11-architectural-patterns/#5.-Middleware","page":"Architectural Patterns","title":"5. Middleware","text":"Middleware runs before every event handler. Return the event to continue, nothing to cancel.\n\n# Logging middleware\nregister_middleware!(client.event_handler) do client, event\n    @debug \"Event received\" type=typeof(event)\n    return event  # pass through\nend\n\n# Ignore list middleware\nconst IGNORED_USERS = Set{[`Snowflake`](@ref)}()\n\nregister_middleware!(client.event_handler) do client, event\n    if event isa [`MessageCreate`](@ref)\n        user_id = ismissing(event.message.author) ? nothing : event.message.author.id\n        if !isnothing(user_id) && user_id in IGNORED_USERS\n            return nothing  # cancel event\n        end\n    end\n    return event\nend\n\n# Rate limiting middleware\nconst user_cooldowns = Dict{[`Snowflake`](@ref), Float64}()\nconst COOLDOWN_SECONDS = 2.0\n\nregister_middleware!(client.event_handler) do client, event\n    if event isa [`InteractionCreate`](@ref)\n        user_id = event.interaction.member.user.id\n        last_use = get(user_cooldowns, user_id, 0.0)\n        if time() - last_use < COOLDOWN_SECONDS\n            return nothing  # too fast, ignore\n        end\n        user_cooldowns[user_id] = time()\n    end\n    return event\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#6.-Configuration-with-TOML","page":"Architectural Patterns","title":"6. Configuration with TOML","text":"# config.toml\n[bot]\nprefix = \"!\"\ndev_guild_id = \"123456789012345678\"\nerror_channel_id = \"987654321098765432\"\n\n[cache]\nmax_users = 50000\nmax_members = 50000\n\n[features]\nenable_logging = true\nenable_moderation = true\nenable_fun = true\n\n# src/utils/config.jl\nimport TOML\n\nfunction load_config(path=\"config.toml\")\n    config = TOML.parsefile(path)\n\n    # Merge with env vars (env takes precedence)\n    config[\"token\"] = ENV[\"DISCORD_TOKEN\"]\n\n    return config\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#7.-Entry-Point","page":"Architectural Patterns","title":"7. Entry Point","text":"# bin/run.jl\nusing Pkg\nPkg.activate(joinpath(@__DIR__, \"..\"))\n\n# Load .env\nfor line in eachline(\".env\")\n    stripped = strip(line)\n    (isempty(stripped) || startswith(stripped, '#')) && continue\n    key, value = split(stripped, '='; limit=2)\n    ENV[strip(key)] = strip(value)\nend\n\nusing MyBot\n\nconfig = MyBot.load_config()\nclient = MyBot.create_bot(config)\n\n@info \"Starting bot...\"\nstart(client)","category":"section"},{"location":"cookbook/11-architectural-patterns/#8.-Database-Integration-Pattern","page":"Architectural Patterns","title":"8. Database Integration Pattern","text":"# src/services/database.jl\nimport SQLite\n\nconst db = Ref{SQLite.DB}()\n\nfunction init_db(path=\"bot.db\")\n    db[] = SQLite.DB(path)\n\n    SQLite.execute(db[], \"\"\"\n        CREATE TABLE IF NOT EXISTS warnings (\n            id INTEGER PRIMARY KEY AUTOINCREMENT,\n            guild_id TEXT NOT NULL,\n            user_id TEXT NOT NULL,\n            moderator_id TEXT NOT NULL,\n            reason TEXT NOT NULL,\n            created_at TEXT NOT NULL\n        )\n    \"\"\")\nend\n\nfunction add_warning(guild_id, user_id, moderator_id, reason)\n    SQLite.execute(db[], \"\"\"\n        INSERT INTO warnings (guild_id, user_id, moderator_id, reason, created_at)\n        VALUES (?, ?, ?, ?, ?)\n    \"\"\", [string(guild_id), string(user_id), string(moderator_id), reason, string(now())])\nend\n\nfunction get_warnings(guild_id, user_id)\n    SQLite.DBInterface.execute(db[], \"\"\"\n        SELECT * FROM warnings WHERE guild_id = ? AND user_id = ? ORDER BY created_at DESC\n    \"\"\", [string(guild_id), string(user_id)]) |> collect\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#9.-Idiomatic-Julia-Patterns","page":"Architectural Patterns","title":"9. Idiomatic Julia Patterns","text":"","category":"section"},{"location":"cookbook/11-architectural-patterns/#Multiple-Dispatch-for-Event-Routing","page":"Architectural Patterns","title":"Multiple Dispatch for Event Routing","text":"# Julia's type system naturally routes events\nfunction handle_event(client, event::[`GuildMemberAdd`](@ref))\n    @info \"Welcome!\" user=event.member.user.username\nend\n\nfunction handle_event(client, event::[`GuildMemberRemove`](@ref))\n    @info \"Goodbye!\" user=event.user.username\nend\n\nfunction handle_event(client, event::[`AbstractEvent`](@ref))\n    # fallback — nothing\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#Type-Stable-Option-Extraction","page":"Architectural Patterns","title":"Type-Stable Option Extraction","text":"# Annotate types when extracting options\nfunction handle_greet(ctx)\n    name = get_option(ctx, \"name\", \"World\")::String\n    times = get_option(ctx, \"times\", 1)::Int\n    respond(ctx; content=join(fill(\"Hello, $name!\", times), \"\\n\"))\nend","category":"section"},{"location":"cookbook/11-architectural-patterns/#Avoid-Global-Mutable-State","page":"Architectural Patterns","title":"Avoid Global Mutable State","text":"# ✅ Preferred: inject state via Client's state parameter\nstruct BotState\n    warnings::Dict{[`Snowflake`](@ref), Vector{String}}\n    config::Dict{String, Any}\n    db::Any\nend\n\n# State is accessible from handlers via ctx.state\nbot_state = BotState(Dict(), config, db_conn)\nclient = Client(token; state=bot_state)\n\nfunction register_commands!(client)\n    @slash_command client \"warn\" \"Warn a user\" function(ctx)\n        # ctx.state is the BotState struct — no globals!\n        warns = get!(ctx.state.warnings, ctx.interaction.guild_id, String[])\n        push!(warns, \"warning\")\n        respond(ctx; content=\"Warning recorded ($(length(warns)) total)\")\n    end\n\n    # Access database cleanly\n    @slash_command client \"stats\" \"Show stats\" function(ctx)\n        count = query_count(ctx.state.db, ctx.guild_id)\n        respond(ctx; content=\"Total: $count\")\n    end\nend\n\n\n\nNext steps: Recipe 12 — Performance for Julia-specific optimizations.","category":"section"},{"location":"#Accord.jl","page":"Home","title":"Accord.jl","text":"Accord.jl is a high-performance, ergonomic Discord API library for Julia. Built for speed and developer happiness, it leverages Julia's multiple dispatch and concurrency model to make bot development intuitive and powerful.","category":"section"},{"location":"#Features","page":"Home","title":"Features","text":"Full v10 Support: Compatible with the latest Discord API features.\nErgonomic UI Macros: Decorators for Slash Commands, Buttons, Modals, and Select Menus.\n@check Guards: Declarative pre-execution checks for permissions, ownership, and custom conditions.\nwait_for Conversations: Lightweight state machines using Julia Channels — no manual state management.\nState Injection: Pass your database, config, or services via ctx.state — zero globals.\nHigh-Performance Voice: Built-in support for Opus encoding and encryption for music/voice bots.\nEfficient Caching: Automatic state management with customizable LRU/TTL strategies.\nType Safety: Leveraging Julia's type system to catch bugs before they happen.\nAsync First: Built on top of Julia's Tasks and Channels for non-blocking I/O.","category":"section"},{"location":"#Installation","page":"Home","title":"Installation","text":"using Pkg\nPkg.add(\"Accord\")","category":"section"},{"location":"#Quick-Start","page":"Home","title":"Quick Start","text":"using Accord\n\nclient = [`Client`](@ref)(ENV[\"DISCORD_TOKEN\"];\n    intents = [`IntentGuilds`](@ref) | [`IntentGuildMessages`](@ref) | [`IntentMessageContent`](@ref)\n)\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    @info \"Bot is online as $(event.user.username)!\"\nend\n\n@slash_command client \"ping\" \"Check latency\" function(ctx)\n    [`respond`](@ref)(ctx; content=\"Pong!\")\nend\n\non(client, [`ReadyEvent`](@ref)) do c, event\n    [`sync_commands!`](@ref)(c, c.command_tree)\nend\n\nstart(client)","category":"section"},{"location":"#Next-Steps","page":"Home","title":"Next Steps","text":"Browse the Cookbook for step-by-step recipes\nCheck the API Reference for detailed documentation","category":"section"}]
}
